import { NextRequest, NextResponse } from "next/server";
import {
  apiBibleFetch,
  BibleChapterContent,
  isSafeBibleIdentifier,
  sanitizeScriptureHtml,
} from "@/lib/bible/apiBible";

export const dynamic = "force-dynamic";

export async function GET(request: NextRequest) {
  const bibleId = request.nextUrl.searchParams.get("bibleId")?.trim() || "";
  const chapterId =
    request.nextUrl.searchParams.get("chapterId")?.trim() || "";

  if (
    !bibleId ||
    !chapterId ||
    !isSafeBibleIdentifier(bibleId) ||
    !isSafeBibleIdentifier(chapterId)
  ) {
    return NextResponse.json(
      { error: "Version ou chapitre invalide." },
      { status: 400 }
    );
  }

  const query = new URLSearchParams({
    "content-type": "html",
    "include-notes": "false",
    "include-titles": "true",
    "include-chapter-numbers": "false",
    "include-verse-numbers": "true",
    "include-verse-spans": "true",
    "use-org-id": "false",
    "fums-version": "3",
  });

  try {
    const response = await apiBibleFetch<BibleChapterContent>(
      `/bibles/${encodeURIComponent(
        bibleId
      )}/chapters/${encodeURIComponent(chapterId)}?${query.toString()}`,
      { revalidate: 600 }
    );

    return NextResponse.json(
      {
        data: {
          ...response.data,
          content: sanitizeScriptureHtml(response.data?.content || ""),
        },
        fumsToken: response.meta?.fumsToken || null,
      },
      {
        headers: {
          "Cache-Control": "private, max-age=120",
        },
      }
    );
  } catch (error: any) {
    return NextResponse.json(
      {
        error: error?.message || "Impossible de charger ce chapitre.",
      },
      { status: 503 }
    );
  }
}

import React from "react";
import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
import type { Metadata } from "next";
import type { LucideIcon } from "lucide-react";
import {
  CalendarDays,
  HeartHandshake,
  LockKeyhole,
  Mail,
  MapPin,
  MessageCircle,
  Phone,
  PlayCircle,
  Sparkles,
  UserPlus,
} from "lucide-react";

import ChurchTeachingsBlock from "@/components/public/ChurchTeachingsBlock";
import PublicBibleBlock from "@/components/public/bible/PublicBibleBlock";
import PublicDonationSection from "@/components/public/PublicDonationSection";
import PublicLiveStreamSection from "@/components/public/PublicLiveStreamSection";
import PublicMobileBottomNav from "@/components/public/PublicMobileBottomNav";
import PublicTestimoniesSection from "@/components/public/PublicTestimoniesSection";
import { createClient } from "@/lib/supabase/server";

type PublicChurchPageProps = {
  params: Promise<{
    slug: string;
  }>;
};

type PublicChurchNameInput = {
  name?: string | null;
  public_name?: string | null;
};

type PublicChurch = {
  id: string;
  name: string | null;
  public_name: string | null;
  slug: string | null;
  status: string | null;

  logo_url: string | null;
  pastor_photo_url: string | null;
  pastor_name: string | null;
  pastor_title: string | null;

  address: string | null;
  city: string | null;
  country: string | null;
  phone: string | null;
  whatsapp: string | null;
  email: string | null;

  public_hero_title: string | null;
  public_message: string | null;
  service_times: string | null;
  public_enabled: boolean | null;
  login_enabled: boolean | null;

  youtube_channel_url: string | null;
  latest_video_url: string | null;
  news_title: string | null;
  news_description: string | null;

  donation_enabled: boolean | null;
  donation_message: string | null;
  donation_mobile_money: string | null;
  donation_mobile_money_name: string | null;
  donation_card_url: string | null;
  donation_bank_name: string | null;
  donation_bank_account_name: string | null;
  donation_bank_account_number: string | null;
  donation_bank_iban: string | null;
  donation_bank_swift: string | null;
  donation_bank_details: string | null;

  live_stream_enabled: boolean | null;
  live_stream_url: string | null;
  live_stream_title: string | null;
  live_stream_description: string | null;
  live_stream_platform: string | null;
  live_stream_started_at: string | null;
  live_stream_notified_at: string | null;
};

function getPublicChurchName(church: PublicChurchNameInput) {
  const publicName = church.public_name?.trim();

  if (publicName) {
    return publicName;
  }

  const name = church.name?.trim();

  if (!name) {
    return "Église";
  }

  return name.replace(/\s*[,|-]?\s*extension.*$/i, "").trim();
}

function formatPhoneForWhatsapp(phone: string | null) {
  if (!phone) return null;

  const cleaned = phone.replace(/[^\d]/g, "");

  if (!cleaned) return null;

  return `https://wa.me/${cleaned}`;
}

function getYoutubeEmbedUrl(url: string | null) {
  if (!url) return null;

  if (url.includes("youtube.com/embed/")) {
    return url;
  }

  const watchMatch = url.match(/[?&]v=([^&]+)/);

  if (watchMatch?.[1]) {
    return `https://www.youtube.com/embed/${watchMatch[1]}`;
  }

  const shortMatch = url.match(/youtu\.be\/([^?&]+)/);

  if (shortMatch?.[1]) {
    return `https://www.youtube.com/embed/${shortMatch[1]}`;
  }

  return null;
}

export async function generateMetadata({
  params,
}: PublicChurchPageProps): Promise<Metadata> {
  const { slug } = await params;
  const supabase = await createClient();

  const { data: church } = await supabase
    .from("churches")
    .select("name, public_name, public_message, logo_url")
    .eq("slug", slug)
    .maybeSingle();

  if (!church) {
    return {
      title: "Église | Mpangi-church",
      manifest: `/church/${slug}/manifest.webmanifest`,
    };
  }

  const churchPublicName = getPublicChurchName(church);

  return {
    title: `${churchPublicName} | Mpangi-church`,
    description:
      church.public_message ||
      `Page officielle de ${churchPublicName} sur Mpangi-church.`,
    manifest: `/church/${slug}/manifest.webmanifest`,
    icons: {
      icon: `/church/${slug}/icon.png`,
      apple: `/church/${slug}/icon.png`,
    },
  };
}

export default async function PublicChurchPage({
  params,
}: PublicChurchPageProps) {
  const { slug } = await params;
  const supabase = await createClient();

  const { data: churchRaw, error } = await supabase
    .from("churches")
    .select(
      `
      id,
      name,
      public_name,
      slug,
      status,
      logo_url,
      pastor_photo_url,
      pastor_name,
      pastor_title,
      address,
      city,
      country,
      phone,
      whatsapp,
      email,
      public_hero_title,
      public_message,
      service_times,
      public_enabled,
      login_enabled,
      youtube_channel_url,
      latest_video_url,
      news_title,
      news_description,
      donation_enabled,
      donation_message,
      donation_mobile_money,
      donation_mobile_money_name,
      donation_card_url,
      donation_bank_name,
      donation_bank_account_name,
      donation_bank_account_number,
      donation_bank_iban,
      donation_bank_swift,
      donation_bank_details,
      live_stream_enabled,
      live_stream_url,
      live_stream_title,
      live_stream_description,
      live_stream_platform,
      live_stream_started_at,
      live_stream_notified_at
    `
    )
    .eq("slug", slug)
    .maybeSingle();

  if (
    error ||
    !churchRaw ||
    churchRaw.status !== "active" ||
    !churchRaw.public_enabled
  ) {
    notFound();
  }

  const church = churchRaw as PublicChurch;
  const churchSlug = church.slug?.trim() || slug;
  const churchPublicName = getPublicChurchName(church);
  const whatsappUrl = formatPhoneForWhatsapp(church.whatsapp || church.phone);

  const logoSrc =
    church.logo_url || "/images/churches/maison-misericorde-logo.png";

  const pastorPhotoSrc =
    church.pastor_photo_url ||
    "/images/churches/maison-misericorde-pasteur.png";

  const youtubeEmbedUrl = getYoutubeEmbedUrl(church.latest_video_url);

  const welcomeTitle =
    church.public_hero_title?.trim() || `Bienvenue à ${churchPublicName}`;

  return (
    <main className="min-h-screen overflow-x-hidden bg-[#F5F9FC] pb-24 text-[#0F172A] lg:pb-0">
      <style>
        {`
          @keyframes mmFloat {
            0%, 100% { transform: translateY(0) scale(1); }
            50% { transform: translateY(-6px) scale(1.015); }
          }

          @keyframes mmPulseRing {
            0%, 100% { box-shadow: 0 0 0 0 rgba(255,255,255,0.25); }
            50% { box-shadow: 0 0 0 14px rgba(255,255,255,0); }
          }

          .mm-float {
            animation: mmFloat 7s ease-in-out infinite;
          }

          .mm-float-reverse {
            animation: mmFloat 8s ease-in-out infinite reverse;
          }

          .mm-pulse-ring {
            animation: mmPulseRing 4.2s ease-in-out infinite;
          }

          @media (prefers-reduced-motion: reduce) {
            .mm-float,
            .mm-float-reverse,
            .mm-pulse-ring {
              animation: none !important;
            }
          }
        `}
      </style>

      <section className="relative overflow-hidden bg-gradient-to-br from-[#03357A] via-[#2563EB] to-[#8B5CF6] px-4 py-5 text-white md:px-6 md:py-7">
        <div className="absolute -right-24 -top-24 h-80 w-80 rounded-full bg-white/10 blur-3xl" />
        <div className="absolute -bottom-32 -left-24 h-96 w-96 rounded-full bg-white/10 blur-3xl" />

        <div className="relative mx-auto max-w-6xl">
          <header className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
            <div className="flex min-w-0 items-center gap-3 md:gap-4">
              <div className="mm-float relative flex h-16 w-16 shrink-0 items-center justify-center rounded-2xl bg-white p-2.5 shadow-2xl md:h-20 md:w-20 md:rounded-[1.6rem]">
                <Image
                  src={logoSrc}
                  alt={`Logo ${churchPublicName}`}
                  width={80}
                  height={80}
                  className="h-full w-full object-contain"
                  priority
                />
              </div>

              <div className="min-w-0">
                <p className="text-[11px] font-semibold uppercase tracking-[0.22em] text-blue-100 md:text-sm">
                  Page publique
                </p>

                <h1 className="break-words text-xl font-extrabold leading-tight md:text-3xl">
                  {churchPublicName}
                </h1>
              </div>
            </div>

            {church.login_enabled && (
              <Link
                href={`/login?church=${encodeURIComponent(churchSlug)}`}
                className="inline-flex w-fit shrink-0 items-center gap-2 rounded-2xl bg-white/15 px-4 py-2.5 text-sm font-bold ring-1 ring-white/20 hover:bg-white/20"
              >
                <LockKeyhole className="h-4 w-4" />
                Espace église
              </Link>
            )}
          </header>

          <div className="grid gap-5 pb-4 pt-5 lg:grid-cols-[1.05fr_0.95fr] lg:items-start">
            <div className="min-w-0">
              <p className="inline-flex rounded-full bg-white/15 px-3 py-2 text-xs font-bold ring-1 ring-white/20 md:px-4 md:text-sm">
                Bienvenue dans notre communauté
              </p>

              <h2 className="mt-3 max-w-3xl break-words text-3xl font-black leading-tight md:text-5xl">
                {welcomeTitle}
              </h2>

              <p className="mt-4 max-w-3xl break-words text-sm leading-7 text-blue-50 md:text-lg md:leading-8">
                {church.public_message ||
                  "Bienvenue sur la page publique de notre église."}
              </p>

              <div className="mt-5 grid gap-3 sm:grid-cols-2">
                <HeroButton
                  href={`/church/${churchSlug}/prayer`}
                  icon={HeartHandshake}
                  label="Demander une prière"
                  variant="white"
                />

                <HeroButton
                  href={`/church/${churchSlug}/appointment`}
                  icon={CalendarDays}
                  label="Demander un rendez-vous"
                  variant="glass"
                />

                <a
                  href="#don"
                  className="inline-flex min-h-12 items-center justify-center rounded-2xl bg-[#03357A] px-4 py-3 text-center text-sm font-extrabold text-white shadow-lg shadow-blue-900/20 hover:bg-[#022B63]"
                >
                  Faire un don
                </a>

                <HeroButton
                  href={`/church/${churchSlug}/join`}
                  icon={UserPlus}
                  label="Rejoindre l’église"
                  variant="glass"
                />

                <HeroButton
                  href={`/church/${churchSlug}/testimony`}
                  icon={Sparkles}
                  label="Partager un témoignage"
                  variant="glass"
                />

                <HeroButton
                  href="/install"
                  icon={Sparkles}
                  label="Installer l’application"
                  variant="glass"
                />
              </div>

              <div className="mt-5 rounded-3xl bg-white/10 p-4 ring-1 ring-white/20 md:p-5">
                <p className="text-xs font-bold uppercase tracking-[0.18em] text-blue-100 md:text-sm">
                  Parcours d’accompagnement
                </p>

                <div className="mt-4 grid gap-3 md:grid-cols-3">
                  <StepBox number="01" label="Votre demande est reçue" />
                  <StepBox
                    number="02"
                    label="L’équipe pastorale vous contacte"
                  />
                  <StepBox
                    number="03"
                    label="Un suivi spirituel est organisé"
                  />
                </div>
              </div>
            </div>

            <div className="rounded-3xl border border-white/20 bg-white/10 p-3 shadow-2xl backdrop-blur md:p-4">
              <div className="rounded-3xl bg-white p-4 text-[#0F172A] md:p-5">
                <div className="flex flex-col items-center text-center">
                  <div className="mm-float-reverse mm-pulse-ring relative h-32 w-32 overflow-hidden rounded-full border-6 border-[#EAF3FA] bg-[#F8FBFD] shadow-2xl md:h-44 md:w-44 md:border-8">
                    <Image
                      src={pastorPhotoSrc}
                      alt={church.pastor_name || "Pasteur responsable"}
                      fill
                      sizes="(max-width: 768px) 128px, 176px"
                      className="object-cover"
                      priority
                    />
                  </div>

                  <h3 className="mt-4 break-words text-lg font-extrabold text-[#03357A] md:text-xl">
                    {church.pastor_name || "Pasteur responsable"}
                  </h3>

                  <p className="mt-1 break-words text-sm font-semibold text-slate-500">
                    {church.pastor_title || "Responsable de l’église"}
                  </p>
                </div>

                <div className="mt-5 space-y-3 md:mt-6 md:space-y-4">
                  <Info
                    icon={MapPin}
                    label="Adresse"
                    value={
                      [church.address, church.city, church.country]
                        .filter(Boolean)
                        .join(", ") || "À compléter"
                    }
                  />

                  <Info
                    icon={Phone}
                    label="Téléphone"
                    value={church.phone || "À compléter"}
                  />

                  <Info
                    icon={Mail}
                    label="Email"
                    value={church.email || "À compléter"}
                  />
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      <PublicLiveStreamSection church={church as any} />

      <section className="mx-auto max-w-6xl px-4 pt-7 md:px-6 md:pt-8">
        <ChurchTeachingsBlock churchId={church.id} slug={churchSlug} />
      </section>

      <section
        id="bible"
        className="scroll-mt-24 mx-auto max-w-6xl px-4 pt-7 md:px-6 md:pt-8"
      >
        <PublicBibleBlock slug={churchSlug} />
      </section>

      <section className="mx-auto max-w-6xl px-4 py-7 md:px-6 md:py-8">
        <div className="grid gap-5 lg:grid-cols-[0.85fr_1.15fr] lg:gap-6">
          <div className="min-w-0 rounded-3xl border border-[#DCEAF5] bg-white p-4 shadow-sm md:p-6">
            <h3 className="text-xl font-extrabold text-[#03357A]">
              Programmes
