            <p className="mt-4 whitespace-pre-line break-words rounded-2xl bg-[#F8FBFD] p-4 text-sm leading-7 text-slate-600 md:mt-5 md:p-5">
              {church.service_times || "Les programmes seront bientôt publiés."}
            </p>

            <div className="mt-5 rounded-3xl bg-[#EAF3FA] p-4 md:mt-6 md:p-5">
              <h4 className="font-extrabold text-[#03357A]">
                Contact rapide
