              <div className="mt-4 flex flex-wrap gap-3">
                {church.phone && (
                  <a
                    href={`tel:${church.phone}`}
                    className="inline-flex min-h-11 items-center gap-2 rounded-2xl bg-white px-4 py-3 text-sm font-bold text-[#03357A] shadow-sm hover:bg-[#F8FBFD]"
                  >
                    <Phone className="h-4 w-4" />
                    Appeler
                  </a>
                )}

                {whatsappUrl && (
                  <a
                    href={whatsappUrl}
                    target="_blank"
                    rel="noreferrer"
                    className="inline-flex min-h-11 items-center gap-2 rounded-2xl bg-white px-4 py-3 text-sm font-bold text-[#03357A] shadow-sm hover:bg-[#F8FBFD]"
                  >
                    <MessageCircle className="h-4 w-4" />
