        login_enabled: loginEnabled,
        youtube_channel_url: youtubeChannelUrl.trim() || null,
        latest_video_url: latestVideoUrl.trim() || null,
        news_title: newsTitle.trim() || null,
        news_description: newsDescription.trim() || null,
