function FilePicker({
  label,
  file,
  existingUrl,
  onChange,
}: {
  label: string;
  file: File | null;
  existingUrl: string | null;
  onChange: (file: File | null) => void;
}) {
  const [previewUrl, setPreviewUrl] = useState(existingUrl);

  useEffect(() => {
    if (!file) {
      setPreviewUrl(existingUrl);
      return;
    }

    const objectUrl = URL.createObjectURL(file);
    setPreviewUrl(objectUrl);

    return () => URL.revokeObjectURL(objectUrl);
  }, [file, existingUrl]);

  return (
    <div className="mt-2 rounded-2xl border border-dashed border-[#C9DBEA] bg-white p-4">
      {previewUrl ? (
        <div className="relative mb-4 h-40 overflow-hidden rounded-2xl bg-[#F8FBFD]">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img
            src={previewUrl}
            alt={label}
            className="h-full w-full object-contain p-3"
          />

          {file && (
            <button
              type="button"
              onClick={() => onChange(null)}
              className="absolute right-3 top-3 rounded-full bg-white p-2 text-red-600 shadow"
            >
              <X className="h-4 w-4" />
            </button>
          )}
        </div>
      ) : (
        <div className="mb-4 flex h-40 items-center justify-center rounded-2xl bg-[#F8FBFD]">
          <ImageIcon className="h-10 w-10 text-[#3F79B3]" />
        </div>
      )}

      <label className="flex cursor-pointer flex-col items-center justify-center rounded-2xl bg-[#EAF3FA] px-4 py-4 text-center hover:bg-[#DCEAF5]">
        <UploadCloud className="h-6 w-6 text-[#03357A]" />

        <span className="mt-2 text-sm font-bold text-[#03357A]">{label}</span>

        <span className="mt-1 text-xs text-slate-500">
          {file ? file.name : "PNG, JPG ou WEBP — max 5 Mo"}
        </span>

        <input
          type="file"
          accept="image/png,image/jpeg,image/webp"
          className="hidden"
          onChange={(event) => {
            const selectedFile = event.target.files?.[0] ?? null;
            onChange(selectedFile);
          }}
        />
      </label>
    </div>
  );
}

import { createAdminClient } from "@/lib/supabase/admin";

const SUBDOMAIN_TO_SLUG: Record<string, string> = {
  mdm: "maison-misericorde-cmp",
  icckinshasa: "iccrdc",
  iccrdc: "iccrdc",
};

function normalizeHost(host: string) {
  return host.split(":")[0].trim().toLowerCase();
}

export function getSlugFromHost(host: string) {
  const cleanHost = normalizeHost(host);
  const firstPart = cleanHost.split(".")[0] || "";

  if (SUBDOMAIN_TO_SLUG[firstPart]) return SUBDOMAIN_TO_SLUG[firstPart];

  if (
    firstPart &&
    !["www", "mpangi-church", "localhost", "127"].includes(firstPart)
  ) {
    return firstPart;
  }

  return "";
}

function field(row: any, key: string, fallback = "") {
  const value = row?.[key];

  return typeof value === "string" ? value.trim() || fallback : fallback;
}

function getShortName(name: string, slug: string) {
  if (slug === "maison-misericorde-cmp") return "MDM";
  if (slug === "iccrdc") return "ICC RDC";
  if (/maison.*mis[eé]ricorde/i.test(name)) return "MDM";
  if (/impact.*centre.*chr[eé]tien.*rdc/i.test(name)) return "ICC RDC";
  if (/impact.*centre.*chr[eé]tien/i.test(name)) return "ICC";

  return name.length > 12 ? name.slice(0, 12) : name || "Église";
}

export async function resolveTenantPwaData(host: string) {
  const cleanHost = normalizeHost(host);
  const slug = getSlugFromHost(cleanHost);
  const admin = createAdminClient();

  let church: any = null;

  if (slug) {
    const { data } = await admin
      .from("churches")
      .select("*")
      .eq("slug", slug)
      .maybeSingle();

    church = data ?? null;
  }

  const finalSlug = field(church, "slug", slug || "mpangi-church");
  const appName =
    field(church, "public_name") ||
    field(church, "name") ||
    "Mpangi-church";

  return {
    host: cleanHost,
    slug: finalSlug,
    church,
    appName,
    shortName: getShortName(appName, finalSlug),
    logoUrl: field(church, "logo_url"),
    themeColor: field(church, "theme_color", "#03357A"),
    backgroundColor: field(church, "background_color", "#F5F9FC"),
    version: field(church, "updated_at") || String(Date.now()),
  };
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

type BrowserPushSubscription = {
  endpoint?: string;
  keys?: {
    p256dh?: string;
    auth?: string;
  };
};

export async function POST(
  request: Request
) {
  try {
    const payload =
      await request.json();

    const subscription =
      (payload.subscription ||
        payload) as BrowserPushSubscription;

    const endpoint =
      subscription?.endpoint;

    const p256dh =
      subscription?.keys?.p256dh;

    const auth =
      subscription?.keys?.auth;

    if (
      !endpoint ||
      !p256dh ||
      !auth
    ) {
      return NextResponse.json(
        {
          error:
            "Subscription push invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const supabase =
      await createClient();

    const {
      data: { user },
    } = await supabase.auth.getUser();

    let profileId:
      | string
      | null = null;

    let churchId:
      | string
      | null =
      payload.churchId || null;

    if (user) {
      const { data: profile } =
        await supabase
          .from("profiles")
          .select(
            "id, church_id"
          )
          .eq(
            "user_id",
            user.id
          )
          .maybeSingle();

      if (profile?.id) {
        profileId =
          profile.id;
      }

      if (
        profile?.church_id
      ) {
        churchId =
          profile.church_id;
      }
    }

    if (
      !churchId &&
      payload.churchSlug
    ) {
      const { data: church } =
        await admin
          .from("churches")
          .select(
            "id, status, public_enabled"
          )
          .eq(
            "slug",
            String(
              payload.churchSlug
            ).trim()
          )
          .maybeSingle();

      if (
        church?.id &&
        church.status ===
          "active" &&
        church.public_enabled
      ) {
        churchId =
          church.id;
      }
    }

    if (!churchId) {
      return NextResponse.json(
        {
          error:
            "Église introuvable pour cette notification.",
        },
        { status: 400 }
      );
    }

    const {
      data: church,
      error: churchError,
    } = await admin
      .from("churches")
      .select(
        "id, status, public_enabled"
      )
      .eq("id", churchId)
      .maybeSingle();

    if (
      churchError ||
      !church ||
      church.status !==
        "active" ||
      !church.public_enabled
    ) {
      return NextResponse.json(
        {
          error:
            "Église non disponible.",
        },
        { status: 404 }
      );
    }

    const { error } =
      await admin
        .from(
          "church_notification_subscriptions"
        )
        .upsert(
          {
            church_id:
              churchId,
            profile_id:
              profileId,
            endpoint,
            p256dh,
            auth,
            user_agent:
              request.headers.get(
                "user-agent"
              ),
            active: true,
            updated_at:
              new Date().toISOString(),
          },
          {
            onConflict:
              "endpoint",
          }
        );

    if (error) {
      return NextResponse.json(
        {
          error:
            error.message,
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      ok: true,
      message:
        "Notifications activées.",
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        error:
          error?.message ||
          "Impossible d’activer les notifications.",
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import { sendChurchNotification } from "@/lib/notifications/push";

type PublicationAction =
  | "publish"
  | "unpublish"
  | "feature"
  | "unfeature"
  | "notify"
  | "delete";

type PatchPublicationBody = {
  publicationId?: string;
  action?: PublicationAction;
};

const PUBLICATION_TYPES = new Set([
  "news",
  "event",
  "announcement",
  "teaching",
  "sermon",
  "video",
  "message",
]);

const PUBLICATION_BUCKET = "church-publications";
const MAX_IMAGE_SIZE = 4 * 1024 * 1024;

function getString(value: unknown, maxLength = 5000) {
  if (value === null || value === undefined) {
    return "";
  }

  return String(value).trim().slice(0, maxLength);
}

function getBoolean(value: unknown) {
  return (
    value === true ||
    value === "true" ||
    value === "on" ||
    value === "1"
  );
}

function getYoutubeVideoId(url: string) {
  if (!url) return null;

  const watchMatch = url.match(/[?&]v=([^&]+)/);

  if (watchMatch?.[1]) {
    return watchMatch[1];
  }

  const shortMatch = url.match(/youtu\.be\/([^?&]+)/);

  if (shortMatch?.[1]) {
    return shortMatch[1];
  }

  const embedMatch = url.match(
    /youtube\.com\/embed\/([^?&/]+)/
  );

  return embedMatch?.[1] || null;
}

function getPublicationTypeLabel(value: string) {
  if (value === "news") return "Actualité";
  if (value === "event") return "Événement";
  if (value === "announcement") return "Annonce";
  if (value === "sermon") return "Prédication";
  if (value === "video") return "Vidéo";
  if (value === "message") return "Message";
  return "Enseignement";
}

async function getCurrentProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return {
      error: "Utilisateur non connecté.",
      status: 401,
      profile: null,
    };
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, user_id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) {
    return {
      error: "Profil utilisateur introuvable.",
      status: 404,
      profile: null,
    };
  }

  if (
    profile.status &&
    !["active", "actif"].includes(profile.status)
  ) {
    return {
      error: "Compte désactivé.",
      status: 403,
      profile: null,
    };
  }

  if (
    profile.role === "super_admin" ||
    !profile.church_id
  ) {
    return {
      error:
        "Cette action doit être effectuée depuis un espace église.",
      status: 403,
      profile: null,
    };
  }

  return {
    error: null,
    status: 200,
    profile,
  };
}

async function parseCreateBody(request: Request) {
  const contentType =
    request.headers.get("content-type") || "";

  if (
    contentType.includes(
      "multipart/form-data"
    )
  ) {
    const formData =
      await request.formData();

    const imageValue =
      formData.get("coverImage");

    return {
      title: getString(
        formData.get("title"),
        180
      ),
      excerpt: getString(
        formData.get("description"),
        1000
      ),
      content: getString(
        formData.get("content"),
        10000
      ),
      category:
        getString(
          formData.get("publicationType"),
          40
        ) || "teaching",
      videoUrl: getString(
        formData.get("videoUrl"),
        1000
      ),
      isPublished: getBoolean(
        formData.get("isPublished")
      ),
      isFeatured: getBoolean(
        formData.get("isFeatured")
      ),
      notify: getBoolean(
        formData.get("notify")
      ),
      coverImage:
        imageValue instanceof File &&
        imageValue.size > 0
          ? imageValue
          : null,
    };
  }

  const body =
    (await request.json()) as Record<
      string,
      unknown
    >;

  return {
    title: getString(
      body.title,
      180
    ),
    excerpt: getString(
      body.description,
      1000
    ),
    content: getString(
      body.content,
      10000
    ),
    category:
      getString(
        body.publicationType,
        40
      ) || "teaching",
    videoUrl: getString(
      body.videoUrl,
      1000
    ),
    isPublished: getBoolean(
      body.isPublished
    ),
    isFeatured: getBoolean(
      body.isFeatured
    ),
    notify: getBoolean(body.notify),
    coverImage: null as File | null,
  };
}

async function uploadCoverImage({
  admin,
  churchId,
  file,
}: {
  admin: ReturnType<
    typeof createAdminClient
  >;
  churchId: string;
  file: File;
}) {
  const allowedTypes =
    new Map<string, string>([
      ["image/jpeg", "jpg"],
      ["image/png", "png"],
      ["image/webp", "webp"],
    ]);

  const extension =
    allowedTypes.get(file.type);

  if (!extension) {
    throw new Error(
      "La photo doit être au format JPG, PNG ou WebP."
    );
  }

  if (file.size > MAX_IMAGE_SIZE) {
    throw new Error(
      "La photo ne peut pas dépasser 4 Mo."
    );
  }

  const objectPath = `${churchId}/${new Date().getUTCFullYear()}/${crypto.randomUUID()}.${extension}`;

  const content = Buffer.from(
    await file.arrayBuffer()
  );

  const { error } = await admin.storage
    .from(PUBLICATION_BUCKET)
    .upload(objectPath, content, {
      contentType: file.type,
      cacheControl: "3600",
      upsert: false,
    });

  if (error) {
    throw new Error(
      `Photo non envoyée : ${error.message}`
    );
  }

  const {
    data: { publicUrl },
  } = admin.storage
    .from(PUBLICATION_BUCKET)
    .getPublicUrl(objectPath);

  return {
    imageUrl: publicUrl,
    imagePath: objectPath,
  };
}

async function notifySubscribers({
  churchId,
  profileId,
  title,
  excerpt,
  category,
}: {
  churchId: string;
  profileId: string;
  title: string;
  excerpt: string;
  category: string;
}) {
  try {
    const result =
      await sendChurchNotification({
        churchId,
        createdBy: profileId,
        title: `${getPublicationTypeLabel(
          category
        )} : ${title}`,
        body:
          excerpt ||
          "Une nouvelle publication vient d’être ajoutée par votre église.",
        url: "/#actualites",
        type: "publication",
        data: {
          category,
        },
      });

    return {
      sentCount:
        result.successCount,
      failedCount:
        result.failureCount,
      warning:
        result.recipientsCount === 0
          ? "Publication enregistrée, mais aucun appareil n’est encore abonné."
          : null,
    };
  } catch (error: any) {
    return {
      sentCount: 0,
      failedCount: 0,
      warning:
        error?.message ||
        "Publication enregistrée, mais les notifications n’ont pas pu être envoyées.",
    };
  }
}

export async function POST(
  request: Request
) {
  let uploadedImagePath:
    | string
    | null = null;

  try {
    const {
      profile,
      error,
      status,
    } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json(
        { error },
        { status }
      );
    }

    const body =
      await parseCreateBody(request);

    if (!body.title) {
      return NextResponse.json(
        {
          error:
            "Le titre est obligatoire.",
        },
        { status: 400 }
      );
    }

    if (
      !PUBLICATION_TYPES.has(
        body.category
      )
    ) {
      return NextResponse.json(
        {
          error:
            "Type de publication invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    let imageUrl: string | null =
      null;

    if (body.coverImage) {
      const uploaded =
        await uploadCoverImage({
          admin,
          churchId:
            profile.church_id,
          file: body.coverImage,
        });

      imageUrl =
        uploaded.imageUrl;
      uploadedImagePath =
        uploaded.imagePath;
    }

    const published =
      body.isPublished ||
      body.notify;

    const youtubeVideoId =
      getYoutubeVideoId(
        body.videoUrl
      );

    const {
      data: publication,
      error: insertError,
    } = await admin
      .from(
        "church_publications"
      )
      .insert({
        church_id:
          profile.church_id,
        title: body.title,
        excerpt:
          body.excerpt || null,
        content:
          body.content || null,
        category:
          body.category,
        image_url:
          imageUrl,
        image_path:
          uploadedImagePath,
        video_url:
          body.videoUrl || null,
        youtube_url:
          body.videoUrl || null,
        youtube_video_id:
          youtubeVideoId,
        status: published
          ? "published"
          : "draft",
        is_public: true,
        is_featured:
          body.isFeatured,
        notify_subscribers:
          body.notify,
        published_at: published
          ? new Date().toISOString()
          : null,
        notified_at: null,
        created_by:
          profile.id,
        updated_by:
          profile.id,
      })
      .select(
        "id, title, excerpt, category"
      )
      .single();

    if (
      insertError ||
      !publication
    ) {
      if (uploadedImagePath) {
        await admin.storage
          .from(
            PUBLICATION_BUCKET
          )
          .remove([
            uploadedImagePath,
          ]);
      }

      return NextResponse.json(
        {
          error:
            insertError?.message ||
            "Impossible d’enregistrer la publication.",
          code:
            insertError?.code ||
            null,
          details:
            insertError?.details ||
            null,
          hint:
            insertError?.hint ||
            null,
        },
        { status: 400 }
      );
    }

    let sentCount = 0;
    let failedCount = 0;
    let warning:
      | string
      | null = null;

    if (body.notify) {
      const notifyResult =
        await notifySubscribers({
          churchId:
            profile.church_id,
          profileId:
            profile.id,
          title:
            publication.title,
          excerpt:
            publication.excerpt ||
            "",
          category:
            publication.category ||
            "teaching",
        });

      sentCount =
        notifyResult.sentCount;
      failedCount =
        notifyResult.failedCount;
      warning =
        notifyResult.warning;

      await admin
        .from(
          "church_publications"
        )
        .update({
          notified_at:
            new Date().toISOString(),
        })
        .eq(
          "id",
          publication.id
        )
        .eq(
          "church_id",
          profile.church_id
        );
    }

    return NextResponse.json({
      success: true,
      publicationId:
        publication.id,
      sentCount,
      failedCount,
      warning,
    });
  } catch (caughtError: any) {
    return NextResponse.json(
      {
        error:
          caughtError?.message ||
          "Erreur inattendue pendant la publication.",
        code:
          caughtError?.code ||
          null,
        details:
          caughtError?.details ||
          null,
        hint:
          caughtError?.hint ||
          null,
      },
      { status: 500 }
    );
  }
}

export async function PATCH(
  request: Request
) {
  try {
    const {
      profile,
      error,
      status,
    } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json(
        { error },
        { status }
      );
    }

    const body =
      (await request.json()) as PatchPublicationBody;

    const publicationId =
      getString(
        body.publicationId,
        80
      );

    const action =
      body.action;

    if (
      !publicationId ||
      !action
    ) {
      return NextResponse.json(
        {
          error:
            "Action invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const {
      data: publication,
      error:
        publicationError,
    } = await admin
      .from(
        "church_publications"
      )
      .select(
        "id, church_id, title, excerpt, category, status, is_featured, image_path"
      )
      .eq("id", publicationId)
      .eq(
        "church_id",
        profile.church_id
      )
      .maybeSingle();

    if (
      publicationError ||
      !publication
    ) {
      return NextResponse.json(
        {
          error:
            publicationError?.message ||
            "Publication introuvable.",
        },
        { status: 404 }
      );
    }

    if (action === "delete") {
      const { error: deleteError } =
        await admin
          .from(
            "church_publications"
          )
          .delete()
          .eq(
            "id",
            publicationId
          )
          .eq(
            "church_id",
            profile.church_id
          );

      if (deleteError) {
        return NextResponse.json(
          {
            error:
              deleteError.message,
          },
          { status: 400 }
        );
      }

      if (
        publication.image_path
      ) {
        await admin.storage
          .from(
            PUBLICATION_BUCKET
          )
          .remove([
            publication.image_path,
          ]);
      }

      return NextResponse.json({
        success: true,
      });
    }

    if (action === "notify") {
      if (
        publication.status !==
        "published"
      ) {
        await admin
          .from(
            "church_publications"
          )
          .update({
            status: "published",
            is_public: true,
            published_at:
              new Date().toISOString(),
            updated_by:
              profile.id,
          })
          .eq(
            "id",
            publicationId
          )
          .eq(
            "church_id",
            profile.church_id
          );
      }

      const notifyResult =
        await notifySubscribers({
          churchId:
            profile.church_id,
          profileId:
            profile.id,
          title:
            publication.title,
          excerpt:
            publication.excerpt ||
            "",
          category:
            publication.category ||
            "teaching",
        });

      await admin
        .from(
          "church_publications"
        )
        .update({
          notified_at:
            new Date().toISOString(),
          notify_subscribers:
            true,
          updated_by:
            profile.id,
        })
        .eq(
          "id",
          publicationId
        )
        .eq(
          "church_id",
          profile.church_id
        );

      return NextResponse.json({
        success: true,
        sentCount:
          notifyResult.sentCount,
        failedCount:
          notifyResult.failedCount,
        warning:
          notifyResult.warning,
      });
    }

    const updates: Record<
      string,
      unknown
    > = {
      updated_at:
        new Date().toISOString(),
      updated_by:
        profile.id,
    };

    if (action === "publish") {
      updates.status =
        "published";
      updates.is_public = true;
      updates.published_at =
        new Date().toISOString();
    }

    if (
      action === "unpublish"
    ) {
      updates.status = "draft";
    }

    if (action === "feature") {
      updates.is_featured = true;
    }

    if (
      action === "unfeature"
    ) {
      updates.is_featured = false;
    }

    const { error: updateError } =
      await admin
        .from(
          "church_publications"
        )
        .update(updates)
        .eq(
          "id",
          publicationId
        )
        .eq(
          "church_id",
          profile.church_id
        );

    if (updateError) {
      return NextResponse.json(
        {
          error:
            updateError.message,
          code:
            updateError.code ||
            null,
          details:
            updateError.details ||
            null,
          hint:
            updateError.hint ||
            null,
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      success: true,
    });
  } catch (caughtError: any) {
    return NextResponse.json(
      {
        error:
          caughtError?.message ||
          "Erreur inattendue pendant la mise à jour.",
        code:
          caughtError?.code ||
          null,
        details:
          caughtError?.details ||
          null,
        hint:
          caughtError?.hint ||
          null,
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";

type BrowserPushSubscription = {
  endpoint?: string;
  keys?: {
    p256dh?: string;
    auth?: string;
  };
};

export async function POST(
  request: Request
) {
  try {
    const body =
      await request.json();

    const churchId =
      String(
        body.churchId || ""
      ).trim();

    const subscription =
      body.subscription as BrowserPushSubscription;

    if (
      !churchId ||
      !subscription?.endpoint ||
      !subscription.keys?.p256dh ||
      !subscription.keys?.auth
    ) {
      return NextResponse.json(
        {
          error:
            "Abonnement invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const { data: church } =
      await admin
        .from("churches")
        .select(
          "id, status, public_enabled"
        )
        .eq("id", churchId)
        .maybeSingle();

    if (
      !church ||
      church.status !==
        "active" ||
      !church.public_enabled
    ) {
      return NextResponse.json(
        {
          error:
            "Église non disponible.",
        },
        { status: 404 }
      );
    }

    const { error } =
      await admin
        .from(
          "church_notification_subscriptions"
        )
        .upsert(
          {
            church_id:
              churchId,
            profile_id: null,
            endpoint:
              subscription.endpoint,
            p256dh:
              subscription.keys.p256dh,
            auth:
              subscription.keys.auth,
            user_agent:
              request.headers.get(
                "user-agent"
              ),
            active: true,
            updated_at:
              new Date().toISOString(),
          },
          {
            onConflict:
              "endpoint",
          }
        );

    if (error) {
      return NextResponse.json(
        {
          error:
            error.message,
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      success: true,
      message:
        "Notifications activées.",
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        error:
          error?.message ||
          "Erreur pendant l’activation des notifications.",
      },
      { status: 500 }
    );
  }
}

