function formatDate(
  value?: string | null
) {
  if (!value) return "-";

  return new Intl.DateTimeFormat(
    "fr-FR",
    {
      day: "2-digit",
      month: "short",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    }
  ).format(new Date(value));
}

function getTypeLabel(
  type?: string | null
) {
  if (type === "news") {
    return "Actualité";
