source:
"use client";

import {
  Bookmark,
  BookOpen,
  ChevronLeft,
  ChevronRight,
  Loader2,
  Minus,
  Moon,
  Search,
  Share2,
  Sun,
  Type,
  X,
} from "lucide-react";
import {
  FormEvent,
  useEffect,
  useMemo,
  useState,
} from "react";

type BibleVersion = {
  id: string;
  abbreviation?: string;
  abbreviationLocal?: string;
  name?: string;
  nameLocal?: string;
  copyright?: string;
  language?: {
    id?: string;
    name?: string;
    nameLocal?: string;
  };
};

type BibleChapterSummary = {
  id: string;
  bibleId: string;
  number: string;
  bookId: string;
  reference: string;
};

type BibleBook = {
  id: string;
  bibleId: string;
  abbreviation?: string;
  name: string;
  nameLong?: string;
  chapters?: BibleChapterSummary[];
};

type BibleChapterContent = {
  id: string;
  bibleId: string;
  number: string;
  bookId: string;
  reference: string;
  content: string;
  verseCount?: number;
  copyright?: string;
  next?: {
    id: string;
    number: string;
  } | null;
  previous?: {
    id: string;
    number: string;
  } | null;
};

type SearchVerse = {
  id: string;
  bibleId: string;
  bookId: string;
  chapterId: string;
  reference: string;
  text: string;
};

type ReaderTheme =
  | "light"
  | "sepia"
  | "dark";

const STORAGE_KEY =
  "mpangi-bible-reader-v2";

function getVersionLabel(
  version?: BibleVersion
) {
  if (!version) {
    return "Version";
  }

  const abbreviation =
    version.abbreviationLocal ||
    version.abbreviation ||
    "";

  const name =
    version.nameLocal ||
    version.name ||
    "Bible";

  return abbreviation
    ? `${abbreviation} — ${name}`
    : name;
}

function getShortBookName(
  book?: BibleBook
) {
  if (!book) return "Livre";

  const raw =
    book.name?.trim() ||
    book.nameLong?.trim() ||
    "Livre";

  const aliases: Array<
    [RegExp, string]
  > = [
    [
      /le premier livre de mo[iï]se.*gen[eè]se/i,
      "Genèse",
    ],
    [
      /le deuxi[eè]me livre de mo[iï]se.*exode/i,
      "Exode",
    ],
    [
      /le troisi[eè]me livre de mo[iï]se.*l[eé]vitique/i,
      "Lévitique",
    ],
    [
      /le quatri[eè]me livre de mo[iï]se.*nombres/i,
      "Nombres",
    ],
    [
      /le cinqui[eè]me livre de mo[iï]se.*deut[eé]ronome/i,
      "Deutéronome",
    ],
  ];

  for (const [
    pattern,
    replacement,
  ] of aliases) {
    if (pattern.test(raw)) {
      return replacement;
    }
  }

  return raw
    .replace(
      /^Le livre de\s+/i,
      ""
    )
    .replace(
      /^L['’]Évangile selon\s+/i,
      ""
    )
    .replace(
      /^Évangile selon\s+/i,
      ""
    );
}

function chapterOptions(
  book?: BibleBook
) {
  return (book?.chapters || []).filter(
    (chapter) =>
      chapter.id &&
      /^\d+$/.test(
        String(
          chapter.number
        )
      )
  );
}

function themeClasses(
  theme: ReaderTheme
) {
  if (theme === "dark") {
    return {
      shell:
        "bg-slate-950 text-slate-100",
      card:
        "border-slate-800 bg-slate-900",
      muted:
        "text-slate-300",
      field:
        "border-slate-700 bg-slate-950 text-slate-100",
      soft:
        "bg-slate-800 text-slate-100",
    };
  }

  if (theme === "sepia") {
    return {
      shell:
        "bg-[#F4E8D0] text-[#3B2F24]",
      card:
        "border-[#D8C49D] bg-[#FFF8E8]",
      muted:
        "text-[#6B5843]",
      field:
        "border-[#D8C49D] bg-[#FFFDF5] text-[#3B2F24]",
      soft:
        "bg-[#EAD8B5] text-[#4D3B2A]",
    };
  }

  return {
    shell:
      "bg-[#F5F9FC] text-slate-800",
    card:
      "border-[#DCEAF5] bg-white",
    muted:
      "text-slate-600",
    field:
      "border-[#C9DBEA] bg-white text-slate-900",
    soft:
      "bg-[#EAF3FA] text-[#03357A]",
  };
}

export default function BibleReaderClient({
  churchSlug,
  churchName,
}: {
  churchSlug: string;
  churchName: string;
}) {
  const [
    versions,
    setVersions,
  ] = useState<BibleVersion[]>(
    []
  );

  const [
    books,
    setBooks,
  ] = useState<BibleBook[]>(
    []
  );

  const [
    bibleId,
    setBibleId,
  ] = useState("");

  const [
    bookId,
    setBookId,
  ] = useState("");

  const [
    chapterId,
    setChapterId,
  ] = useState("");

  const [
    chapter,
    setChapter,
  ] =
    useState<BibleChapterContent | null>(
      null
    );

  const [
    loadingVersions,
    setLoadingVersions,
  ] = useState(true);

  const [
    loadingBooks,
    setLoadingBooks,
  ] = useState(false);

  const [
    loadingChapter,
    setLoadingChapter,
  ] = useState(false);

  const [
    error,
    setError,
  ] = useState("");

  const [
    fontScale,
    setFontScale,
  ] = useState(100);

  const [
    theme,
    setTheme,
  ] =
    useState<ReaderTheme>(
      "light"
    );

  const [
    searchOpen,
    setSearchOpen,
  ] = useState(false);

  const [
    searchQuery,
    setSearchQuery,
  ] = useState("");

  const [
    searchResults,
    setSearchResults,
  ] = useState<SearchVerse[]>(
    []
  );

  const [
    searching,
    setSearching,
  ] = useState(false);

  const [
    favorite,
    setFavorite,
  ] = useState(false);

  const selectedVersion =
    useMemo(
      () =>
        versions.find(
          (version) =>
            version.id ===
            bibleId
        ),
      [versions, bibleId]
    );

  const selectedBook =
    useMemo(
      () =>
        books.find(
          (book) =>
            book.id === bookId
        ),
      [books, bookId]
    );

  const chapters =
    useMemo(
      () =>
        chapterOptions(
          selectedBook
        ),
      [selectedBook]
    );

  const classes =
    themeClasses(theme);

  useEffect(() => {
    try {
      const saved =
        JSON.parse(
          localStorage.getItem(
            STORAGE_KEY
          ) || "{}"
        );

      if (
        typeof saved.fontScale ===
        "number"
      ) {
        setFontScale(
          Math.min(
            145,
            Math.max(
              85,
              saved.fontScale
            )
          )
        );
      }

      if (
        ["light", "sepia", "dark"].includes(
          saved.theme
        )
      ) {
        setTheme(
          saved.theme
        );
      }
    } catch {
      // Les préférences locales restent facultatives.
    }
  }, []);

  useEffect(() => {
    localStorage.setItem(
      STORAGE_KEY,
      JSON.stringify({
        bibleId,
        bookId,
        chapterId,
        fontScale,
        theme,
      })
    );
  }, [
    bibleId,
    bookId,
    chapterId,
    fontScale,
    theme,
  ]);

  useEffect(() => {
    let active = true;

    async function loadVersions() {
      setLoadingVersions(true);
      setError("");

      try {
        const response =
          await fetch(
            "/api/bible/versions",
            {
              cache: "no-store",
            }
          );

        const payload =
          await response.json();

        if (!response.ok) {
          throw new Error(
            payload.error ||
              "Impossible de charger les versions bibliques."
          );
        }

        const nextVersions =
          (payload.data ||
            []) as BibleVersion[];

        if (!active) return;

        setVersions(
          nextVersions
        );

        let savedBibleId = "";

        try {
          savedBibleId =
            JSON.parse(
              localStorage.getItem(
                STORAGE_KEY
              ) || "{}"
            ).bibleId || "";
        } catch {
          savedBibleId = "";
        }

        const firstId =
          nextVersions.find(
            (item) =>
              item.id ===
              savedBibleId
          )?.id ||
          payload.defaultBibleId ||
          nextVersions[0]?.id ||
          "";

        setBibleId(firstId);

        if (
          nextVersions.length === 0
        ) {
          setError(
            "Aucune version française n’est disponible avec la clé API.Bible actuelle."
          );
        }
      } catch (
        loadError: any
      ) {
        if (active) {
          setError(
            loadError?.message ||
              "Impossible de charger les versions bibliques."
          );
        }
      } finally {
        if (active) {
          setLoadingVersions(
            false
          );
        }
      }
    }

    loadVersions();

    return () => {
      active = false;
    };
  }, []);

  useEffect(() => {
    if (!bibleId) {
      setBooks([]);
      setBookId("");
      setChapterId("");
      setChapter(null);
      return;
    }

    let active = true;

    async function loadBooks() {
      setLoadingBooks(true);
      setError("");

      try {
        const response =
          await fetch(
            `/api/bible/books?bibleId=${encodeURIComponent(
              bibleId
            )}`,
            {
              cache: "no-store",
            }
          );

        const payload =
          await response.json();

        if (!response.ok) {
          throw new Error(
            payload.error ||
              "Impossible de charger les livres."
          );
        }

        const nextBooks =
          (payload.data ||
            []) as BibleBook[];

        if (!active) return;

        setBooks(nextBooks);

        let savedBookId = "";

        try {
          savedBookId =
            JSON.parse(
              localStorage.getItem(
                STORAGE_KEY
              ) || "{}"
            ).bookId || "";
        } catch {
          savedBookId = "";
        }

        const nextBook =
          nextBooks.find(
            (item) =>
              item.id ===
              savedBookId
          ) ||
          nextBooks.find(
            (item) =>
              item.id
                .toUpperCase()
                .startsWith(
                  "GEN"
                )
          ) ||
          nextBooks[0];

        setBookId(
          nextBook?.id || ""
        );

        const nextChapters =
          chapterOptions(
            nextBook
          );

        setChapterId(
          nextChapters[0]?.id ||
            ""
        );
      } catch (
        loadError: any
      ) {
        if (active) {
          setError(
            loadError?.message ||
              "Impossible de charger les livres."
          );
        }
      } finally {
        if (active) {
          setLoadingBooks(
            false
          );
        }
      }
    }

    loadBooks();

    return () => {
      active = false;
    };
  }, [bibleId]);

  useEffect(() => {
    if (
      !bibleId ||
      !chapterId
    ) {
      setChapter(null);
      return;
    }

    let active = true;

    async function loadChapter() {
      setLoadingChapter(
        true
      );
      setError("");

      try {
        const response =
          await fetch(
            `/api/bible/chapter?bibleId=${encodeURIComponent(
              bibleId
            )}&chapterId=${encodeURIComponent(
              chapterId
            )}`,
            {
              cache: "no-store",
            }
          );

        const payload =
          await response.json();

        if (!response.ok) {
          throw new Error(
            [
              payload.error,
              payload.details
                ? JSON.stringify(
                    payload.details
                  )
                : "",
            ]
              .filter(Boolean)
              .join(" — ")
          );
        }

        if (active) {
          setChapter(
            payload.data ||
              null
          );
        }
      } catch (
        loadError: any
      ) {
        if (active) {
          setChapter(null);
          setError(
            loadError?.message ||
              "Impossible de charger ce chapitre."
          );
        }
      } finally {
        if (active) {
          setLoadingChapter(
            false
          );
        }
      }
    }

    loadChapter();

    return () => {
      active = false;
    };
  }, [
    bibleId,
    chapterId,
  ]);

  useEffect(() => {
    if (!chapter?.reference) {
      setFavorite(false);
      return;
    }

    try {
      const favorites =
        JSON.parse(
          localStorage.getItem(
            "mpangi-bible-favorites"
          ) || "[]"
        ) as string[];

      setFavorite(
        favorites.includes(
          `${bibleId}:${chapter.id}`
        )
      );
    } catch {
      setFavorite(false);
    }
  }, [
    bibleId,
    chapter?.id,
    chapter?.reference,
  ]);

  function handleBookChange(
    nextBookId: string
  ) {
    setBookId(nextBookId);

    const nextBook =
      books.find(
        (item) =>
          item.id ===
          nextBookId
      );

    const nextChapters =
      chapterOptions(nextBook);

    setChapterId(
      nextChapters[0]?.id ||
        ""
    );
  }

  async function shareChapter() {
    const title =
      chapter?.reference ||
      `${getShortBookName(
        selectedBook
      )} ${chapter?.number || ""}`;

    const text = `${title} — ${getVersionLabel(
      selectedVersion
    )}`;

    try {
      if (navigator.share) {
        await navigator.share({
          title,
          text,
          url:
            window.location.href,
        });
      } else {
        await navigator.clipboard.writeText(
          `${text}\n${window.location.href}`
        );

        alert(
          "Lien copié dans le presse-papiers."
        );
      }
    } catch {
      // Un abandon volontaire du partage n'est pas une erreur.
    }
  }

  function toggleFavorite() {
    if (!chapter?.id) return;

    const key =
      `${bibleId}:${chapter.id}`;

    let favorites: string[] =
      [];

    try {
      favorites =
        JSON.parse(
          localStorage.getItem(
            "mpangi-bible-favorites"
          ) || "[]"
        );
    } catch {
      favorites = [];
    }

    const next =
      favorites.includes(key)
        ? favorites.filter(
            (item) =>
              item !== key
          )
        : [
            ...favorites,
            key,
          ];

    localStorage.setItem(
      "mpangi-bible-favorites",
      JSON.stringify(next)
    );

    setFavorite(
      next.includes(key)
    );
  }

  async function runSearch(
    event: FormEvent
  ) {
    event.preventDefault();

    if (
      searchQuery.trim().length <
      2
    ) {
      setError(
        "Saisissez au moins deux caractères pour la recherche."
      );
      return;
    }

    setSearching(true);
    setError("");

    try {
      const response =
        await fetch(
          `/api/bible/search?bibleId=${encodeURIComponent(
            bibleId
          )}&query=${encodeURIComponent(
            searchQuery.trim()
          )}`,
          {
            cache: "no-store",
          }
        );

      const payload =
        await response.json();

      if (!response.ok) {
        throw new Error(
          payload.error ||
            "La recherche a échoué."
        );
      }

      setSearchResults(
        payload.data || []
      );
    } catch (
      searchError: any
    ) {
      setError(
        searchError?.message ||
          "La recherche a échoué."
      );
    } finally {
      setSearching(false);
    }
  }

  function openSearchResult(
    result: SearchVerse
  ) {
    setBookId(
      result.bookId
    );
    setChapterId(
      result.chapterId
    );
    setSearchOpen(false);
    setSearchResults([]);
    setSearchQuery("");
  }

  return (
    <div
      data-bible-reader
      data-bible-theme={theme}
      className={[
        "mx-auto w-full max-w-7xl space-y-4 rounded-[1.5rem] transition-colors",
        classes.shell,
