  churchId: string;
};

function getTypeLabel(
  type?: string | null
) {
  if (type === "news") {
    return "Actualité";
  }

  if (type === "event") {
    return "Événement";
  }

  if (
    type === "announcement"
  ) {
    return "Annonce";
  }

  if (type === "sermon") {
    return "Prédication";
  }

  if (type === "video") {
    return "Vidéo";
  }

  if (type === "message") {
    return "Message";
  }

  return "Enseignement";
}

function getYoutubeEmbedUrl(
  url?: string | null
) {
  if (!url) return null;

  if (
    url.includes(
      "youtube.com/embed/"
    )
  ) {
    return url;
  }

  const watchMatch =
    url.match(/[?&]v=([^&]+)/);

  if (watchMatch?.[1]) {
    return `https://www.youtube.com/embed/${watchMatch[1]}`;
  }

  const shortMatch =
    url.match(
      /youtu\.be\/([^?&]+)/
    );

  if (shortMatch?.[1]) {
    return `https://www.youtube.com/embed/${shortMatch[1]}`;
  }

  return null;
}

function formatDate(
  value?: string | null
) {
  if (!value) return "";

  return new Intl.DateTimeFormat(
    "fr-FR",
    {
      day: "2-digit",
      month: "short",
      year: "numeric",
    }
  ).format(new Date(value));
}

export default async function PublicTeachingsSection({
  churchId,
}: PublicTeachingsSectionProps) {
  const supabase =
    await createClient();

  const { data: publications } =
    await supabase
      .from(
        "church_publications"
      )
      .select(
        `
        id,
        title,
        excerpt,
        content,
        category,
        image_url,
        video_url,
        status,
        is_public,
        is_featured,
        published_at
      `
      )
      .eq(
        "church_id",
        churchId
      )
      .eq(
        "status",
        "published"
      )
      .eq("is_public", true)
      .order("is_featured", {
        ascending: false,
      })
      .order("published_at", {
        ascending: false,
      })
      .limit(8);

  const items =
    publications ?? [];

  if (items.length === 0) {
    return null;
  }

  const featured =
    items.find(
      (item: any) =>
        item.is_featured
    ) || items[0];

  const others =
    items.filter(
      (item: any) =>
        item.id !== featured.id
    );

  const featuredEmbed =
    getYoutubeEmbedUrl(
      featured.video_url
