"use client";

import {
  BellRing,
  CalendarDays,
  ImagePlus,
  Loader2,
  Send,
  Star,
  X,
} from "lucide-react";
import {
  FormEvent,
  useMemo,
  useState,
} from "react";
import { useRouter } from "next/navigation";

const inputClass =
  "mpangi-form-control min-h-12";

const textareaClass =
  "mpangi-form-control min-h-28 py-3";

const MAX_IMAGE_SIZE =
  4 * 1024 * 1024;

export default function PublicationForm() {
  const router = useRouter();

  const [isLoading, setIsLoading] =
    useState(false);

  const [message, setMessage] =
    useState("");

  const [error, setError] =
    useState("");

  const [
    previewUrl,
    setPreviewUrl,
  ] = useState<string | null>(
    null
  );

  const [
    selectedFileName,
    setSelectedFileName,
  ] = useState("");

  const previewStyle =
    useMemo(
      () =>
        previewUrl
          ? {
              backgroundImage: `url("${previewUrl}")`,
            }
          : undefined,
      [previewUrl]
    );

  function clearImage(
    input?: HTMLInputElement | null
  ) {
    if (previewUrl) {
      URL.revokeObjectURL(
        previewUrl
      );
    }

    setPreviewUrl(null);
    setSelectedFileName("");

    if (input) {
      input.value = "";
    }
  }

  async function handleSubmit(
    event: FormEvent<HTMLFormElement>
  ) {
    event.preventDefault();

    const formElement =
      event.currentTarget;

    const form =
      new FormData(formElement);

    const image =
      form.get("coverImage");

    if (
      image instanceof File &&
      image.size >
        MAX_IMAGE_SIZE
    ) {
      setError(
        "La photo ne peut pas dépasser 4 Mo."
      );
      return;
    }

    setIsLoading(true);
    setMessage("");
    setError("");

    try {
      const response = await fetch(
        "/api/publications",
        {
          method: "POST",
          body: form,
        }
      );

      const payload =
        await response.json();

      if (!response.ok) {
        const detail = [
          payload.error,
          payload.details,
          payload.hint,
        ]
          .filter(Boolean)
          .join(" — ");

        throw new Error(
          detail ||
            "Erreur pendant l’enregistrement."
        );
      }

      formElement.reset();
      clearImage();

      setMessage(
        payload.warning ||
          `Publication enregistrée. Notifications envoyées : ${
            payload.sentCount || 0
          }.`
      );

      router.refresh();
    } catch (
      submitError: any
    ) {
      setError(
        submitError?.message ||
          "Une erreur a empêché la publication."
      );
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <form
      onSubmit={handleSubmit}
      className="rounded-[1.75rem] border border-[#DCEAF5] bg-white p-4 shadow-sm sm:p-6"
    >
      <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between">
        <div>
          <p className="text-xs font-black uppercase tracking-[0.2em] text-[#3F79B3]">
            Communication
          </p>

          <h2 className="mt-2 text-2xl font-black text-[#03357A]">
            Nouvelle publication
          </h2>

          <p className="mt-2 max-w-3xl text-sm leading-7 text-slate-600">
            Publiez une actualité,
            un événement, une
            annonce, une vidéo ou
            un enseignement. Une
            photo peut être mise en
            vedette sur la page
            publique.
          </p>
        </div>

        <div className="inline-flex items-center gap-2 rounded-2xl bg-[#EAF3FA] px-4 py-3 text-xs font-black text-[#03357A]">
          <CalendarDays className="h-4 w-4" />
          Visible immédiatement si
          « Publier » est coché
        </div>
      </div>

      {error && (
        <div className="mt-5 rounded-2xl border border-red-100 bg-red-50 p-4 text-sm font-bold leading-6 text-red-700">
          {error}
        </div>
      )}

      {message && (
        <div className="mt-5 rounded-2xl border border-green-100 bg-green-50 p-4 text-sm font-bold leading-6 text-green-700">
          {message}
        </div>
      )}

      <div className="mt-6 grid gap-4 md:grid-cols-2">
        <label className="space-y-2">
          <span className="text-sm font-black text-[#03357A]">
            Titre *
          </span>

          <input
            name="title"
            required
            maxLength={180}
            className={inputClass}
            placeholder="Titre de la publication"
          />
        </label>

        <label className="space-y-2">
          <span className="text-sm font-black text-[#03357A]">
            Type
          </span>

          <select
            name="publicationType"
            defaultValue="news"
            className={inputClass}
          >
            <option value="news">
              Actualité
            </option>
            <option value="event">
              Événement
            </option>
            <option value="announcement">
              Annonce
            </option>
            <option value="teaching">
              Enseignement
            </option>
            <option value="sermon">
              Prédication
            </option>
            <option value="video">
              Vidéo
            </option>
            <option value="message">
              Message d’édification
            </option>
          </select>
        </label>

        <label className="space-y-2 md:col-span-2">
          <span className="text-sm font-black text-[#03357A]">
            Lien vidéo YouTube
          </span>

          <input
            name="videoUrl"
            type="url"
            className={inputClass}
            placeholder="https://www.youtube.com/watch?v=..."
          />
        </label>

        <label className="space-y-2 md:col-span-2">
          <span className="text-sm font-black text-[#03357A]">
            Résumé court
          </span>

          <textarea
            name="description"
            maxLength={1000}
            className={textareaClass}
            placeholder="Résumé visible sur la page publique..."
          />
        </label>

        <label className="space-y-2 md:col-span-2">
          <span className="text-sm font-black text-[#03357A]">
            Contenu complet
          </span>

          <textarea
            name="content"
            maxLength={10000}
            className="mpangi-form-control min-h-40 py-3"
            placeholder="Texte complet, programme, passage biblique, informations pratiques..."
          />
        </label>

        <div className="md:col-span-2">
          <p className="text-sm font-black text-[#03357A]">
            Photo de couverture
          </p>

          <p className="mt-1 text-xs font-semibold leading-5 text-slate-500">
            JPG, PNG ou WebP. Maximum
            4 Mo. Ratio conseillé :
            16:9.
          </p>

          <label className="mt-3 block cursor-pointer">
            <input
              name="coverImage"
              type="file"
              accept="image/jpeg,image/png,image/webp"
              className="sr-only"
              onChange={(event) => {
                const file =
                  event.target
                    .files?.[0];

                if (!file) {
                  clearImage(
                    event.currentTarget
                  );
                  return;
                }

                if (
                  file.size >
                  MAX_IMAGE_SIZE
                ) {
                  setError(
                    "La photo ne peut pas dépasser 4 Mo."
                  );
                  clearImage(
                    event.currentTarget
                  );
                  return;
                }

                if (previewUrl) {
                  URL.revokeObjectURL(
                    previewUrl
                  );
                }

                setPreviewUrl(
                  URL.createObjectURL(
                    file
                  )
                );

                setSelectedFileName(
                  file.name
                );

                setError("");
              }}
            />

            <div
              className={[
                "relative flex min-h-52 items-center justify-center overflow-hidden rounded-3xl border-2 border-dashed bg-[#F8FBFD] bg-cover bg-center p-5 transition",
                previewUrl
                  ? "border-[#2563EB]"
                  : "border-[#C9DBEA] hover:border-[#03357A]",
              ].join(" ")}
              style={previewStyle}
            >
              {previewUrl && (
                <div className="absolute inset-0 bg-slate-950/25" />
              )}

              <div className="relative z-10 flex flex-col items-center text-center">
                <div className="flex h-14 w-14 items-center justify-center rounded-2xl bg-white text-[#03357A] shadow-lg">
                  <ImagePlus className="h-7 w-7" />
                </div>

                <p
                  className={[
                    "mt-3 max-w-xs text-sm font-black",
                    previewUrl
                      ? "text-white"
                      : "text-[#03357A]",
                  ].join(" ")}
                >
                  {selectedFileName ||
                    "Choisir une photo"}
                </p>

                <p
                  className={[
                    "mt-1 text-xs font-semibold",
                    previewUrl
                      ? "text-white/90"
                      : "text-slate-500",
                  ].join(" ")}
                >
                  Touchez pour remplacer
                  l’image
                </p>
              </div>
            </div>
          </label>

          {previewUrl && (
            <button
              type="button"
              onClick={() => {
                const input =
                  document.querySelector<HTMLInputElement>(
                    'input[name="coverImage"]'
                  );

                clearImage(input);
              }}
              className="mt-3 inline-flex min-h-10 items-center gap-2 rounded-xl bg-red-50 px-4 text-xs font-black text-red-700"
            >
              <X className="h-4 w-4" />
              Retirer la photo
            </button>
          )}
        </div>
      </div>

      <div className="mt-5 grid gap-3 sm:grid-cols-3">
        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="isPublished"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          Publier sur la page
          publique
        </label>

        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="isFeatured"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          <Star className="h-4 w-4 text-amber-500" />
          Mettre en vedette
        </label>

        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="notify"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          <BellRing className="h-4 w-4 text-green-600" />
          Notifier les abonnés
        </label>
      </div>

      <div className="mt-6 flex justify-end">
        <button
          type="submit"
          disabled={isLoading}
          className="inline-flex min-h-12 w-full items-center justify-center gap-2 rounded-2xl bg-gradient-to-r from-[#03357A] to-[#2563EB] px-6 py-3 text-sm font-black text-white shadow-lg shadow-blue-900/20 disabled:opacity-60 sm:w-auto"
        >
          {isLoading ? (
            <Loader2 className="h-5 w-5 animate-spin" />
          ) : (
            <Send className="h-5 w-5" />
          )}

          {isLoading
            ? "Publication en cours..."
            : "Enregistrer la publication"}
        </button>
      </div>
    </form>
  );
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import { sendChurchNotification } from "@/lib/notifications/push";

type PublicationAction =
  | "publish"
  | "unpublish"
  | "feature"
  | "unfeature"
  | "notify"
  | "delete";

type PatchPublicationBody = {
  publicationId?: string;
  action?: PublicationAction;
};

const PUBLICATION_TYPES = new Set([
  "news",
  "event",
  "announcement",
  "teaching",
  "sermon",
  "video",
  "message",
]);

const PUBLICATION_BUCKET = "church-publications";
const MAX_IMAGE_SIZE = 4 * 1024 * 1024;

function getString(value: unknown, maxLength = 5000) {
  if (value === null || value === undefined) {
    return "";
  }

  return String(value).trim().slice(0, maxLength);
}

function getBoolean(value: unknown) {
  return (
    value === true ||
    value === "true" ||
    value === "on" ||
    value === "1"
  );
}

function getYoutubeVideoId(url: string) {
  if (!url) return null;

  const watchMatch = url.match(/[?&]v=([^&]+)/);

  if (watchMatch?.[1]) {
    return watchMatch[1];
  }

  const shortMatch = url.match(/youtu\.be\/([^?&]+)/);

  if (shortMatch?.[1]) {
    return shortMatch[1];
  }

  const embedMatch = url.match(
    /youtube\.com\/embed\/([^?&/]+)/
  );

  return embedMatch?.[1] || null;
}

function getPublicationTypeLabel(value: string) {
  if (value === "news") return "Actualité";
  if (value === "event") return "Événement";
  if (value === "announcement") return "Annonce";
  if (value === "sermon") return "Prédication";
  if (value === "video") return "Vidéo";
  if (value === "message") return "Message";
  return "Enseignement";
}

async function getCurrentProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return {
      error: "Utilisateur non connecté.",
      status: 401,
      profile: null,
    };
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, user_id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) {
    return {
      error: "Profil utilisateur introuvable.",
      status: 404,
      profile: null,
    };
  }

  if (
    profile.status &&
    !["active", "actif"].includes(profile.status)
  ) {
    return {
      error: "Compte désactivé.",
      status: 403,
      profile: null,
    };
  }

  if (
    profile.role === "super_admin" ||
    !profile.church_id
  ) {
    return {
      error:
        "Cette action doit être effectuée depuis un espace église.",
      status: 403,
      profile: null,
    };
  }

  return {
    error: null,
    status: 200,
    profile,
  };
}

async function parseCreateBody(request: Request) {
  const contentType =
    request.headers.get("content-type") || "";

  if (
    contentType.includes(
      "multipart/form-data"
    )
  ) {
    const formData =
      await request.formData();

    const imageValue =
      formData.get("coverImage");

    return {
      title: getString(
        formData.get("title"),
        180
      ),
      excerpt: getString(
        formData.get("description"),
        1000
      ),
      content: getString(
        formData.get("content"),
        10000
      ),
      category:
        getString(
          formData.get("publicationType"),
          40
        ) || "teaching",
      videoUrl: getString(
        formData.get("videoUrl"),
        1000
      ),
      isPublished: getBoolean(
        formData.get("isPublished")
      ),
      isFeatured: getBoolean(
        formData.get("isFeatured")
      ),
      notify: getBoolean(
        formData.get("notify")
      ),
      coverImage:
        imageValue instanceof File &&
        imageValue.size > 0
          ? imageValue
          : null,
    };
  }

  const body =
    (await request.json()) as Record<
      string,
      unknown
    >;

  return {
    title: getString(
      body.title,
      180
    ),
    excerpt: getString(
      body.description,
      1000
    ),
    content: getString(
      body.content,
      10000
    ),
    category:
      getString(
        body.publicationType,
        40
      ) || "teaching",
    videoUrl: getString(
      body.videoUrl,
      1000
    ),
    isPublished: getBoolean(
      body.isPublished
    ),
    isFeatured: getBoolean(
      body.isFeatured
    ),
    notify: getBoolean(body.notify),
    coverImage: null as File | null,
  };
}

async function uploadCoverImage({
  admin,
  churchId,
  file,
}: {
  admin: ReturnType<
    typeof createAdminClient
  >;
  churchId: string;
  file: File;
}) {
  const allowedTypes =
    new Map<string, string>([
      ["image/jpeg", "jpg"],
      ["image/png", "png"],
      ["image/webp", "webp"],
    ]);

  const extension =
    allowedTypes.get(file.type);

  if (!extension) {
    throw new Error(
      "La photo doit être au format JPG, PNG ou WebP."
    );
  }

  if (file.size > MAX_IMAGE_SIZE) {
    throw new Error(
      "La photo ne peut pas dépasser 4 Mo."
    );
  }

  const objectPath = `${churchId}/${new Date().getUTCFullYear()}/${crypto.randomUUID()}.${extension}`;

  const content = Buffer.from(
    await file.arrayBuffer()
  );

  const { error } = await admin.storage
    .from(PUBLICATION_BUCKET)
    .upload(objectPath, content, {
      contentType: file.type,
      cacheControl: "3600",
      upsert: false,
    });

  if (error) {
    throw new Error(
      `Photo non envoyée : ${error.message}`
    );
  }

  const {
    data: { publicUrl },
  } = admin.storage
    .from(PUBLICATION_BUCKET)
    .getPublicUrl(objectPath);

  return {
    imageUrl: publicUrl,
    imagePath: objectPath,
  };
}

async function notifySubscribers({
  churchId,
  profileId,
  title,
  excerpt,
  category,
}: {
  churchId: string;
  profileId: string;
  title: string;
  excerpt: string;
  category: string;
}) {
  try {
    const result =
      await sendChurchNotification({
        churchId,
        createdBy: profileId,
        title: `${getPublicationTypeLabel(
          category
        )} : ${title}`,
        body:
          excerpt ||
          "Une nouvelle publication vient d’être ajoutée par votre église.",
        url: "/#actualites",
        type: "publication",
        data: {
          category,
        },
      });

    return {
      sentCount:
        result.successCount,
      failedCount:
        result.failureCount,
      warning:
        result.recipientsCount === 0
          ? "Publication enregistrée, mais aucun appareil n’est encore abonné."
          : null,
    };
  } catch (error: any) {
    return {
      sentCount: 0,
      failedCount: 0,
      warning:
        error?.message ||
        "Publication enregistrée, mais les notifications n’ont pas pu être envoyées.",
    };
  }
}

export async function POST(
  request: Request
) {
  let uploadedImagePath:
    | string
    | null = null;

  try {
    const {
      profile,
      error,
      status,
    } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json(
        { error },
        { status }
      );
    }

    const body =
      await parseCreateBody(request);

    if (!body.title) {
      return NextResponse.json(
        {
          error:
            "Le titre est obligatoire.",
        },
        { status: 400 }
      );
    }

    if (
      !PUBLICATION_TYPES.has(
        body.category
      )
    ) {
      return NextResponse.json(
        {
          error:
            "Type de publication invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    let imageUrl: string | null =
      null;

    if (body.coverImage) {
      const uploaded =
        await uploadCoverImage({
          admin,
          churchId:
            profile.church_id,
          file: body.coverImage,
        });

      imageUrl =
        uploaded.imageUrl;
      uploadedImagePath =
        uploaded.imagePath;
    }

    const published =
      body.isPublished ||
      body.notify;

    const youtubeVideoId =
      getYoutubeVideoId(
        body.videoUrl
      );

    const {
      data: publication,
      error: insertError,
    } = await admin
      .from(
        "church_publications"
      )
      .insert({
        church_id:
          profile.church_id,
        title: body.title,
        excerpt:
          body.excerpt || null,
        content:
          body.content || null,
        category:
          body.category,
        image_url:
          imageUrl,
        image_path:
          uploadedImagePath,
        video_url:
          body.videoUrl || null,
        youtube_url:
          body.videoUrl || null,
        youtube_video_id:
          youtubeVideoId,
        status: published
          ? "published"
          : "draft",
        is_public: true,
        is_featured:
          body.isFeatured,
        notify_subscribers:
          body.notify,
        published_at: published
          ? new Date().toISOString()
          : null,
        notified_at: null,
        created_by:
          profile.id,
        updated_by:
          profile.id,
      })
      .select(
        "id, title, excerpt, category"
      )
      .single();

    if (
      insertError ||
      !publication
    ) {
      if (uploadedImagePath) {
        await admin.storage
          .from(
            PUBLICATION_BUCKET
          )
          .remove([
            uploadedImagePath,
          ]);
      }

      return NextResponse.json(
        {
          error:
            insertError?.message ||
            "Impossible d’enregistrer la publication.",
          code:
            insertError?.code ||
            null,
          details:
            insertError?.details ||
            null,
          hint:
            insertError?.hint ||
            null,
        },
        { status: 400 }
      );
    }

    let sentCount = 0;
    let failedCount = 0;
    let warning:
      | string
      | null = null;

    if (body.notify) {
      const notifyResult =
        await notifySubscribers({
          churchId:
            profile.church_id,
          profileId:
            profile.id,
          title:
            publication.title,
          excerpt:
            publication.excerpt ||
            "",
          category:
            publication.category ||
            "teaching",
        });

      sentCount =
        notifyResult.sentCount;
      failedCount =
        notifyResult.failedCount;
      warning =
        notifyResult.warning;

      await admin
        .from(
          "church_publications"
        )
        .update({
          notified_at:
            new Date().toISOString(),
        })
        .eq(
          "id",
          publication.id
        )
        .eq(
          "church_id",
          profile.church_id
        );
    }

    return NextResponse.json({
      success: true,
      publicationId:
        publication.id,
      sentCount,
      failedCount,
      warning,
    });
  } catch (caughtError: any) {
    return NextResponse.json(
      {
        error:
          caughtError?.message ||
          "Erreur inattendue pendant la publication.",
        code:
          caughtError?.code ||
          null,
        details:
          caughtError?.details ||
          null,
        hint:
          caughtError?.hint ||
          null,
      },
      { status: 500 }
    );
  }
}

export async function PATCH(
  request: Request
) {
  try {
    const {
      profile,
      error,
      status,
    } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json(
        { error },
        { status }
      );
    }

    const body =
      (await request.json()) as PatchPublicationBody;

    const publicationId =
      getString(
        body.publicationId,
        80
      );

    const action =
      body.action;

    if (
      !publicationId ||
      !action
    ) {
      return NextResponse.json(
        {
          error:
            "Action invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const {
      data: publication,
      error:
        publicationError,
    } = await admin
      .from(
        "church_publications"
      )
      .select(
        "id, church_id, title, excerpt, category, status, is_featured, image_path"
      )
      .eq("id", publicationId)
      .eq(
        "church_id",
        profile.church_id
      )
      .maybeSingle();

    if (
      publicationError ||
      !publication
    ) {
      return NextResponse.json(
        {
          error:
            publicationError?.message ||
            "Publication introuvable.",
        },
        { status: 404 }
      );
    }

    if (action === "delete") {
      const { error: deleteError } =
        await admin
          .from(
            "church_publications"
          )
          .delete()
          .eq(
            "id",
            publicationId
          )
          .eq(
            "church_id",
            profile.church_id
          );

      if (deleteError) {
        return NextResponse.json(
          {
            error:
              deleteError.message,
          },
          { status: 400 }
        );
      }

      if (
        publication.image_path
      ) {
        await admin.storage
          .from(
            PUBLICATION_BUCKET
          )
          .remove([
            publication.image_path,
          ]);
      }

      return NextResponse.json({
        success: true,
      });
    }

    if (action === "notify") {
      if (
        publication.status !==
        "published"
      ) {
        await admin
          .from(
            "church_publications"
          )
          .update({
            status: "published",
            is_public: true,
            published_at:
              new Date().toISOString(),
            updated_by:
              profile.id,
          })
          .eq(
            "id",
            publicationId
          )
          .eq(
            "church_id",
            profile.church_id
          );
      }

      const notifyResult =
        await notifySubscribers({
          churchId:
            profile.church_id,
          profileId:
            profile.id,
          title:
            publication.title,
          excerpt:
            publication.excerpt ||
            "",
          category:
            publication.category ||
            "teaching",
        });

      await admin
        .from(
          "church_publications"
        )
        .update({
          notified_at:
            new Date().toISOString(),
          notify_subscribers:
            true,
          updated_by:
            profile.id,
        })
        .eq(
          "id",
          publicationId
        )
        .eq(
          "church_id",
          profile.church_id
        );

      return NextResponse.json({
        success: true,
        sentCount:
          notifyResult.sentCount,
        failedCount:
          notifyResult.failedCount,
        warning:
          notifyResult.warning,
      });
    }

    const updates: Record<
      string,
      unknown
    > = {
      updated_at:
        new Date().toISOString(),
      updated_by:
        profile.id,
    };

    if (action === "publish") {
      updates.status =
        "published";
      updates.is_public = true;
      updates.published_at =
        new Date().toISOString();
    }

    if (
      action === "unpublish"
    ) {
      updates.status = "draft";
    }

    if (action === "feature") {
      updates.is_featured = true;
    }

    if (
      action === "unfeature"
    ) {
      updates.is_featured = false;
    }

    const { error: updateError } =
      await admin
        .from(
          "church_publications"
        )
        .update(updates)
        .eq(
          "id",
          publicationId
        )
        .eq(
          "church_id",
          profile.church_id
        );

    if (updateError) {
      return NextResponse.json(
        {
          error:
            updateError.message,
          code:
            updateError.code ||
            null,
          details:
            updateError.details ||
            null,
          hint:
            updateError.hint ||
            null,
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      success: true,
    });
  } catch (caughtError: any) {
    return NextResponse.json(
      {
        error:
          caughtError?.message ||
          "Erreur inattendue pendant la mise à jour.",
        code:
          caughtError?.code ||
          null,
        details:
          caughtError?.details ||
          null,
        hint:
          caughtError?.hint ||
          null,
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";

type BrowserPushSubscription = {
  endpoint?: string;
  keys?: {
    p256dh?: string;
    auth?: string;
  };
};

export async function POST(
  request: Request
) {
  try {
    const body =
      await request.json();

    const churchId =
      String(
        body.churchId || ""
      ).trim();

    const subscription =
      body.subscription as BrowserPushSubscription;

    if (
      !churchId ||
      !subscription?.endpoint ||
      !subscription.keys?.p256dh ||
      !subscription.keys?.auth
    ) {
      return NextResponse.json(
        {
          error:
            "Abonnement invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const { data: church } =
      await admin
        .from("churches")
        .select(
          "id, status, public_enabled"
        )
        .eq("id", churchId)
        .maybeSingle();

    if (
      !church ||
      church.status !==
        "active" ||
      !church.public_enabled
    ) {
      return NextResponse.json(
        {
          error:
            "Église non disponible.",
        },
        { status: 404 }
      );
    }

    const { error } =
      await admin
        .from(
          "church_notification_subscriptions"
        )
        .upsert(
          {
            church_id:
              churchId,
            profile_id: null,
            endpoint:
              subscription.endpoint,
            p256dh:
              subscription.keys.p256dh,
            auth:
              subscription.keys.auth,
            user_agent:
              request.headers.get(
                "user-agent"
              ),
            active: true,
            updated_at:
              new Date().toISOString(),
          },
          {
            onConflict:
              "endpoint",
          }
        );

    if (error) {
      return NextResponse.json(
        {
          error:
            error.message,
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      success: true,
      message:
        "Notifications activées.",
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        error:
          error?.message ||
          "Erreur pendant l’activation des notifications.",
      },
      { status: 500 }
    );
  }
}

import Link from "next/link";
import {
  CheckCircle2,
  Clock3,
  Settings,
  Wallet,
} from "lucide-react";
import { redirect } from "next/navigation";
import { updateDonationStatusAction } from "./actions";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import {
  DONATION_STATUSES,
  formatDonationAmount,
  getDonationChannelLabel,
  getDonationMethodLabel,
  getDonationPurposeLabel,
  getDonationStatusLabel,
} from "@/lib/donations/constants";

type PageProps = {
  searchParams: Promise<{
    status?: string;
    error?: string;
  }>;
};

const ALLOWED_ROLES = new Set([
  "super_admin",
  "church_admin",
  "admin_eglise",
  "pasteur_t",
  "pastor",
  "charge_afp",
]);

export default async function FinanceDonationsPage({
  searchParams,
}: PageProps) {
  const query = await searchParams;
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    redirect("/login?reason=auth_required");
  }

  const admin = createAdminClient();

  const { data: profile } = await admin
    .from("profiles")
    .select("role, church_id")
    .eq("user_id", user.id)
    .maybeSingle();

  if (
    !profile ||
    !profile.church_id ||
    !ALLOWED_ROLES.has(String(profile.role))
  ) {
    redirect("/unauthorized?reason=donations_access");
  }

  let donationsQuery = admin
    .from("church_donations")
    .select("*")
    .eq("church_id", profile.church_id)
    .order("created_at", { ascending: false })
    .limit(300);

  if (
    query.status &&
    DONATION_STATUSES.some(
      (item) => item.value === query.status
    )
  ) {
    donationsQuery = donationsQuery.eq("status", query.status);
  }

  const { data: donations, error } = await donationsQuery;

  const rows = donations || [];
  const confirmed = rows.filter(
    (item) => item.status === "confirmed"
  );
  const pending = rows.filter(
    (item) =>
      item.status === "pending" ||
      item.status === "awaiting_payment" ||
      item.status === "submitted"
  );

  const totalsByCurrency = confirmed.reduce(
    (acc: Record<string, number>, item) => {
      const currency = item.currency || "CDF";
      acc[currency] =
        (acc[currency] || 0) + Number(item.amount || 0);
      return acc;
    },
    {}
  );

  return (
    <main className="min-h-screen bg-[#F5F9FC] px-3 py-5 pb-24 sm:px-6 sm:py-8">
      <div className="mx-auto max-w-7xl">
        <header className="rounded-[1.75rem] bg-gradient-to-br from-[#03357A] via-[#2563EB] to-[#8B5CF6] p-5 text-white sm:p-7">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between">
            <div>
              <p className="text-xs font-black uppercase tracking-[0.22em] text-blue-100">
                Volet finances
              </p>
              <h1 className="mt-2 text-3xl font-black">
                Dons reçus
              </h1>
              <p className="mt-3 text-sm leading-7 text-blue-50">
                Suivez les intentions de dons et confirmez les
                paiements réellement reçus.
              </p>
            </div>

            <Link
              href="/settings/donations"
              className="inline-flex min-h-11 items-center justify-center gap-2 rounded-2xl bg-white px-4 py-3 text-sm font-black text-[#03357A]"
            >
              <Settings className="h-4 w-4" />
              Configurer
            </Link>
          </div>
        </header>

        {query.error && (
          <div className="mt-4 rounded-2xl bg-red-50 p-4 text-sm font-bold text-red-700">
            {query.error}
          </div>
        )}

        {error && (
          <div className="mt-4 rounded-2xl bg-red-50 p-4 text-sm font-bold text-red-700">
            {error.message}
          </div>
        )}

        <section className="mt-5 grid gap-3 sm:grid-cols-3">
          <Metric
            icon={Wallet}
            label="Intentions"
            value={String(rows.length)}
          />
          <Metric
            icon={Clock3}
            label="À vérifier"
            value={String(pending.length)}
          />
          <Metric
            icon={CheckCircle2}
            label="Confirmés"
            value={String(confirmed.length)}
          />
        </section>

        {Object.keys(totalsByCurrency).length > 0 && (
          <section className="mt-5 rounded-[1.5rem] border border-[#DCEAF5] bg-white p-4 shadow-sm sm:p-5">
            <h2 className="font-black text-[#03357A]">
              Total confirmé par devise
            </h2>
            <div className="mt-3 flex flex-wrap gap-2">
              {Object.entries(totalsByCurrency).map(
                ([currency, amount]) => (
                  <span
                    key={currency}
                    className="rounded-full bg-green-50 px-4 py-2 text-sm font-black text-green-700"
                  >
                    {formatDonationAmount(amount, currency)}
                  </span>
                )
              )}
            </div>
          </section>
        )}

        <nav className="mt-5 flex gap-2 overflow-x-auto pb-2">
          <Filter href="/finance/donations" label="Tous" />
          {DONATION_STATUSES.map((item) => (
            <Filter
              key={item.value}
              href={`/finance/donations?status=${item.value}`}
              label={item.label}
            />
          ))}
        </nav>

        <section className="mt-3 overflow-hidden rounded-[1.5rem] border border-[#DCEAF5] bg-white shadow-sm">
          {rows.length === 0 ? (
            <div className="p-10 text-center text-sm font-bold text-slate-500">
              Aucun don correspondant à ce filtre.
            </div>
          ) : (
            <div className="divide-y divide-[#DCEAF5]">
              {rows.map((donation) => (
                <article
                  key={donation.id}
                  className="grid gap-4 p-4 lg:grid-cols-[1fr_auto] lg:items-center sm:p-5"
                >
                  <div className="min-w-0">
                    <div className="flex flex-wrap items-center gap-2">
                      <span className="rounded-full bg-[#EAF3FA] px-3 py-1 text-xs font-black text-[#03357A]">
                        {donation.reference}
                      </span>
                      <span className="rounded-full bg-slate-100 px-3 py-1 text-xs font-bold text-slate-600">
                        {getDonationStatusLabel(donation.status)}
                      </span>
                    </div>

                    <h2 className="mt-3 break-words text-xl font-black text-[#03357A]">
                      {formatDonationAmount(
                        donation.amount,
                        donation.currency
                      )}
                    </h2>

                    <div className="mt-2 flex flex-wrap gap-x-5 gap-y-2 text-sm text-slate-600">
                      <span>
                        {getDonationPurposeLabel(donation.purpose)}
                      </span>
                      <span>
                        {getDonationMethodLabel(donation.method)}
                      </span>
                      <span>
                        {donation.is_anonymous
                          ? "Don anonyme"
                          : donation.donor_name || "Donateur non renseigné"}
                      </span>
                      <span>
                        {new Date(
                          donation.created_at
                        ).toLocaleString("fr-FR")}
                      </span>
                    </div>

                    {donation.note && (
                      <p className="mt-3 break-words text-sm leading-6 text-slate-500">
                        {donation.note}
                      </p>
                    )}
                  </div>

                  <form
                    action={updateDonationStatusAction}
                    className="flex flex-col gap-2 sm:flex-row"
                  >
                    <input
                      type="hidden"
                      name="donation_id"
                      value={donation.id}
                    />

                    <select
                      name="status"
                      defaultValue={donation.status}
                      className="min-h-11 rounded-xl border border-[#DCEAF5] bg-[#F8FBFD] px-3 text-sm font-bold text-[#03357A]"
                    >
                      {DONATION_STATUSES.map((item) => (
                        <option
                          key={item.value}
                          value={item.value}
                        >
                          {item.label}
                        </option>
                      ))}
                    </select>

                    <button
                      type="submit"
                      className="min-h-11 rounded-xl bg-[#03357A] px-4 text-sm font-black text-white"
                    >
                      Mettre à jour
                    </button>
                  </form>
                </article>
              ))}
            </div>
          )}
        </section>
      </div>
    </main>
  );
}

function Metric({
  icon: Icon,
  label,
  value,
}: {
  icon: typeof Wallet;
  label: string;
  value: string;
}) {
  return (
    <div className="rounded-[1.5rem] border border-[#DCEAF5] bg-white p-4 shadow-sm">
      <Icon className="h-6 w-6 text-[#03357A]" />
      <p className="mt-4 text-sm font-bold text-slate-500">
        {label}
      </p>
      <p className="mt-1 text-3xl font-black text-[#03357A]">
        {value}
      </p>
    </div>
  );
}

function Filter({
  href,
  label,
}: {
  href: string;
  label: string;
}) {
  return (
    <Link
      href={href}
      className="whitespace-nowrap rounded-full bg-white px-4 py-2 text-sm font-black text-[#03357A] shadow-sm ring-1 ring-[#DCEAF5]"
    >
      {label}
    </Link>
  );
}

"use server";

import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { requireChurchModuleAccess } from "@/lib/modules/moduleAccess";
import { sendChurchNotification } from "@/lib/notifications/push";
import {
  extractYouTubeVideoId,
  getYouTubeThumbnailUrl,
} from "@/lib/youtube";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
function text(value: FormDataEntryValue | null) {
  return value === null || value === undefined ? "" : String(value).trim();
}

function normalizeStatus(status: string) {
  if (["draft", "published", "archived"].includes(status)) return status;
  return "draft";
}

function payloadFromForm(formData: FormData) {
  const youtubeUrl = text(formData.get("youtube_url"));
  const videoId = extractYouTubeVideoId(youtubeUrl);
  const status = normalizeStatus(text(formData.get("status")));
  const now = new Date().toISOString();

  return {
    title: text(formData.get("title")),
    description: text(formData.get("description")) || null,
    youtube_url: youtubeUrl,
    youtube_video_id: videoId,
    thumbnail_url: videoId ? getYouTubeThumbnailUrl(videoId) : null,
    teacher_name: text(formData.get("teacher_name")) || null,
    category: text(formData.get("category")) || null,
    status,
    is_featured: formData.get("is_featured") === "on",
    published_at: status === "published" ? now : null,
  };
}

async function getChurchSlug(admin: any, churchId: string) {
  const { data: church } = await admin
    .from("churches")
    .select("slug")
    .eq("id", churchId)
    .maybeSingle();

  return church?.slug || "";
}

export async function createTeachingAction(formData: FormData) {
  await requireAnyActionPermission(["teachings"], "create");
  const { admin, profile } = await requireChurchModuleAccess("teachings");
  const payload = payloadFromForm(formData);

  if (!payload.title || !payload.youtube_url || !payload.youtube_video_id) {
    redirect("/teachings/new?error=required");
  }

  const { data, error } = await admin
    .from("church_teachings")
    .insert({
      church_id: profile.church_id,
      ...payload,
      created_by: profile.id,
      updated_by: profile.id,
    })
    .select("id, status, title, description")
    .single();

  if (error || !data) {
    redirect(`/teachings/new?error=${encodeURIComponent(error?.message || "create")}`);
  }

  if (payload.status === "published") {
    const slug = await getChurchSlug(admin, profile.church_id);

    await sendChurchNotification({
      churchId: profile.church_id,
      title: "Nouvel enseignement publié",
      body: payload.title,
      url: slug ? `/church/${slug}/teachings/${data.id}` : "/teachings",
      type: "teaching_published",
      createdBy: profile.id,
      data: { teachingId: data.id },
    });
  }

  revalidatePath("/teachings");
  revalidatePath("/church");
  redirect(`/teachings/${data.id}`);
}

export async function updateTeachingAction(formData: FormData) {
  await requireAnyActionPermission(["teachings"], "update");
  const { admin, profile } = await requireChurchModuleAccess("teachings");
  const id = text(formData.get("id"));
  const payload = payloadFromForm(formData);

  if (!id) redirect("/teachings");

  if (!payload.title || !payload.youtube_url || !payload.youtube_video_id) {
    redirect(`/teachings/${id}/edit?error=required`);
  }

  const { error } = await admin
    .from("church_teachings")
    .update({
      ...payload,
      updated_by: profile.id,
      updated_at: new Date().toISOString(),
    })
    .eq("church_id", profile.church_id)
    .eq("id", id);

  if (error) {
    redirect(`/teachings/${id}/edit?error=${encodeURIComponent(error.message)}`);
  }

  revalidatePath("/teachings");
  revalidatePath(`/teachings/${id}`);
  redirect(`/teachings/${id}`);
}

export async function publishTeachingAction(formData: FormData) {
  await requireAnyActionPermission(["teachings"], "update");
  const { admin, profile } = await requireChurchModuleAccess("teachings");
  const id = text(formData.get("id"));

  if (!id) redirect("/teachings");

  const now = new Date().toISOString();

  const { data: teaching } = await admin
    .from("church_teachings")
    .update({
      status: "published",
      published_at: now,
      updated_by: profile.id,
      updated_at: now,
    })
    .eq("church_id", profile.church_id)
    .eq("id", id)
    .select("id, title, description")
    .single();

  if (teaching) {
    const slug = await getChurchSlug(admin, profile.church_id);

    await sendChurchNotification({
      churchId: profile.church_id,
      title: "Nouvel enseignement publié",
      body: teaching.title,
      url: slug ? `/church/${slug}/teachings/${teaching.id}` : "/teachings",
      type: "teaching_published",
      createdBy: profile.id,
      data: { teachingId: teaching.id },
    });
  }

  revalidatePath("/teachings");
  revalidatePath(`/teachings/${id}`);
  redirect(`/teachings/${id}?published=1`);
}

export async function archiveTeachingAction(formData: FormData) {
  await requireAnyActionPermission(["teachings"], "delete");
  const { admin, profile } = await requireChurchModuleAccess("teachings");
  const id = text(formData.get("id"));

  if (!id) redirect("/teachings");

  await admin
    .from("church_teachings")
    .update({
      status: "archived",
      updated_by: profile.id,
      updated_at: new Date().toISOString(),
    })
    .eq("church_id", profile.church_id)
    .eq("id", id);

  revalidatePath("/teachings");
  redirect("/teachings");
}

"use client";

import {
  BellRing,
  CheckCircle2,
  Loader2,
} from "lucide-react";
import {
  useEffect,
  useState,
} from "react";

type NotificationSubscribeButtonProps = {
  churchId: string;
  label?: string;
  className?: string;
};

function urlBase64ToUint8Array(
  base64String: string
) {
  const padding = "=".repeat(
    (
      4 -
      (base64String.length %
        4)
    ) % 4
  );

  const base64 =
    `${base64String}${padding}`
      .replace(/-/g, "+")
      .replace(/_/g, "/");

  const rawData =
    window.atob(base64);

  const outputArray =
    new Uint8Array(
      rawData.length
    );

  for (
    let index = 0;
    index < rawData.length;
    index += 1
  ) {
    outputArray[index] =
      rawData.charCodeAt(
        index
      );
  }

  return outputArray;
}

export default function NotificationSubscribeButton({
  churchId,
  label = "Activer les notifications",
  className,
}: NotificationSubscribeButtonProps) {
  const [
    isSupported,
    setIsSupported,
  ] = useState(false);

  const [
    isSubscribed,
    setIsSubscribed,
  ] = useState(false);

  const [
    isLoading,
    setIsLoading,
  ] = useState(false);

  const [
    message,
    setMessage,
  ] = useState("");

  useEffect(() => {
    let active = true;

    async function detectStatus() {
      const supported =
        typeof window !==
          "undefined" &&
        "Notification" in
          window &&
        "serviceWorker" in
          navigator &&
        "PushManager" in
          window;

      if (!active) return;

      setIsSupported(
        supported
      );

      if (!supported) return;

      try {
        const registration =
          await navigator.serviceWorker.getRegistration(
            "/"
          );

        const subscription =
          await registration?.pushManager.getSubscription();

        if (active) {
          setIsSubscribed(
            Boolean(
              subscription &&
                Notification.permission ===
                  "granted"
            )
          );
        }
      } catch {
        if (active) {
          setIsSubscribed(
            false
          );
        }
      }
    }

    detectStatus();

    return () => {
      active = false;
    };
  }, []);

  async function handleSubscribe() {
    setMessage("");

    if (!isSupported) {
      setMessage(
        "Ce navigateur ne supporte pas les notifications Push."
      );
      return;
    }

    const publicKey =
      process.env
        .NEXT_PUBLIC_VAPID_PUBLIC_KEY;

    if (!publicKey) {
      setMessage(
        "La clé publique VAPID n’est pas configurée."
      );
      return;
    }

    setIsLoading(true);

    try {
      const registration =
        (
          await navigator.serviceWorker.getRegistration(
            "/"
          )
        ) ||
        (
          await navigator.serviceWorker.register(
            "/sw.js",
            {
              scope: "/",
            }
          )
        );

      await navigator.serviceWorker.ready;

      const permission =
        await Notification.requestPermission();

      if (
        permission !==
        "granted"
      ) {
        setMessage(
          "Autorisation refusée. Réactivez les notifications dans les paramètres du site."
        );
        return;
      }

      let subscription =
        await registration.pushManager.getSubscription();

      if (!subscription) {
        subscription =
          await registration.pushManager.subscribe(
            {
              userVisibleOnly:
                true,
              applicationServerKey:
                urlBase64ToUint8Array(
                  publicKey
                ),
            }
          );
      }

      const response =
        await fetch(
          "/api/push/subscribe",
          {
            method: "POST",
            headers: {
              "Content-Type":
                "application/json",
            },
            body: JSON.stringify({
              churchId,
              subscription:
                subscription.toJSON(),
            }),
          }
        );

      const payload =
        await response.json();

      if (!response.ok) {
        throw new Error(
          payload.error ||
            "Impossible d’activer les notifications."
        );
      }

      setIsSubscribed(true);
      setMessage(
        "Notifications activées sur cet appareil."
      );
    } catch (
      subscribeError: any
    ) {
      setMessage(
        subscribeError?.message ||
          "Impossible d’activer les notifications."
      );
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <div>
      <button
        type="button"
        onClick={
          handleSubscribe
        }
        disabled={
          isLoading ||
          isSubscribed
        }
        className={
          className ||
          [
            "inline-flex min-h-12 items-center justify-center gap-2 rounded-2xl px-5 py-3 text-sm font-black shadow-sm transition",
            isSubscribed
              ? "bg-green-50 text-green-700"
              : "bg-[#03357A] text-white hover:bg-[#022B63]",
          ].join(" ")
        }
      >
        {isLoading ? (
          <Loader2 className="h-4 w-4 animate-spin" />
        ) : isSubscribed ? (
          <CheckCircle2 className="h-4 w-4" />
        ) : (
          <BellRing className="h-4 w-4" />
        )}

        {isSubscribed
          ? "Notifications activées"
          : label}
      </button>

      {!isSupported && (
        <p className="mt-2 max-w-md text-xs font-semibold leading-5 text-amber-700">
          Ce navigateur ne
          supporte pas les
          notifications Push.
        </p>
      )}

      {message && (
        <p className="mt-2 max-w-md text-xs font-semibold leading-5 text-slate-600">
          {message}
        </p>
      )}
    </div>
  );
}

"use client";

import {
  BellRing,
  CalendarDays,
