const inputClass =
  "mpangi-form-control min-h-12";

const textareaClass =
  "mpangi-form-control min-h-28 py-3";

const MAX_IMAGE_SIZE =
  4 * 1024 * 1024;

export default function PublicationForm() {
  const router = useRouter();

  const [isLoading, setIsLoading] =
    useState(false);

  const [message, setMessage] =
    useState("");

  const [error, setError] =
    useState("");

  const [
    previewUrl,
    setPreviewUrl,
  ] = useState<string | null>(
    null
  );

  const [
    selectedFileName,
    setSelectedFileName,
  ] = useState("");

  const previewStyle =
    useMemo(
      () =>
        previewUrl
          ? {
              backgroundImage: `url("${previewUrl}")`,
            }
          : undefined,
      [previewUrl]
    );

  function clearImage(
    input?: HTMLInputElement | null
  ) {
    if (previewUrl) {
      URL.revokeObjectURL(
        previewUrl
      );
    }

    setPreviewUrl(null);
    setSelectedFileName("");

    if (input) {
      input.value = "";
    }
