            <option value="news">
              Actualité
            </option>
            <option value="event">
              Événement
            </option>
            <option value="announcement">
              Annonce
            </option>
            <option value="teaching">
              Enseignement
            </option>
            <option value="sermon">
              Prédication
            </option>
            <option value="video">
