              accept="image/jpeg,image/png,image/webp"
              className="sr-only"
              onChange={(event) => {
                const file =
                  event.target
                    .files?.[0];

                if (!file) {
                  clearImage(
                    event.currentTarget
                  );
                  return;
                }

                if (
                  file.size >
                  MAX_IMAGE_SIZE
                ) {
                  setError(
                    "La photo ne peut pas dépasser 4 Mo."
                  );
                  clearImage(
                    event.currentTarget
                  );
                  return;
                }

                if (previewUrl) {
                  URL.revokeObjectURL(
                    previewUrl
                  );
                }

                setPreviewUrl(
                  URL.createObjectURL(
                    file
                  )
                );

                setSelectedFileName(
                  file.name
                );

                setError("");
              }}
            />

            <div
              className={[
                "relative flex min-h-52 items-center justify-center overflow-hidden rounded-3xl border-2 border-dashed bg-[#F8FBFD] bg-cover bg-center p-5 transition",
                previewUrl
                  ? "border-[#2563EB]"
                  : "border-[#C9DBEA] hover:border-[#03357A]",
              ].join(" ")}
              style={previewStyle}
            >
              {previewUrl && (
                <div className="absolute inset-0 bg-slate-950/25" />
              )}

              <div className="relative z-10 flex flex-col items-center text-center">
                <div className="flex h-14 w-14 items-center justify-center rounded-2xl bg-white text-[#03357A] shadow-lg">
                  <ImagePlus className="h-7 w-7" />
                </div>

                <p
                  className={[
                    "mt-3 max-w-xs text-sm font-black",
                    previewUrl
                      ? "text-white"
                      : "text-[#03357A]",
