      <div className="mt-5 grid gap-3 sm:grid-cols-3">
        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="isPublished"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          Publier sur la page
          publique
        </label>

        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="isFeatured"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          <Star className="h-4 w-4 text-amber-500" />
          Mettre en vedette
        </label>

        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="notify"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          <BellRing className="h-4 w-4 text-green-600" />
          Notifier les abonnés
        </label>
      </div>

      <div className="mt-6 flex justify-end">
        <button
          type="submit"
          disabled={isLoading}
          className="inline-flex min-h-12 w-full items-center justify-center gap-2 rounded-2xl bg-gradient-to-r from-[#03357A] to-[#2563EB] px-6 py-3 text-sm font-black text-white shadow-lg shadow-blue-900/20 disabled:opacity-60 sm:w-auto"
        >
          {isLoading ? (
            <Loader2 className="h-5 w-5 animate-spin" />
          ) : (
            <Send className="h-5 w-5" />
          )}

          {isLoading
            ? "Publication en cours..."
            : "Enregistrer la publication"}
        </button>
      </div>
    </form>
  );
}

import webpush from "web-push";
import { createAdminClient } from "@/lib/supabase/admin";

let configured = false;

function configureWebPush() {
  if (configured) return;

  const publicKey = process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY;
  const privateKey = process.env.VAPID_PRIVATE_KEY;
  const subject =
    process.env.VAPID_SUBJECT || "mailto:aksantictech@gmail.com";

  if (!publicKey || !privateKey) {
    throw new Error(
      "Variables VAPID manquantes : NEXT_PUBLIC_VAPID_PUBLIC_KEY et VAPID_PRIVATE_KEY."
    );
  }

  webpush.setVapidDetails(subject, publicKey, privateKey);
  configured = true;
}

export type SendChurchNotificationInput = {
  churchId: string;
  title: string;
  body?: string;
  url?: string;
  type?: string;
  createdBy?: string | null;
  data?: Record<string, unknown>;
};

export async function sendChurchNotification({
  churchId,
  title,
  body,
  url,
  type = "manual",
  createdBy = null,
  data = {},
}: SendChurchNotificationInput) {
  configureWebPush();

  const admin = createAdminClient();

  const { data: subscriptions } = await admin
    .from("church_notification_subscriptions")
    .select("id, endpoint, p256dh, auth")
    .eq("church_id", churchId)
    .eq("active", true);

  const rows = subscriptions ?? [];

  let successCount = 0;
  let failureCount = 0;

  const payload = JSON.stringify({
    title,
    body: body || "",
    url: url || "/",
    type,
    data,
  });

  await Promise.all(
    rows.map(async (subscription: any) => {
      try {
        await webpush.sendNotification(
          {
            endpoint: subscription.endpoint,
            keys: {
              p256dh: subscription.p256dh,
              auth: subscription.auth,
            },
          },
          payload
        );

        successCount += 1;
      } catch (error: any) {
        failureCount += 1;

        if (error?.statusCode === 404 || error?.statusCode === 410) {
          await admin
            .from("church_notification_subscriptions")
            .update({
              active: false,
              updated_at: new Date().toISOString(),
            })
            .eq("id", subscription.id);
        }
      }
    })
  );

  await admin.from("church_notification_logs").insert({
    church_id: churchId,
    title,
    body: body || null,
    url: url || null,
    type,
    status: failureCount > 0 && successCount === 0 ? "failed" : "sent",
    recipients_count: rows.length,
    success_count: successCount,
    failure_count: failureCount,
    created_by: createdBy,
  });

  return {
    recipientsCount: rows.length,
    successCount,
    failureCount,
  };
}

