function urlBase64ToUint8Array(
  base64String: string
) {
  const padding = "=".repeat(
    (
      4 -
      (base64String.length %
        4)
    ) % 4
  );

  const base64 =
    `${base64String}${padding}`
      .replace(/-/g, "+")
      .replace(/_/g, "/");

  const rawData =
    window.atob(base64);

  return Uint8Array.from(
    rawData,
    (character) =>
      character.charCodeAt(0)
  );
}

async function readPayload(
  response: Response
) {
  const raw =
    await response.text();

  if (!raw) return {};

  try {
    return JSON.parse(raw);
  } catch {
    return {
      error:
        raw.slice(0, 400),
    };
  }
}

export default function NotificationPermissionCard({
  churchSlug,
}: {
  churchSlug?: string;
}) {
  const [
    supported,
    setSupported,
  ] = useState(true);

  const [
    permission,
    setPermission,
  ] =
    useState<NotificationPermission>(
      "default"
    );

  const [
    subscribed,
    setSubscribed,
  ] = useState(false);

  const [
    loading,
    setLoading,
  ] = useState(false);

  const [
    message,
    setMessage,
  ] = useState("");

  useEffect(() => {
    let active = true;

    async function detect() {
      const isSupported =
        typeof window !==
          "undefined" &&
        "serviceWorker" in
          navigator &&
        "PushManager" in
          window &&
        "Notification" in
          window;

      if (!active) return;

      setSupported(
        isSupported
      );

      if (!isSupported) return;

      setPermission(
        Notification.permission
      );

      const registration =
        await navigator.serviceWorker.getRegistration(
          "/"
        );

      const existing =
        await registration?.pushManager.getSubscription();

      if (active) {
        setSubscribed(
          Boolean(
            existing &&
              Notification.permission ===
                "granted"
          )
        );
      }
    }

    detect().catch(() => {
      if (active) {
        setSubscribed(false);
      }
    });

    return () => {
      active = false;
    };
  }, []);

  async function activateNotifications() {
    try {
      setLoading(true);
      setMessage("");

      if (
        Notification.permission ===
        "denied"
      ) {
        setPermission("denied");
        setMessage(
          "Les notifications ont déjà été bloquées dans les permissions du navigateur."
        );
        return;
      }

      const vapidPublicKey =
        process.env
          .NEXT_PUBLIC_VAPID_PUBLIC_KEY;

      if (!vapidPublicKey) {
        setMessage(
          "Clé VAPID publique manquante dans Vercel."
        );
        return;
      }

      const result =
        await Notification.requestPermission();

      setPermission(result);

      if (
        result !==
        "granted"
      ) {
        setMessage(
          "Notifications refusées par le navigateur."
        );
        return;
      }

      const registration =
        (
          await navigator.serviceWorker.getRegistration(
            "/"
          )
        ) ||
        (
          await navigator.serviceWorker.register(
            "/sw.js",
            {
              scope: "/",
            }
          )
        );

      await navigator.serviceWorker.ready;

      const existingSubscription =
        await registration.pushManager.getSubscription();

      const subscription =
        existingSubscription ||
        (
          await registration.pushManager.subscribe(
            {
              userVisibleOnly:
                true,
              applicationServerKey:
                urlBase64ToUint8Array(
                  vapidPublicKey
                ),
            }
          )
        );

      const response =
        await fetch(
          "/api/notifications/subscribe",
          {
            method: "POST",
            headers: {
              "Content-Type":
                "application/json",
            },
            body: JSON.stringify({
              subscription:
                subscription.toJSON(),
              churchSlug,
            }),
          }
        );

      const payload =
        await readPayload(
          response
        );

      if (!response.ok) {
        setMessage(
          payload.error ||
            "Activation impossible."
        );
        return;
      }

      setSubscribed(true);
      setMessage(
        "Notifications activées sur cet appareil."
      );
    } catch (error: any) {
      setMessage(
        error?.message ||
          "Activation impossible."
      );
    } finally {
      setLoading(false);
    }
  }

  if (!supported) {
    return (
      <div className="rounded-3xl border border-orange-100 bg-orange-50 p-5 text-orange-800">
        <div className="flex items-start gap-3">
          <WifiOff className="h-6 w-6 shrink-0" />
          <div>
            <h3 className="font-black">
              Notifications non supportées
            </h3>
            <p className="mt-1 text-sm">
              Ce navigateur ne supporte pas les notifications Web Push.
            </p>
          </div>
        </div>
      </div>
    );
  }

  const denied =
    permission === "denied";

  return (
    <section className="rounded-3xl border border-[#DCEAF5] bg-white p-5 shadow-sm">
      <div className="flex items-start gap-3">
        <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-2xl bg-[#EAF3FA] text-[#03357A]">
          <BellRing className="h-6 w-6" />
        </div>

        <div className="min-w-0">
          <h3 className="font-black text-[#03357A]">
            Notifications sur cet appareil
          </h3>

          <p className="mt-1 text-sm leading-6 text-slate-600">
            Recevez les publications et alertes de votre église.
          </p>
        </div>
      </div>

      {denied && (
        <div className="mt-4 rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm leading-6 text-amber-900">
          <p className="font-black">
            Autorisation bloquée par Chrome
          </p>

          <p className="mt-2">
            Touchez l’icône des réglages à gauche de l’adresse du site,
            puis Permissions → Notifications → Autoriser.
          </p>

          <p className="mt-2 text-xs font-semibold">
            Rechargez ensuite la page et appuyez sur Vérifier.
          </p>
        </div>
      )}

      <button
        type="button"
        onClick={
          denied
            ? () =>
                window.location.reload()
            : activateNotifications
        }
        disabled={
          loading ||
          subscribed
        }
        className={[
          "mt-4 inline-flex min-h-12 w-full items-center justify-center gap-2 rounded-2xl px-5 py-3 text-sm font-black transition sm:w-auto",
          subscribed
            ? "bg-green-50 text-green-700"
            : denied
              ? "bg-amber-100 text-amber-900"
              : "bg-[#03357A] text-white",
        ].join(" ")}
      >
        {loading ? (
          <Loader2 className="h-4 w-4 animate-spin" />
        ) : subscribed ? (
          <CheckCircle2 className="h-4 w-4" />
        ) : denied ? (
          <RotateCcw className="h-4 w-4" />
        ) : (
          <BellRing className="h-4 w-4" />
        )}

        {subscribed
          ? "Notifications activées"
          : denied
            ? "Vérifier après réactivation"
            : "Activer les notifications"}
      </button>

      {message && (
        <p className="mt-3 text-sm font-semibold leading-6 text-slate-600">
          {message}
        </p>
      )}
    </section>
  );
}

"use client";

import {
  BellRing,
  CheckCircle2,
  ExternalLink,
  Loader2,
  RotateCcw,
} from "lucide-react";
import {
  useEffect,
  useState,
} from "react";

type NotificationSubscribeButtonProps = {
  churchId: string;
  label?: string;
  className?: string;
};

function urlBase64ToUint8Array(
  base64String: string
) {
  const padding = "=".repeat(
    (
      4 -
      (base64String.length %
        4)
    ) % 4
  );

  const base64 =
    `${base64String}${padding}`
      .replace(/-/g, "+")
      .replace(/_/g, "/");

  const rawData =
    window.atob(base64);

  const outputArray =
    new Uint8Array(
      rawData.length
    );

  for (
    let index = 0;
    index < rawData.length;
    index += 1
  ) {
    outputArray[index] =
      rawData.charCodeAt(
        index
      );
  }

  return outputArray;
}

async function readPayload(
  response: Response
) {
  const raw =
    await response.text();

  if (!raw) return {};

  try {
    return JSON.parse(raw);
  } catch {
    return {
      error:
        raw.slice(0, 400),
    };
  }
}

export default function NotificationSubscribeButton({
  churchId,
  label = "Activer les notifications",
  className,
}: NotificationSubscribeButtonProps) {
  const [
    isSupported,
    setIsSupported,
  ] = useState(false);

  const [
    permission,
    setPermission,
  ] =
    useState<NotificationPermission>(
      "default"
    );

  const [
    isSubscribed,
    setIsSubscribed,
  ] = useState(false);

  const [
    isLoading,
    setIsLoading,
  ] = useState(false);

  const [
    message,
    setMessage,
  ] = useState("");

  useEffect(() => {
    let active = true;

    async function detectStatus() {
      const supported =
        typeof window !==
          "undefined" &&
        "Notification" in
          window &&
        "serviceWorker" in
          navigator &&
        "PushManager" in
          window;

      if (!active) return;

      setIsSupported(
        supported
      );

      if (!supported) return;

      setPermission(
        Notification.permission
      );

      try {
        const registration =
          await navigator.serviceWorker.getRegistration(
            "/"
          );

        const subscription =
          await registration?.pushManager.getSubscription();

        if (active) {
          setIsSubscribed(
            Boolean(
              subscription &&
                Notification.permission ===
                  "granted"
            )
          );
        }
      } catch {
        if (active) {
          setIsSubscribed(
            false
          );
        }
      }
    }

    detectStatus();

    return () => {
      active = false;
    };
  }, []);

  async function handleSubscribe() {
    setMessage("");

    if (!isSupported) {
      setMessage(
        "Ce navigateur ne supporte pas les notifications Push."
      );
      return;
    }

    if (
      Notification.permission ===
      "denied"
    ) {
      setPermission("denied");
      setMessage(
        "L’autorisation a déjà été bloquée dans Chrome. Réactivez-la dans les permissions du site, puis rechargez cette page."
      );
      return;
    }

    const publicKey =
      process.env
        .NEXT_PUBLIC_VAPID_PUBLIC_KEY;

    if (!publicKey) {
      setMessage(
        "La clé publique VAPID n’est pas configurée dans Vercel."
      );
      return;
    }

    setIsLoading(true);

    try {
      const registration =
        (
          await navigator.serviceWorker.getRegistration(
            "/"
          )
        ) ||
        (
          await navigator.serviceWorker.register(
            "/sw.js",
            {
              scope: "/",
            }
          )
        );

      await navigator.serviceWorker.ready;

      const nextPermission =
        await Notification.requestPermission();

      setPermission(
        nextPermission
      );

      if (
        nextPermission !==
        "granted"
      ) {
        setMessage(
          "Autorisation refusée. Utilisez les permissions du site dans Chrome pour choisir Autoriser."
        );
        return;
      }

      let subscription =
        await registration.pushManager.getSubscription();

      if (!subscription) {
        subscription =
          await registration.pushManager.subscribe(
            {
              userVisibleOnly:
                true,
              applicationServerKey:
                urlBase64ToUint8Array(
                  publicKey
                ),
            }
          );
      }

      const response =
        await fetch(
          "/api/push/subscribe",
          {
            method: "POST",
            headers: {
              "Content-Type":
                "application/json",
            },
            body: JSON.stringify({
              churchId,
              subscription:
                subscription.toJSON(),
            }),
          }
        );

      const payload =
        await readPayload(
          response
        );

      if (!response.ok) {
        throw new Error(
          payload.error ||
            "Impossible d’activer les notifications."
        );
      }

      setIsSubscribed(true);
      setMessage(
        "Notifications activées sur cet appareil."
      );
    } catch (
      subscribeError: any
    ) {
      setMessage(
        subscribeError?.message ||
          "Impossible d’activer les notifications."
      );
    } finally {
      setIsLoading(false);
    }
  }

  const denied =
    permission === "denied";

  return (
    <div>
      <button
        type="button"
        onClick={
          denied
            ? () => {
                setPermission(
                  Notification.permission
                );

                window.location.reload();
              }
            : handleSubscribe
        }
        disabled={
          isLoading ||
          isSubscribed
        }
        className={
          className ||
          [
            "inline-flex min-h-12 items-center justify-center gap-2 rounded-2xl px-5 py-3 text-sm font-black shadow-sm transition",
            isSubscribed
              ? "bg-green-50 text-green-700"
              : denied
                ? "bg-amber-50 text-amber-800 ring-1 ring-amber-200"
                : "bg-[#03357A] text-white hover:bg-[#022B63]",
          ].join(" ")
        }
      >
        {isLoading ? (
          <Loader2 className="h-4 w-4 animate-spin" />
        ) : isSubscribed ? (
          <CheckCircle2 className="h-4 w-4" />
        ) : denied ? (
          <RotateCcw className="h-4 w-4" />
        ) : (
          <BellRing className="h-4 w-4" />
        )}

        {isSubscribed
          ? "Notifications activées"
          : denied
            ? "Vérifier après réactivation"
            : label}
      </button>

      {!isSupported && (
        <p className="mt-2 max-w-md text-xs font-semibold leading-5 text-amber-700">
          Ce navigateur ne
          supporte pas les
          notifications Push.
        </p>
      )}

      {denied && (
        <div className="mt-3 max-w-xl rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm leading-6 text-amber-900">
          <p className="font-black">
            Réactivation nécessaire dans Chrome
          </p>

          <p className="mt-2">
            Touchez l’icône des réglages à gauche de l’adresse du site,
            puis Permissions → Notifications → Autoriser. Rechargez
            ensuite cette page.
          </p>

          <p className="mt-2 text-xs font-semibold">
            Autre chemin : Chrome → Paramètres → Paramètres des sites
            → Notifications → recherchez ce sous-domaine → Autoriser.
          </p>

          <span className="mt-3 inline-flex items-center gap-2 text-xs font-black text-amber-800">
            <ExternalLink className="h-4 w-4" />
            Le navigateur interdit à l’application de modifier elle-même
            une autorisation déjà refusée.
          </span>
        </div>
      )}

      {message && (
        <p className="mt-2 max-w-md text-xs font-semibold leading-5 text-slate-600">
          {message}
        </p>
      )}
    </div>
  );
}

"use client";

import {
  BellRing,
  CalendarDays,
  ImagePlus,
  Loader2,
  Send,
  Star,
  X,
} from "lucide-react";
import {
  FormEvent,
  useMemo,
  useState,
} from "react";
import { useRouter } from "next/navigation";

const inputClass =
  "mpangi-form-control min-h-12";

const textareaClass =
  "mpangi-form-control min-h-28 py-3";

const MAX_IMAGE_SIZE =
  4 * 1024 * 1024;


async function readApiPayload(
  response: Response
) {
  const raw =
    await response.text();

  if (!raw) return {};

  try {
    return JSON.parse(raw);
  } catch {
    return {
      error:
        raw.slice(0, 500) ||
        `Erreur HTTP ${response.status}`,
    };
  }
}

async function fetchWithTimeout(
  input: RequestInfo | URL,
  init: RequestInit,
  timeoutMilliseconds: number
) {
  const controller =
    new AbortController();

  const timeout =
    setTimeout(() => {
      controller.abort();
    }, timeoutMilliseconds);

  try {
    return await fetch(input, {
      ...init,
      signal:
        controller.signal,
    });
  } finally {
    clearTimeout(timeout);
  }
}

export default function PublicationForm() {
  const router = useRouter();

  const [isLoading, setIsLoading] =
    useState(false);

  const [message, setMessage] =
    useState("");

  const [error, setError] =
    useState("");

  const [
    previewUrl,
    setPreviewUrl,
  ] = useState<string | null>(
    null
  );

  const [
    selectedFileName,
    setSelectedFileName,
  ] = useState("");

  const previewStyle =
    useMemo(
      () =>
        previewUrl
          ? {
              backgroundImage: `url("${previewUrl}")`,
            }
          : undefined,
      [previewUrl]
    );

  function clearImage(
    input?: HTMLInputElement | null
  ) {
    if (previewUrl) {
      URL.revokeObjectURL(
        previewUrl
      );
    }

    setPreviewUrl(null);
    setSelectedFileName("");

    if (input) {
      input.value = "";
    }
  }

  async function handleSubmit(
    event: FormEvent<HTMLFormElement>
  ) {
    event.preventDefault();

    const formElement =
      event.currentTarget;

    const form =
      new FormData(formElement);

    const image =
      form.get("coverImage");

    if (
      image instanceof File &&
      image.size >
        MAX_IMAGE_SIZE
    ) {
      setError(
        "La photo ne peut pas dépasser 4 Mo."
      );
      return;
    }

    const notifyRequested =
      form.get("notify") === "on";

    /*
     * L’enregistrement et l’envoi Push sont volontairement séparés.
     * Une panne VAPID ne doit jamais annuler la publication.
     */
    if (notifyRequested) {
      form.set(
        "notify",
        "false"
      );

      form.set(
        "isPublished",
        "on"
      );
    }

    setIsLoading(true);
    setMessage("");
    setError("");

    try {
      const response =
        await fetchWithTimeout(
          "/api/publications",
          {
            method: "POST",
            body: form,
          },
          45000
        );

      const payload =
        await readApiPayload(
          response
        );

      if (!response.ok) {
        const detail = [
          payload.error,
          payload.details,
          payload.hint,
        ]
          .filter(Boolean)
          .join(" — ");

        throw new Error(
          detail ||
            "Erreur pendant l’enregistrement."
        );
      }

      let successMessage =
        "Publication enregistrée.";

      if (
        notifyRequested &&
        payload.publicationId
      ) {
        try {
          const notifyResponse =
            await fetchWithTimeout(
              "/api/publications",
              {
                method: "PATCH",
                headers: {
                  "Content-Type":
                    "application/json",
                },
                body:
                  JSON.stringify({
                    publicationId:
                      payload.publicationId,
                    action: "notify",
                  }),
              },
              20000
            );

          const notifyPayload =
            await readApiPayload(
              notifyResponse
            );

          if (!notifyResponse.ok) {
            successMessage +=
              ` Notification non envoyée : ${
                notifyPayload.error ||
                "erreur Push"
              }.`;
          } else {
            successMessage =
              notifyPayload.warning ||
              `Publication enregistrée. Notifications envoyées : ${
                notifyPayload.sentCount ||
                0
              }.`;
          }
        } catch (
          notifyError: any
        ) {
          successMessage +=
            ` Notification non envoyée : ${
              notifyError?.name ===
              "AbortError"
                ? "délai dépassé"
                : notifyError?.message ||
                  "erreur réseau"
            }.`;
        }
      }

      formElement.reset();
      clearImage();

      setMessage(
        successMessage
      );

      router.refresh();
    } catch (
      submitError: any
    ) {
      setError(
        submitError?.name ===
          "AbortError"
          ? "Le serveur a mis trop de temps à répondre. La publication n’a pas été confirmée."
          : submitError?.message ||
            "Une erreur a empêché la publication."
      );
    } finally {
      setIsLoading(false);
    }
  }

  return (
    <form
      onSubmit={handleSubmit}
      className="rounded-[1.75rem] border border-[#DCEAF5] bg-white p-4 shadow-sm sm:p-6"
    >
      <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between">
        <div>
          <p className="text-xs font-black uppercase tracking-[0.2em] text-[#3F79B3]">
            Communication
          </p>

          <h2 className="mt-2 text-2xl font-black text-[#03357A]">
            Nouvelle publication
          </h2>

          <p className="mt-2 max-w-3xl text-sm leading-7 text-slate-600">
            Publiez une actualité,
            un événement, une
            annonce, une vidéo ou
            un enseignement. Une
            photo peut être mise en
            vedette sur la page
            publique.
          </p>
        </div>

        <div className="inline-flex items-center gap-2 rounded-2xl bg-[#EAF3FA] px-4 py-3 text-xs font-black text-[#03357A]">
          <CalendarDays className="h-4 w-4" />
          Visible immédiatement si
          « Publier » est coché
        </div>
      </div>

      {error && (
        <div className="mt-5 rounded-2xl border border-red-100 bg-red-50 p-4 text-sm font-bold leading-6 text-red-700">
          {error}
        </div>
      )}

      {message && (
        <div className="mt-5 rounded-2xl border border-green-100 bg-green-50 p-4 text-sm font-bold leading-6 text-green-700">
          {message}
        </div>
      )}

      <div className="mt-6 grid gap-4 md:grid-cols-2">
        <label className="space-y-2">
          <span className="text-sm font-black text-[#03357A]">
            Titre *
          </span>

          <input
            name="title"
            required
            maxLength={180}
            className={inputClass}
            placeholder="Titre de la publication"
          />
        </label>

        <label className="space-y-2">
          <span className="text-sm font-black text-[#03357A]">
            Type
          </span>

          <select
            name="publicationType"
            defaultValue="news"
            className={inputClass}
          >
            <option value="news">
              Actualité
            </option>
            <option value="event">
              Événement
            </option>
            <option value="announcement">
              Annonce
            </option>
            <option value="teaching">
              Enseignement
            </option>
            <option value="sermon">
              Prédication
            </option>
            <option value="video">
              Vidéo
            </option>
            <option value="message">
              Message d’édification
            </option>
          </select>
        </label>

        <label className="space-y-2 md:col-span-2">
          <span className="text-sm font-black text-[#03357A]">
            Lien vidéo YouTube
          </span>

          <input
            name="videoUrl"
            type="url"
            className={inputClass}
            placeholder="https://www.youtube.com/watch?v=..."
          />
        </label>

        <label className="space-y-2 md:col-span-2">
          <span className="text-sm font-black text-[#03357A]">
            Résumé court
          </span>

          <textarea
            name="description"
            maxLength={1000}
            className={textareaClass}
            placeholder="Résumé visible sur la page publique..."
          />
        </label>

        <label className="space-y-2 md:col-span-2">
          <span className="text-sm font-black text-[#03357A]">
            Contenu complet
          </span>

          <textarea
            name="content"
            maxLength={10000}
            className="mpangi-form-control min-h-40 py-3"
            placeholder="Texte complet, programme, passage biblique, informations pratiques..."
          />
        </label>

        <div className="md:col-span-2">
          <p className="text-sm font-black text-[#03357A]">
            Photo de couverture
          </p>

          <p className="mt-1 text-xs font-semibold leading-5 text-slate-500">
            JPG, PNG ou WebP. Maximum
            4 Mo. Ratio conseillé :
            16:9.
          </p>

          <label className="mt-3 block cursor-pointer">
            <input
              name="coverImage"
              type="file"
              accept="image/jpeg,image/png,image/webp"
              className="sr-only"
              onChange={(event) => {
                const file =
                  event.target
                    .files?.[0];

                if (!file) {
                  clearImage(
                    event.currentTarget
                  );
                  return;
                }

                if (
                  file.size >
                  MAX_IMAGE_SIZE
                ) {
                  setError(
                    "La photo ne peut pas dépasser 4 Mo."
                  );
                  clearImage(
                    event.currentTarget
                  );
                  return;
                }

                if (previewUrl) {
                  URL.revokeObjectURL(
                    previewUrl
                  );
                }

                setPreviewUrl(
                  URL.createObjectURL(
                    file
                  )
                );

                setSelectedFileName(
                  file.name
                );

                setError("");
              }}
            />

            <div
              className={[
                "relative flex min-h-52 items-center justify-center overflow-hidden rounded-3xl border-2 border-dashed bg-[#F8FBFD] bg-cover bg-center p-5 transition",
                previewUrl
                  ? "border-[#2563EB]"
                  : "border-[#C9DBEA] hover:border-[#03357A]",
              ].join(" ")}
              style={previewStyle}
            >
              {previewUrl && (
                <div className="absolute inset-0 bg-slate-950/25" />
              )}

              <div className="relative z-10 flex flex-col items-center text-center">
                <div className="flex h-14 w-14 items-center justify-center rounded-2xl bg-white text-[#03357A] shadow-lg">
                  <ImagePlus className="h-7 w-7" />
                </div>

                <p
                  className={[
                    "mt-3 max-w-xs text-sm font-black",
                    previewUrl
                      ? "text-white"
                      : "text-[#03357A]",
                  ].join(" ")}
                >
                  {selectedFileName ||
                    "Choisir une photo"}
                </p>

                <p
                  className={[
                    "mt-1 text-xs font-semibold",
                    previewUrl
                      ? "text-white/90"
                      : "text-slate-500",
                  ].join(" ")}
                >
                  Touchez pour remplacer
                  l’image
                </p>
              </div>
            </div>
          </label>

          {previewUrl && (
            <button
              type="button"
              onClick={() => {
                const input =
                  document.querySelector<HTMLInputElement>(
                    'input[name="coverImage"]'
                  );

                clearImage(input);
              }}
              className="mt-3 inline-flex min-h-10 items-center gap-2 rounded-xl bg-red-50 px-4 text-xs font-black text-red-700"
            >
              <X className="h-4 w-4" />
              Retirer la photo
            </button>
          )}
        </div>
      </div>

      <div className="mt-5 grid gap-3 sm:grid-cols-3">
        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="isPublished"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          Publier sur la page
          publique
        </label>

        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="isFeatured"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          <Star className="h-4 w-4 text-amber-500" />
          Mettre en vedette
        </label>

        <label className="flex min-h-16 items-center gap-3 rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-sm font-black text-slate-700">
          <input
            name="notify"
            type="checkbox"
            className="h-5 w-5 rounded border-[#B8CCDC]"
          />
          <BellRing className="h-4 w-4 text-green-600" />
          Notifier les abonnés
        </label>
      </div>

      <div className="mt-6 flex justify-end">
        <button
          type="submit"
          disabled={isLoading}
          className="inline-flex min-h-12 w-full items-center justify-center gap-2 rounded-2xl bg-gradient-to-r from-[#03357A] to-[#2563EB] px-6 py-3 text-sm font-black text-white shadow-lg shadow-blue-900/20 disabled:opacity-60 sm:w-auto"
        >
          {isLoading ? (
            <Loader2 className="h-5 w-5 animate-spin" />
          ) : (
            <Send className="h-5 w-5" />
          )}

          {isLoading
            ? "Publication en cours..."
            : "Enregistrer la publication"}
        </button>
      </div>
    </form>
  );
}

import React from "react";
import Image from "next/image";
import Link from "next/link";
import { notFound } from "next/navigation";
