              ) : (
                <div className="flex aspect-video flex-col items-center justify-center p-6 text-center md:p-8">
                  <PlayCircle className="h-12 w-12 text-[#3F79B3] md:h-14 md:w-14" />

                  <p className="mt-4 text-sm font-semibold text-slate-600">
                    Aucune vidéo YouTube configurée pour le moment.
                  </p>

                  {church.youtube_channel_url && (
                    <a
                      href={church.youtube_channel_url}
                      target="_blank"
                      rel="noreferrer"
                      className="mt-5 inline-flex rounded-2xl bg-[#03357A] px-5 py-3 text-sm font-bold text-white hover:bg-[#022B63]"
                    >
                      Ouvrir la chaîne YouTube
                    </a>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      </section>

      <div id="don" className="scroll-mt-24">
        <PublicDonationSection
          church={{
            ...church,
            name: churchPublicName,
          }}
        />
      </div>

      <PublicTestimoniesSection churchId={church.id} />

      <footer className="border-t border-[#DCEAF5] bg-white px-4 py-6 text-center text-sm leading-6 text-slate-500 md:px-6">
        Propulsé par{" "}
        <span className="font-bold text-[#03357A]">Mpangi-church</span> —
        AKSANTIC Technology
      </footer>

      <PublicMobileBottomNav slug={churchSlug} />
    </main>
  );
}

function StepBox({ number, label }: { number: string; label: string }) {
  return (
    <div className="rounded-2xl bg-white/10 p-4">
      <p className="text-2xl font-black">{number}</p>
      <p className="mt-1 break-words text-sm font-bold">{label}</p>
    </div>
  );
}

function HeroButton({
  href,
  icon: Icon,
  label,
  variant,
}: {
  href: string;
  icon: LucideIcon;
  label: string;
  variant: "white" | "glass";
}) {
  const className =
    variant === "white"
      ? "bg-white text-[#03357A] shadow-lg shadow-blue-950/20 hover:bg-[#EAF3FA]"
      : "bg-white/15 text-white ring-1 ring-white/25 hover:bg-white/20";

  return (
    <Link
      href={href}
      className={`inline-flex min-h-12 items-center justify-center gap-2 rounded-2xl px-4 py-3 text-center text-sm font-extrabold ${className}`}
    >
      <Icon className="h-5 w-5 shrink-0" />
      <span className="break-words">{label}</span>
    </Link>
  );
}

function Info({
  icon: Icon,
  label,
  value,
}: {
  icon: LucideIcon;
  label: string;
  value: string;
}) {
  return (
    <div className="flex min-w-0 gap-3 rounded-2xl bg-[#F8FBFD] p-3 md:p-4">
      <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-[#EAF3FA] text-[#03357A]">
        <Icon className="h-5 w-5" />
      </div>

      <div className="min-w-0">
        <p className="text-xs font-bold uppercase tracking-wide text-slate-400">
          {label}
        </p>

        <p className="mt-1 break-words font-semibold text-slate-700">
          {value || "-"}
        </p>
      </div>
    </div>
  );
}

