function walk(directory) {
  if (!fs.existsSync(directory)) return [];

  return fs
    .readdirSync(directory, {
      withFileTypes: true,
    })
    .flatMap((entry) => {
      const fullPath = path.join(
        directory,
        entry.name
      );

      if (entry.isDirectory()) {
        return walk(fullPath);
      }

      return [fullPath];
    });
}

const layoutAudit = routeMap.map(
  ([route, modules]) => {
    const layoutPath = path.join(
      APP,
      route,
      "layout.tsx"
    );

