const fs = require("fs");
const path = require("path");
const { loadEnv } = require("./env-loader");

function arg(name, fallback = null) {
  const index = process.argv.indexOf(name);
  return index >= 0 && process.argv[index + 1] ? process.argv[index + 1] : fallback;
}

function dayKey(date) {
  return date.toISOString().slice(0, 10);
}

function weekKey(date) {
  const copy = new Date(date);
  const day = (copy.getUTCDay() + 6) % 7;
  copy.setUTCDate(copy.getUTCDate() - day);
  return copy.toISOString().slice(0, 10);
}

function monthKey(date) {
  return date.toISOString().slice(0, 7);
}

function selectUnique(entries, keyFn, count) {
  const seen = new Set();
  const selected = [];

  for (const entry of entries) {
    const key = keyFn(entry.date);
    if (seen.has(key)) continue;
    seen.add(key);
    selected.push(entry);
    if (selected.length >= count) break;
  }

  return selected;
}

function main() {
  const root = process.cwd();
  const env = loadEnv(root);
  const backupsDir = path.resolve(root, arg("--backups-dir", "backups/mpangi-church"));
  const keepDaily = Number(arg("--daily", env.BACKUP_KEEP_DAILY || "7"));
  const keepWeekly = Number(arg("--weekly", env.BACKUP_KEEP_WEEKLY || "4"));
  const keepMonthly = Number(arg("--monthly", env.BACKUP_KEEP_MONTHLY || "6"));
  const execute = process.argv.includes("--execute");

  if (!fs.existsSync(backupsDir)) {
    console.log("ℹ️ Aucun dossier de sauvegarde.");
    return;
  }

  const entries = fs
    .readdirSync(backupsDir, { withFileTypes: true })
    .filter(
      (entry) =>
        entry.isDirectory() &&
        /^\d{4}-\d{2}-\d{2}_\d{2}-\d{2}-\d{2}$/.test(entry.name)
    )
    .map((entry) => {
      const parts = entry.name.match(
        /^(\d{4})-(\d{2})-(\d{2})_(\d{2})-(\d{2})-(\d{2})$/
      );

      const date = new Date(
        Date.UTC(
          Number(parts[1]),
          Number(parts[2]) - 1,
          Number(parts[3]),
          Number(parts[4]),
          Number(parts[5]),
          Number(parts[6])
        )
      );

      return {
        name: entry.name,
        directory: path.join(backupsDir, entry.name),
        archive: path.join(backupsDir, `${entry.name}.zip`),
        date,
      };
    })
    .sort((a, b) => b.date - a.date);

  const keep = new Set([
    ...selectUnique(entries, dayKey, keepDaily),
    ...selectUnique(entries, weekKey, keepWeekly),
    ...selectUnique(entries, monthKey, keepMonthly),
  ].map((entry) => entry.directory));

  const removable = entries.filter((entry) => !keep.has(entry.directory));

  console.log(
    `Politique : ${keepDaily} quotidiennes, ${keepWeekly} hebdomadaires, ${keepMonthly} mensuelles`
  );
  console.log(`Sauvegardes trouvées : ${entries.length}`);
  console.log(`À conserver : ${keep.size}`);
  console.log(`À supprimer : ${removable.length}`);

  for (const entry of removable) {
    console.log(execute ? "🗑️" : "DRY-RUN", entry.directory);

    if (execute) {
      fs.rmSync(entry.directory, { recursive: true, force: true });
      if (fs.existsSync(entry.archive)) fs.rmSync(entry.archive, { force: true });
    }
  }

  if (!execute && removable.length) {
    console.log("Aucune suppression effectuée. Ajouter --execute pour appliquer.");
  }
}

try {
  main();
} catch (error) {
  console.error("❌", error.message || error);
  process.exit(1);
}

const fs = require("fs");
const path = require("path");
const { createClient } = require("@supabase/supabase-js");
const { loadEnv, requireEnv } = require("./env-loader");

function arg(name, fallback = null) {
  const index = process.argv.indexOf(name);
  return index >= 0 && process.argv[index + 1]
    ? process.argv[index + 1]
    : fallback;
}

function ensure(directory) {
  fs.mkdirSync(directory, { recursive: true });
}

function safe(value) {
  return String(value)
    .replace(/[<>:"/\\|?*\x00-\x1F]/g, "_")
    .replace(/\.\./g, "_");
}

async function listAll(supabase, bucketId, prefix = "") {
  const all = [];
  let offset = 0;

  while (true) {
    const { data, error } = await supabase.storage
      .from(bucketId)
      .list(prefix, {
        limit: 1000,
        offset,
        sortBy: { column: "name", order: "asc" },
      });

    if (error) {
      throw new Error(`${bucketId}/${prefix}: ${error.message}`);
    }

    const items = data || [];
    all.push(...items);
    if (items.length < 1000) break;
    offset += 1000;
  }

  return all;
}

function isFolder(item) {
  return !item.id || item.metadata == null;
}

async function collect(supabase, bucketId, prefix = "") {
  const entries = await listAll(supabase, bucketId, prefix);
  const objects = [];

  for (const entry of entries) {
    const objectPath = prefix ? `${prefix}/${entry.name}` : entry.name;

    if (isFolder(entry)) {
      objects.push(...(await collect(supabase, bucketId, objectPath)));
    } else {
      objects.push({
        path: objectPath,
        metadata: entry.metadata || {},
        createdAt: entry.created_at || null,
        updatedAt: entry.updated_at || null,
      });
    }
  }

  return objects;
}

async function main() {
  const root = process.cwd();
  const env = loadEnv(root);
  requireEnv(env, ["NEXT_PUBLIC_SUPABASE_URL", "SUPABASE_SERVICE_ROLE_KEY"]);

  const output = path.resolve(root, arg("--output", "backups/storage-latest"));
  ensure(output);

  const supabase = createClient(
    env.NEXT_PUBLIC_SUPABASE_URL,
    env.SUPABASE_SERVICE_ROLE_KEY,
    { auth: { autoRefreshToken: false, persistSession: false } }
  );

  const { data: buckets, error } = await supabase.storage.listBuckets();
  if (error) throw new Error(error.message);

  const manifest = {
    generatedAt: new Date().toISOString(),
    source: env.NEXT_PUBLIC_SUPABASE_URL,
    buckets: [],
    errors: [],
  };

  for (const bucket of buckets || []) {
    console.log(`▶ Bucket ${bucket.id}`);
    const objects = await collect(supabase, bucket.id);
    const downloaded = [];

    for (const object of objects) {
      try {
        const { data, error: downloadError } = await supabase.storage
          .from(bucket.id)
          .download(object.path);

        if (downloadError || !data) {
          throw new Error(downloadError?.message || "Fichier vide");
        }

        const destination = path.join(
          output,
          safe(bucket.id),
          ...object.path.split("/").map(safe)
        );

        ensure(path.dirname(destination));
        const buffer = Buffer.from(await data.arrayBuffer());
        fs.writeFileSync(destination, buffer);

        downloaded.push({
          ...object,
          localPath: path.relative(output, destination).replace(/\\/g, "/"),
          size: buffer.length,
        });

        console.log(`  ✅ ${object.path}`);
      } catch (downloadError) {
        const message = downloadError?.message || String(downloadError);
        manifest.errors.push({
          bucketId: bucket.id,
          objectPath: object.path,
          message,
        });
        console.error(`  ❌ ${object.path}: ${message}`);
      }
    }

    manifest.buckets.push({
      id: bucket.id,
      name: bucket.name,
      public: Boolean(bucket.public),
      fileSizeLimit: bucket.file_size_limit || null,
      allowedMimeTypes: bucket.allowed_mime_types || null,
      expected: objects.length,
      downloaded: downloaded.length,
      objects: downloaded,
    });
  }

  fs.writeFileSync(
    path.join(output, "storage-manifest.json"),
    JSON.stringify(manifest, null, 2),
    "utf8"
  );

  console.log(`Buckets : ${manifest.buckets.length}`);
  console.log(`Erreurs : ${manifest.errors.length}`);

  if (manifest.errors.length) process.exitCode = 2;
}

main().catch((error) => {
  console.error("❌ Sauvegarde Storage échouée :", error.message || error);
  process.exit(1);
});

