  }

  let source = fs.readFileSync(filePath, "utf8");

  if (
    source.includes(
      "@/lib/security/secureAction"
    ) ||
    source.includes(
      "@/lib/security/routeGuard"
    )
  ) {
    report.files.push({
      file: target.file,
      status: "already_has_security_import",
      patchedFunctions: [],
      unresolvedFunctions: [],
    });

    console.log(
      "ℹ️ Garde déjà présente :",
      target.file
    );
    return;
  }

  backup(filePath, "phase35e2b");

  source = addImport(
    source,
    'import { requireAnyActionPermission } from "@/lib/security/secureAction";\nimport { requireAnyModulePermission } from "@/lib/security/routeGuard";\n',
    "@/lib/security/secureAction"
  );

  const result = patchExportedAsyncFunctions(
    source,
    target.modules,
    target.defaultAction
  );

  const hasPatched = result.patchedFunctions.some(
    (item) =>
      item.status === "patched" ||
      item.status === "patched_arrow"
  );

  if (!hasPatched) {
    report.files.push({
      file: target.file,
      status: "manual_required",
      patchedFunctions:
        result.patchedFunctions,
      unresolvedFunctions:
        result.unresolvedFunctions,
    });

    console.log(
      "❌ Aucun export patché :",
      target.file
    );
    return;
  }

  fs.writeFileSync(
    filePath,
    result.source,
    "utf8"
  );

  report.files.push({
    file: target.file,
    status:
      result.unresolvedFunctions.length > 0
        ? "partial"
        : "patched",
    patchedFunctions:
      result.patchedFunctions,
    unresolvedFunctions:
      result.unresolvedFunctions,
  });

  console.log(
    "✅ Gardes ajoutées :",
    target.file
  );
}

