  lines.push(
    "- [ ] Confirmer : aucune ligne retournée ou accès refusé"
  );
  lines.push(
    "- [ ] Vérifier l’événement dans `/settings/security-audit`"
  );

  fs.writeFileSync(
    path.join(
      process.cwd(),
      "PHASE35E4_REAL_CHECKLIST.md"
    ),
    lines.join("\n"),
    "utf8"
  );

  console.log(
    "Checklist créée : PHASE35E4_REAL_CHECKLIST.md"
  );
}

