      report.skippedLayouts.push({
        route: relativeDirectory,
        reason:
          "layout_exists_manual_integration_required",
      });
      continue;
    }

    fs.mkdirSync(path.dirname(targetPath), {
      recursive: true,
    });

    fs.copyFileSync(templatePath, targetPath);

