function backupFile(
  relativePath
) {
  const targetPath =
    path.join(
      ROOT,
      relativePath
    );

  if (
    !fs.existsSync(
      targetPath
    )
  ) {
    return;
  }

  const backupPath =
    path.join(
      BACKUP_ROOT,
      relativePath
    );

  if (
    fs.existsSync(
      backupPath
    )
  ) {
    return;
  }

  fs.mkdirSync(
    path.dirname(
      backupPath
    ),
    {
      recursive: true,
    }
  );

  fs.copyFileSync(
    targetPath,
    backupPath
  );
}

function installDirectFile(
  relativePath
) {
  const templatePath =
    path.join(
      TEMPLATE_ROOT,
      `${relativePath}.txt`
    );

  const targetPath =
    path.join(
      ROOT,
      relativePath
    );

  if (
    !fs.existsSync(
      templatePath
    )
  ) {
    throw new Error(
      `Template manquant : ${relativePath}`
    );
  }

  backupFile(
    relativePath
  );

  fs.mkdirSync(
    path.dirname(
      targetPath
    ),
    {
      recursive: true,
    }
  );

  fs.copyFileSync(
    templatePath,
    targetPath
  );

  console.log(
    "✅",
    relativePath
  );
}

function patchFile(
  relativePath,
  patcher
) {
  const targetPath =
    path.join(
      ROOT,
      relativePath
    );

  if (
    !fs.existsSync(
      targetPath
    )
  ) {
    throw new Error(
      `Fichier introuvable : ${relativePath}`
    );
  }

  backupFile(
    relativePath
  );

  const source =
    fs.readFileSync(
      targetPath,
      "utf8"
    );

  const result =
    patcher(source);

  if (
    result === source
  ) {
    console.log(
      "ℹ️",
      relativePath,
      "déjà corrigé"
    );

    return;
  }

  fs.writeFileSync(
    targetPath,
    result,
    "utf8"
  );

  console.log(
    "✅",
    relativePath
  );
}

