 shadow-sm"><div className="mb-5 flex items-center gap-3"><div className="flex h-11 w-11 items-center justify-center rounded-2xl bg-[#EAF3FA] text-[#03357A]"><Paperclip className="h-5 w-5"/></div><div><h2 className="text-lg font-extrabold text-[#03357A]">Fichier et instructions</h2><p className="text-sm text-slate-500">Joignez le document transmis et ajoutez les consignes.</p></div></div><div className="grid gap-5"><label className="flex cursor-pointer flex-col items-center justify-center rounded-3xl border-2 border-dashed border-[#DCEAF5] bg-[#F8FBFD] px-5 py-8 text-center transition hover:border-[#03357A]/40 hover:bg-[#EAF3FA]"><FileUp className="h-10 w-10 text-[#03357A]"/><span className="mt-3 text-sm font-extrabold text-[#03357A]">Uploader le fichier transmis</span><span className="mt-1 text-xs font-semibold text-slate-500">PDF, image, Word ou Excel.</span><input type="file" name="document_file" accept=".pdf,.png,.jpg,.jpeg,.webp,.doc,.docx,.xls,.xlsx" className="mt-4 w-full max-w-md rounded-2xl bg-white p-3 text-sm text-slate-600 file:mr-4 file:rounded-xl file:border-0 file:bg-[#03357A] file:px-4 file:py-2 file:text-sm file:font-bold file:text-white"/></label><Field label="Consignes / instructions"><textarea name="instructions" rows={5} placeholder="Consignes pour le traitement du document..." className={textareaClass}/></Field></div></section><div className="sticky bottom-4 z-10 flex flex-col gap-3 rounded-3xl border border-[#DCEAF5] bg-white/95 p-4 shadow-lg backdrop-blur md:flex-row md:justify-end"><Link href="/administration/transmissions" className="inline-flex items-center justify-center rounded-2xl bg-[#EAF3FA] px-5 py-3 text-sm font-extrabold text-[#03357A]">Annuler</Link><button type="submit" className="inline-flex items-center justify-center rounded-2xl bg-[#03357A] px-5 py-3 text-sm font-extrabold text-white shadow-lg shadow-blue-900/20">Envoyer la transmission</button></div></form></div></AppShell>}
function Field({label,children,className=""}:{label:string;children:React.ReactNode;className?:string}){return <label className={`space-y-2 ${className}`}><span className="block text-sm font-extrabold text-[#03357A]">{label}</span>{children}</label>}

import Link from "next/link";
import {
  Archive,
  Download,
  Eye,
  FileText,
  Inbox,
  Pencil,
  Search,
  Send,
  ShieldAlert,
  Workflow,
} from "lucide-react";
import AppShell from "@/components/layout/AppShell";
import { getDocumentDownloadHref } from "@/lib/storage/churchDocuments";
import { requireChurchModuleAccess } from "@/lib/modules/moduleAccess";
import { archiveTransmissionAction } from "./actions";

type TransmissionsPageProps = {
  searchParams?: Promise<{
    q?: string;
    status?: string;
    priority?: string;
    dateFrom?: string;
    dateTo?: string;
  }>;
};

const STATUS_LABELS: Record<string, string> = {
  sent: "Envoyé",
  received: "Reçu",
  read: "Lu",
  in_progress: "En traitement",
  completed: "Terminé",
  returned: "Retourné",
  archived: "Archivé",
};

const PRIORITY_LABELS: Record<string, string> = {
  low: "Faible",
  normal: "Normale",
  high: "Haute",
  urgent: "Urgente",
};

function formatDate(value?: string | null) {
  if (!value) return "-";

  try {
    return new Intl.DateTimeFormat("fr-FR", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    }).format(new Date(value));
  } catch {
    return String(value);
  }
}

function getStatusClass(status: string) {
  if (status === "completed" || status === "archived") return "bg-green-50 text-green-700";
  if (status === "returned") return "bg-red-50 text-red-700";
  if (status === "in_progress") return "bg-orange-50 text-orange-700";
  if (status === "read" || status === "received") return "bg-blue-50 text-blue-700";
  return "bg-[#EAF3FA] text-[#03357A]";
}

function getPriorityClass(priority: string) {
  if (priority === "urgent") return "bg-red-50 text-red-700";
  if (priority === "high") return "bg-orange-50 text-orange-700";
  if (priority === "low") return "bg-slate-100 text-slate-600";
  return "bg-[#EAF3FA] text-[#03357A]";
}

function buildCurrentQuery(params: {
  q: string;
  status: string;
  priority: string;
  dateFrom: string;
  dateTo: string;
}) {
  const query = new URLSearchParams();

  if (params.q) query.set("q", params.q);
  if (params.status) query.set("status", params.status);
  if (params.priority) query.set("priority", params.priority);
  if (params.dateFrom) query.set("dateFrom", params.dateFrom);
  if (params.dateTo) query.set("dateTo", params.dateTo);

  const value = query.toString();
  return value ? `/administration/transmissions?${value}` : "/administration/transmissions";
}

export default async function TransmissionsPage({
  searchParams,
}: TransmissionsPageProps) {
  const resolvedSearchParams = searchParams ? await searchParams : {};
  const q = (resolvedSearchParams.q || "").trim();
  const status = resolvedSearchParams.status || "";
  const priority = resolvedSearchParams.priority || "";
  const dateFrom = resolvedSearchParams.dateFrom || "";
  const dateTo = resolvedSearchParams.dateTo || "";

  const currentUrl = buildCurrentQuery({ q, status, priority, dateFrom, dateTo });

  const { admin, profile } = await requireChurchModuleAccess("document_transmissions");

  let query = admin
    .from("admin_document_transmissions")
    .select(
      `
      id,
      reference,
      title,
      priority,
      status,
      due_date,
      sent_at,
      document_path,
      document_name,
      document_url,
      correspondence_id,
      recipient_profile:profiles!admin_document_transmissions_recipient_profile_id_fkey(full_name, role),
      recipient_department:departments!admin_document_transmissions_recipient_department_id_fkey(name),
      correspondence:admin_correspondences(reference, subject)
      `
    )
    .eq("church_id", profile.church_id)
    .order("sent_at", { ascending: false })
    .limit(200);

  if (status) query = query.eq("status", status);
  if (priority) query = query.eq("priority", priority);
  if (dateFrom) query = query.gte("sent_at", `${dateFrom}T00:00:00`);
  if (dateTo) query = query.lte("sent_at", `${dateTo}T23:59:59`);

  if (q) {
    query = query.or(`reference.ilike.%${q}%,title.ilike.%${q}%`);
  }

  const { data: transmissions } = await query;
  const rows = transmissions ?? [];

  const totalCount = rows.length;
  const inProgressCount = rows.filter((row: any) => row.status === "in_progress").length;
  const completedCount = rows.filter((row: any) => row.status === "completed").length;
  const urgentCount = rows.filter((row: any) => row.priority === "urgent").length;

