import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
type AttendanceActionBody = {
  eventId?: string;
  memberId?: string;
  action?: "mark_present" | "remove";
};

function getString(value: unknown) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

async function getCurrentProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return {
      profile: null,
      error: "Utilisateur non connecté.",
      status: 401,
    };
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) {
    return {
      profile: null,
      error: "Profil utilisateur introuvable.",
      status: 403,
    };
  }

  if (profile.status && profile.status !== "active") {
    return {
      profile: null,
      error: "Compte désactivé.",
      status: 403,
    };
  }

  if (!profile.church_id) {
    return {
      profile: null,
      error: "Aucune église rattachée à ce compte.",
      status: 403,
    };
  }

  return {
    profile,
    error: null,
    status: 200,
  };
}

function getMemberName(member: any) {
  return (
    [member.first_name, member.middle_name, member.last_name]
      .filter(Boolean)
      .join(" ") || "Membre"
  );
}

export async function POST(request: Request) {
  await requireAnyActionPermission(["attendance"], "create");
  try {
    const body = (await request.json()) as AttendanceActionBody;

    const eventId = getString(body.eventId);
    const memberId = getString(body.memberId);
    const action = body.action;

    if (!eventId || !memberId || !action) {
      return NextResponse.json(
        { error: "Événement, membre ou action manquant." },
        { status: 400 }
      );
    }

    if (!["mark_present", "remove"].includes(action)) {
      return NextResponse.json(
        { error: "Action de présence invalide." },
        { status: 400 }
      );
    }

    const { profile, error, status } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json({ error }, { status });
    }

    const admin = createAdminClient();

    const { data: event } = await admin
      .from("events")
      .select("id, church_id, title, attendance_enabled")
      .eq("id", eventId)
      .eq("church_id", profile.church_id)
      .maybeSingle();

    if (!event) {
      return NextResponse.json(
        { error: "Événement introuvable dans votre église." },
        { status: 404 }
      );
    }

    if (event.attendance_enabled === false) {
      return NextResponse.json(
        { error: "Le pointage est désactivé pour cet événement." },
        { status: 403 }
      );
    }

    const { data: member } = await admin
      .from("members")
      .select("id, first_name, middle_name, last_name, status, qr_token")
      .eq("id", memberId)
      .eq("church_id", profile.church_id)
      .maybeSingle();

    if (!member) {
      return NextResponse.json(
        { error: "Membre introuvable dans votre église." },
        { status: 404 }
      );
    }

    if (member.status && member.status !== "actif") {
      return NextResponse.json(
        { error: "Ce membre n’est pas actif." },
        { status: 403 }
      );
    }

    const memberName = getMemberName(member);

    if (action === "remove") {
      const { error: deleteError } = await admin
        .from("event_attendances")
        .delete()
        .eq("church_id", profile.church_id)
        .eq("event_id", eventId)
        .eq("member_id", memberId);

      if (deleteError) {
        return NextResponse.json(
          {
            error:
              deleteError.message ||
              "Impossible de retirer la présence du membre.",
          },
          { status: 400 }
        );
      }

      return NextResponse.json({
        success: true,
        status: "removed",
        message: `Présence retirée pour ${memberName}.`,
      });
    }

    const { data: existingAttendance } = await admin
      .from("event_attendances")
      .select("id, check_in_at")
      .eq("church_id", profile.church_id)
      .eq("event_id", eventId)
      .eq("member_id", memberId)
      .maybeSingle();

    if (existingAttendance) {
      return NextResponse.json({
        success: true,
        status: "already_checked_in",
        message: `${memberName} est déjà pointé pour cet événement.`,
        checkInAt: existingAttendance.check_in_at,
      });
    }

    const { data: attendance, error: insertError } = await admin
      .from("event_attendances")
      .insert({
        church_id: profile.church_id,
        event_id: eventId,
        member_id: memberId,
        scanned_by: profile.id,
        status: "present",
        check_in_method: "manual",
        qr_token_snapshot: member.qr_token || `manual:${member.id}`,
      })
      .select("id, check_in_at")
      .single();

    if (insertError || !attendance) {
      return NextResponse.json(
        {
          error:
            insertError?.message ||
            "Impossible d’enregistrer la présence manuelle.",
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      success: true,
      status: "checked_in",
      message: `Présence manuelle enregistrée pour ${memberName}.`,
      checkInAt: attendance.check_in_at,
    });
  } catch {
    return NextResponse.json(
      { error: "Erreur inattendue pendant l’action de présence." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
function getString(value: unknown) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function getEventTitle(event: any) {
  return event.title || event.name || event.event_name || "evenement";
}

function getMemberName(member: any) {
  return [member.first_name, member.middle_name, member.last_name]
    .filter(Boolean)
    .join(" ");
}

function getMemberCode(member: any) {
  if (member.member_code) return member.member_code;
  return `M-${String(member.id).replaceAll("-", "").slice(0, 8).toUpperCase()}`;
}

function formatCsvValue(value: unknown) {
  const text = value === null || value === undefined ? "" : String(value);
  return `"${text.replaceAll('"', '""')}"`;
}

function formatDate(value?: string | null) {
  if (!value) return "";

  try {
    return new Intl.DateTimeFormat("fr-FR", {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    }).format(new Date(value));
  } catch {
    return String(value);
  }
}

function slugifyFileName(value: string) {
  return value
    .toLowerCase()
    .normalize("NFD")
    .replace(/\p{Diacritic}/gu, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "")
    .slice(0, 80);
}

function normalizeText(value: string) {
  return value
    .toLowerCase()
    .normalize("NFD")
    .replace(/\p{Diacritic}/gu, "");
}

function getMethodLabel(method?: string | null) {
  if (method === "qr") return "QR Code";
  if (method === "manual") return "Manuel";
  return method || "";
}

export async function GET(request: Request) {
  await requireAnyModulePermission(["attendance"], "view");
  try {
    const url = new URL(request.url);
    const eventId = getString(url.searchParams.get("eventId"));
    const view = getString(url.searchParams.get("view")) || "all";
    const query = getString(url.searchParams.get("q"));
    const selectedDepartmentId = getString(url.searchParams.get("departmentId"));

    if (!eventId) {
      return NextResponse.json(
        { error: "Événement manquant." },
        { status: 400 }
      );
    }

    const supabase = await createClient();

    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json(
        { error: "Utilisateur non connecté." },
        { status: 401 }
      );
    }

    const { data: profile } = await supabase
      .from("profiles")
      .select("id, role, church_id, status")
      .eq("user_id", user.id)
      .maybeSingle();

    if (!profile || !profile.church_id) {
      return NextResponse.json(
        { error: "Profil utilisateur introuvable." },
        { status: 403 }
      );
    }

    if (profile.status && profile.status !== "active") {
      return NextResponse.json(
        { error: "Compte désactivé." },
        { status: 403 }
      );
    }

    const admin = createAdminClient();

    const { data: event } = await admin
      .from("events")
      .select("*")
      .eq("id", eventId)
      .eq("church_id", profile.church_id)
      .maybeSingle();

    if (!event) {
      return NextResponse.json(
        { error: "Événement introuvable." },
        { status: 404 }
      );
    }

    const { data: attendances } = await admin
      .from("event_attendances")
      .select("member_id, status, check_in_method, check_in_at")
      .eq("church_id", profile.church_id)
      .eq("event_id", eventId)
      .order("check_in_at", { ascending: true });

    const { data: members } = await admin
      .from("members")
      .select(
        `
        id,
        first_name,
        middle_name,
        last_name,
        phone,
        email,
        status,
        member_code
        `
      )
      .eq("church_id", profile.church_id)
      .eq("status", "actif")
      .order("last_name", { ascending: true });

    const allMembers = members ?? [];
    const memberIds = allMembers.map((member: any) => member.id);

    const { data: memberDepartments } =
      memberIds.length > 0
        ? await admin
            .from("member_departments")
            .select("member_id, department_id")
            .eq("church_id", profile.church_id)
            .in("member_id", memberIds)
        : { data: [] as any[] };

    const departmentIds = Array.from(
      new Set(
        (memberDepartments ?? [])
          .map((row: any) => row.department_id)
          .filter(Boolean)
      )
    );

    const { data: departments } =
      departmentIds.length > 0
        ? await admin
            .from("departments")
            .select("id, name")
            .eq("church_id", profile.church_id)
            .in("id", departmentIds)
        : { data: [] as any[] };

    const departmentsById = new Map(
      (departments ?? []).map((department: any) => [
        department.id,
        department.name,
      ])
    );

    const departmentsByMemberId = new Map<string, string[]>();
    const departmentIdsByMemberId = new Map<string, string[]>();

    for (const row of memberDepartments ?? []) {
      const departmentName = departmentsById.get(row.department_id);

      if (!departmentName) continue;

      const existingNames = departmentsByMemberId.get(row.member_id) ?? [];
      existingNames.push(departmentName);
      departmentsByMemberId.set(row.member_id, existingNames);

      const existingIds = departmentIdsByMemberId.get(row.member_id) ?? [];
      existingIds.push(row.department_id);
      departmentIdsByMemberId.set(row.member_id, existingIds);
    }

    const attendanceByMemberId = new Map(
      (attendances ?? []).map((attendance: any) => [
        attendance.member_id,
        attendance,
      ])
    );

    let reportRows = allMembers.map((member: any) => {
      const attendance = attendanceByMemberId.get(member.id) as any | undefined;
      const departments =
        departmentsByMemberId.get(member.id)?.join(", ") || "Non renseigné";
      const memberDepartmentIds = departmentIdsByMemberId.get(member.id) ?? [];
      const fullName = getMemberName(member);

      return {
        member,
        fullName,
        departments,
        memberDepartmentIds,
        attendance,
        isPresent: Boolean(attendance),
      };
    });

    if (selectedDepartmentId) {
      reportRows = reportRows.filter((row) =>
        row.memberDepartmentIds.includes(selectedDepartmentId)
      );
    }

    if (view === "present") {
      reportRows = reportRows.filter((row) => row.isPresent);
    }

    if (view === "absent") {
      reportRows = reportRows.filter((row) => !row.isPresent);
    }

    if (query) {
      const normalizedQuery = normalizeText(query);

      reportRows = reportRows.filter((row) => {
        const searchable = normalizeText(
          [
            row.fullName,
            getMemberCode(row.member),
            row.member.phone || "",
            row.member.email || "",
            row.departments,
          ].join(" ")
        );

        return searchable.includes(normalizedQuery);
      });
    }

    const header = [
      "Evenement",
      "ID membre",
      "Nom complet",
      "Telephone",
      "Email",
      "Departement",
      "Statut presence",
      "Heure pointage",
      "Methode",
    ];

    const lines = [
      header.map(formatCsvValue).join(";"),
      ...reportRows.map((row) => {
        return [
          getEventTitle(event),
          getMemberCode(row.member),
          row.fullName,
          row.member.phone || "",
          row.member.email || "",
          row.departments,
          row.attendance ? "Présent" : "Absent",
          row.attendance ? formatDate(row.attendance.check_in_at) : "",
          getMethodLabel(row.attendance?.check_in_method),
        ]
          .map(formatCsvValue)
          .join(";");
      }),
    ];

    const csv = `\uFEFF${lines.join("\n")}`;
    const filename = `rapport-presence-${slugifyFileName(
      getEventTitle(event)
    )}.csv`;

    return new NextResponse(csv, {
      status: 200,
      headers: {
        "Content-Type": "text/csv; charset=utf-8",
        "Content-Disposition": `attachment; filename="${filename}"`,
      },
    });
  } catch {
    return NextResponse.json(
      { error: "Erreur inattendue pendant l’export." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
type ScanBody = {
  eventId?: string;
  qrValue?: string;
};

type QrIdentity = {
  qrToken: string;
  memberId: string;
};

function getString(value: unknown) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function extractQrIdentity(qrValue: string): QrIdentity {
  const value = qrValue.trim();

  if (!value) {
    return {
      qrToken: "",
      memberId: "",
    };
  }

  /*
   * Cas 1 : ton QR actuel contient du JSON.
   * Exemple :
   * {"type":"mpangi_church_member","member_id":"...","church_slug":"iccrdc"}
   */
  try {
    const parsed = JSON.parse(value);

    if (parsed && typeof parsed === "object") {
      return {
        qrToken:
          getString((parsed as any).qr_token) ||
          getString((parsed as any).qrToken) ||
          getString((parsed as any).token),
        memberId:
          getString((parsed as any).member_id) ||
          getString((parsed as any).memberId) ||
          getString((parsed as any).id),
      };
    }
  } catch {
    // Le QR n'est pas du JSON, on continue avec les autres formats.
  }

  /*
   * Cas 2 : QR sous forme de lien public.
   * Exemple :
   * https://icckinshasa.mpangi-church.app/church/iccrdc/member-card/TOKEN
   */
  try {
    const url = new URL(value);
    const parts = url.pathname.split("/").filter(Boolean);
    const memberCardIndex = parts.findIndex((part) => part === "member-card");

    if (memberCardIndex >= 0 && parts[memberCardIndex + 1]) {
      return {
        qrToken: parts[memberCardIndex + 1],
        memberId: "",
      };
    }
  } catch {
    // Le QR peut contenir directement un token brut.
  }

  if (value.includes("/member-card/")) {
    return {
      qrToken: value.split("/member-card/")[1]?.split(/[?#]/)[0] || "",
      memberId: "",
    };
  }

  /*
   * Cas 3 : token brut.
   */
  return {
    qrToken: value,
    memberId: "",
  };
}

async function getCurrentProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return {
      profile: null,
      error: "Utilisateur non connecté.",
      status: 401,
    };
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) {
    return {
      profile: null,
      error: "Profil utilisateur introuvable.",
      status: 403,
    };
  }

  if (profile.status && profile.status !== "active") {
    return {
      profile: null,
      error: "Compte désactivé.",
      status: 403,
    };
  }

  if (!profile.church_id) {
    return {
      profile: null,
      error: "Aucune église rattachée à ce compte.",
      status: 403,
    };
  }

  return {
    profile,
    error: null,
    status: 200,
  };
}

async function findMemberByQrIdentity({
  admin,
  churchId,
  memberId,
  qrToken,
}: {
  admin: ReturnType<typeof createAdminClient>;
  churchId: string;
  memberId: string;
  qrToken: string;
}) {
  const selectFields = `
    id,
    first_name,
    last_name,
    phone,
    status,
    qr_token,
    qr_enabled
  `;

  /*
   * Priorité au member_id parce que ton QR actuel contient member_id.
   */
  if (memberId) {
    const { data: memberById } = await admin
      .from("members")
      .select(selectFields)
      .eq("church_id", churchId)
      .eq("id", memberId)
      .maybeSingle();

    if (memberById) {
      return memberById;
    }
  }

  /*
   * Compatibilité avec les QR qui contiennent qr_token ou un lien member-card.
   */
  if (qrToken) {
    const { data: memberByToken } = await admin
      .from("members")
      .select(selectFields)
      .eq("church_id", churchId)
      .eq("qr_token", qrToken)
      .maybeSingle();

    if (memberByToken) {
      return memberByToken;
    }
  }

  return null;
}

export async function POST(request: Request) {
  await requireAnyActionPermission(["attendance"], "create");
  try {
    const body = (await request.json()) as ScanBody;

    const eventId = getString(body.eventId);
    const qrValue = getString(body.qrValue);
    const { qrToken, memberId } = extractQrIdentity(qrValue);

    if (!eventId || (!qrToken && !memberId)) {
      return NextResponse.json(
        { error: "QR Code ou événement invalide." },
        { status: 400 }
      );
    }

    const { profile, error, status } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json({ error }, { status });
    }

    const admin = createAdminClient();

    const { data: event } = await admin
      .from("events")
      .select("*")
      .eq("id", eventId)
      .eq("church_id", profile.church_id)
      .maybeSingle();

    if (!event) {
      return NextResponse.json(
        { error: "Événement introuvable dans votre église." },
        { status: 404 }
      );
    }

    if (event.attendance_enabled === false) {
      return NextResponse.json(
        { error: "Le pointage est désactivé pour cet événement." },
        { status: 403 }
      );
    }

    const member = await findMemberByQrIdentity({
      admin,
      churchId: profile.church_id,
      memberId,
      qrToken,
    });

    if (!member) {
      return NextResponse.json(
        {
          error:
            "Membre introuvable pour ce QR Code. Le QR a bien été lu, mais son identifiant ne correspond à aucun membre de cette église.",
        },
        { status: 404 }
      );
    }

    if (member.qr_enabled === false) {
      return NextResponse.json(
        { error: "Le QR Code de ce membre est désactivé." },
        { status: 403 }
      );
    }

    if (member.status && member.status !== "actif") {
      return NextResponse.json(
        { error: "Ce membre n’est pas actif." },
        { status: 403 }
      );
    }

    const memberName =
      [member.first_name, member.last_name].filter(Boolean).join(" ") ||
      "Membre";

    const { data: existingAttendance } = await admin
      .from("event_attendances")
      .select("id, check_in_at")
      .eq("church_id", profile.church_id)
      .eq("event_id", eventId)
      .eq("member_id", member.id)
      .maybeSingle();

    if (existingAttendance) {
      return NextResponse.json({
        success: true,
        status: "already_checked_in",
        message: `${memberName} est déjà pointé pour cet événement.`,
        member: {
          id: member.id,
          name: memberName,
          phone: member.phone,
        },
        checkInAt: existingAttendance.check_in_at,
      });
    }

    const { data: attendance, error: attendanceError } = await admin
      .from("event_attendances")
      .insert({
        church_id: profile.church_id,
        event_id: eventId,
        member_id: member.id,
        scanned_by: profile.id,
        status: "present",
        check_in_method: "qr",
        qr_token_snapshot: qrToken || member.qr_token || memberId,
      })
      .select("id, check_in_at")
      .single();

    if (attendanceError || !attendance) {
      return NextResponse.json(
        {
          error:
            attendanceError?.message ||
            "Impossible d’enregistrer la présence.",
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      success: true,
      status: "checked_in",
      message: `Présence enregistrée pour ${memberName}.`,
      member: {
        id: member.id,
        name: memberName,
        phone: member.phone,
      },
      checkInAt: attendance.check_in_at,
    });
  } catch {
    return NextResponse.json(
      { error: "Erreur inattendue pendant le scan." },
      { status: 500 }
    );
  }
}

