import { NextRequest, NextResponse } from "next/server";
import {
  apiBibleFetch,
  BibleChapterContent,
  isSafeBibleIdentifier,
  sanitizeScriptureHtml,
} from "@/lib/bible/apiBible";

export const dynamic = "force-dynamic";

export async function GET(request: NextRequest) {
  const bibleId =
    request.nextUrl.searchParams.get("bibleId")?.trim() || "";
  const chapterId =
    request.nextUrl.searchParams.get("chapterId")?.trim() || "";

  if (
    !bibleId ||
    !chapterId ||
    !isSafeBibleIdentifier(bibleId) ||
    !isSafeBibleIdentifier(chapterId) ||
    !/^[1-3]?[A-Z]{2,4}\.\d+$/i.test(chapterId)
  ) {
    return NextResponse.json(
      {
        error: "Version ou chapitre invalide.",
        details: { bibleId, chapterId },
      },
      { status: 400 }
    );
  }

  const query = new URLSearchParams({
    "content-type": "html",
    "include-notes": "false",
    "include-titles": "true",
    "include-chapter-numbers": "false",
    "include-verse-numbers": "true",
    "include-verse-spans": "true",
    "fums-version": "3",
  });

  try {
    const response = await apiBibleFetch<BibleChapterContent>(
      `/bibles/${encodeURIComponent(
        bibleId
      )}/chapters/${encodeURIComponent(
        chapterId
      )}?${query.toString()}`,
      { revalidate: 600 }
    );

    return NextResponse.json(
      {
        data: {
          ...response.data,
          content: sanitizeScriptureHtml(
            response.data?.content || ""
          ),
        },
        fumsToken: response.meta?.fumsToken || null,
      },
      {
        headers: {
          "Cache-Control": "private, max-age=120",
        },
      }
    );
  } catch (error: any) {
    return NextResponse.json(
      {
        error:
          error?.message ||
          "Impossible de charger ce chapitre.",
        details: { bibleId, chapterId },
      },
      { status: 503 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import {
  apiBibleFetch,
  BibleSearchVerse,
  isSafeBibleIdentifier,
  stripBibleHtml,
} from "@/lib/bible/apiBible";

export const dynamic = "force-dynamic";

type SearchResponse = {
  query?: string;
  limit?: number;
  offset?: number;
  total?: number;
  verseCount?: number;
  verses?: BibleSearchVerse[];
  passages?: BibleSearchVerse[];
};

export async function GET(request: NextRequest) {
  const bibleId = request.nextUrl.searchParams.get("bibleId")?.trim() || "";
  const searchQuery =
    request.nextUrl.searchParams.get("query")?.trim() || "";

  if (!bibleId || !isSafeBibleIdentifier(bibleId)) {
    return NextResponse.json(
      { error: "Identifiant de version biblique invalide." },
      { status: 400 }
    );
  }

  if (searchQuery.length < 2) {
    return NextResponse.json(
      { error: "Saisissez au moins deux caractères." },
      { status: 400 }
    );
  }

  const query = new URLSearchParams({
    query: searchQuery,
    limit: "30",
    offset: "0",
    sort: "relevance",
    "fums-version": "3",
  });

  try {
    const response = await apiBibleFetch<SearchResponse>(
      `/bibles/${encodeURIComponent(
        bibleId
      )}/search?${query.toString()}`,
      { revalidate: 0 }
    );

    const rawResults =
      response.data?.verses || response.data?.passages || [];

    const results = rawResults.map((item) => ({
      ...item,
      text: stripBibleHtml(item.text || ""),
    }));

    return NextResponse.json({
      data: results,
      total:
        response.data?.total ||
        response.data?.verseCount ||
        results.length,
      fumsToken: response.meta?.fumsToken || null,
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        error: error?.message || "La recherche biblique a échoué.",
      },
      { status: 503 }
    );
  }
}

