      .filter(isFrenchBible)
      .filter(
        (version) => allowedIds.size === 0 || allowedIds.has(version.id)
      )
      .sort((a, b) => {
        const priority =
          getBibleVersionPriority(a) - getBibleVersionPriority(b);

        if (priority !== 0) return priority;

        return (a.nameLocal || a.name).localeCompare(
          b.nameLocal || b.name,
          "fr"
        );
      });

    const requestedDefault =
      process.env.BIBLE_DEFAULT_VERSION_ID?.trim() || "";

    const defaultBibleId =
      versions.find((version) => version.id === requestedDefault)?.id ||
      versions[0]?.id ||
      null;

    return NextResponse.json({
      data: versions,
      defaultBibleId,
      note:
        "Seules les versions françaises autorisées par votre clé API.Bible sont affichées.",
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        error:
          error?.message ||
          "Impossible de charger les versions bibliques françaises.",
      },
      { status: 503 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import { getRoleDashboardConfig } from "@/lib/dashboard/roleDashboard";

export const dynamic = "force-dynamic";

async function safeCount({
  table,
  churchId,
  churchColumn = "church_id",
  filters = [],
}: {
  table: string;
  churchId?: string | null;
  churchColumn?: string;
  filters?: Array<[string, string, any]>;
}) {
  try {
    const admin = createAdminClient();

    let query = admin
      .from(table)
      .select("*", { count: "exact", head: true });

    if (churchId) {
      query = query.eq(churchColumn, churchId);
    }

    for (const [method, column, value] of filters) {
      if (method === "eq") query = query.eq(column, value);
      if (method === "gte") query = query.gte(column, value);
      if (method === "lte") query = query.lte(column, value);
    }

    const { count, error } = await query;

    if (error) return 0;

    return count ?? 0;
  } catch {
    return 0;
  }
}

async function getProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) return null;

  const admin = createAdminClient();

  const { data: profile } = await admin
    .from("profiles")
    .select("id, full_name, email, role, church_id")
    .eq("id", user.id)
    .maybeSingle();

  return {
    user,
    profile,
  };
}

function firstDayOfMonth() {
  const now = new Date();
  return new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1)).toISOString();
}

function todayIsoDate() {
  return new Date().toISOString().slice(0, 10);
}

