  return NextResponse.json({
    profile: session.profile,
    config: {
      role: config.role,
      title: config.title,
      subtitle: config.subtitle,
      focus: config.focus,
      cards: (Array.isArray(config.cards) ? config.cards : []).map((card) => ({
        code: card.code,
        title: card.title,
        description: card.description,
        href: card.href,
        tone: card.tone,
