import { NextResponse } from "next/server";
import { CHURCH_DOCUMENTS_BUCKET } from "@/lib/storage/churchDocuments";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
function getString(value: unknown) {
  return value === null || value === undefined ? "" : String(value).trim();
}

export async function GET(request: Request) {
  await requireAnyModulePermission(["correspondence","inbox","transmissions","document_transmissions","minutes","meetings_minutes","assets","members","teachings"], "view");
  const url = new URL(request.url);
  const path = getString(url.searchParams.get("path"));
  const filename = getString(url.searchParams.get("filename"));

  if (!path) {
    return NextResponse.json({ error: "Chemin du document manquant." }, { status: 400 });
  }

  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return NextResponse.json({ error: "Utilisateur non connecté." }, { status: 401 });
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile || (profile.status && profile.status !== "active")) {
    return NextResponse.json({ error: "Accès refusé." }, { status: 403 });
  }

  if (profile.role !== "super_admin") {
    if (!profile.church_id || !path.startsWith(`${profile.church_id}/`)) {
      return NextResponse.json({ error: "Accès au document refusé." }, { status: 403 });
    }
  }

  const admin = createAdminClient();
  const { data, error } = await admin.storage
    .from(CHURCH_DOCUMENTS_BUCKET)
    .createSignedUrl(path, 60, { download: filename || true });

  if (error || !data?.signedUrl) {
    return NextResponse.json({ error: "Lien de téléchargement impossible." }, { status: 500 });
  }

  return NextResponse.redirect(data.signedUrl);
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
function txt(value: unknown) {
  return value === null || value === undefined ? "" : String(value).trim();
}

function csvEscape(value: unknown) {
  const text = value === null || value === undefined ? "" : String(value);
  return `"${text.replace(/"/g, '""')}"`;
}

function csvLine(values: unknown[]) {
  return values.map(csvEscape).join(";");
}

export async function GET(request: Request) {
  await requireAnyModulePermission(["finance_reports","financial_reports"], "view");
  const url = new URL(request.url);
  const dateFrom = txt(url.searchParams.get("dateFrom"));
  const dateTo = txt(url.searchParams.get("dateTo"));
  const category = txt(url.searchParams.get("category"));
  const department = txt(url.searchParams.get("department"));

  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return NextResponse.json({ error: "Utilisateur non connecté." }, { status: 401 });
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile || (profile.status && profile.status !== "active") || !profile.church_id) {
    return NextResponse.json({ error: "Accès refusé." }, { status: 403 });
  }

  const admin = createAdminClient();

  let query = admin
    .from("finance_transactions")
    .select(
      `
      transaction_date,
      transaction_type,
      title,
      amount,
      currency,
      amount_cdf,
      payment_method,
      reference,
      status,
      category:finance_categories(name),
      department:departments(name)
      `
    )
    .eq("church_id", profile.church_id)
    .neq("status", "archived")
    .order("transaction_date", { ascending: false });

  if (dateFrom) query = query.gte("transaction_date", dateFrom);
  if (dateTo) query = query.lte("transaction_date", dateTo);
  if (category) query = query.eq("category_id", category);
  if (department) query = query.eq("department_id", department);

  const { data, error } = await query;

  if (error) {
    return NextResponse.json({ error: "Export impossible." }, { status: 500 });
  }

  const rows = data ?? [];

  const header = [
    "Date",
    "Type",
    "Titre",
    "Catégorie",
    "Département",
    "Montant",
    "Devise",
    "Montant CDF",
    "Mode paiement",
    "Référence",
    "Statut",
  ];

  const lines = [
    csvLine(header),
    ...rows.map((row: any) =>
      csvLine([
        row.transaction_date,
        row.transaction_type === "income" ? "Entrée" : "Dépense",
        row.title,
        row.category?.name || "",
        row.department?.name || "",
        row.amount,
        row.currency,
        row.amount_cdf || "",
        row.payment_method,
        row.reference || "",
        row.status,
      ])
    ),
  ];

  const csv = "\ufeff" + lines.join("\n");

  return new NextResponse(csv, {
    status: 200,
    headers: {
      "Content-Type": "text/csv; charset=utf-8",
      "Content-Disposition": `attachment; filename="rapport-financier-${dateFrom || "debut"}-${dateTo || "fin"}.csv"`,
    },
  });
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
type MemberAction = "activate" | "deactivate" | "archive" | "delete";

type RequestBody = {
  memberId?: string;
  action?: MemberAction;
};

function getString(value: unknown) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

async function getCurrentProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return {
      profile: null,
      error: "Utilisateur non connecté.",
      status: 401,
    };
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) {
    return {
      profile: null,
      error: "Profil utilisateur introuvable.",
      status: 403,
    };
  }

  if (profile.status && profile.status !== "active") {
    return {
      profile: null,
      error: "Compte désactivé.",
      status: 403,
    };
  }

  if (profile.role === "super_admin") {
    return {
      profile: null,
      error: "Action réservée aux administrateurs d’église.",
      status: 403,
    };
  }

  if (!profile.church_id) {
    return {
      profile: null,
      error: "Aucune église rattachée à ce compte.",
      status: 403,
    };
  }

  return {
    profile,
    error: null,
    status: 200,
  };
}

export async function POST(request: Request) {
  await requireAnyActionPermission(["members"], "create");
  try {
    const body = (await request.json()) as RequestBody;

    const memberId = getString(body.memberId);
    const action = body.action;

    if (!memberId || !action) {
      return NextResponse.json(
        { error: "Action membre invalide." },
        { status: 400 }
      );
    }

    if (!["activate", "deactivate", "archive", "delete"].includes(action)) {
      return NextResponse.json(
        { error: "Type d’action invalide." },
        { status: 400 }
      );
    }

    const { profile, error, status } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json({ error }, { status });
    }

    const admin = createAdminClient();

    const { data: member } = await admin
      .from("members")
      .select("id, church_id, first_name, last_name, status")
      .eq("id", memberId)
      .eq("church_id", profile.church_id)
      .maybeSingle();

    if (!member) {
      return NextResponse.json(
        { error: "Membre introuvable dans votre église." },
        { status: 404 }
      );
    }

    if (action === "activate") {
      const { error: updateError } = await admin
        .from("members")
        .update({
          status: "actif",
          qr_enabled: true,
          archived_at: null,
          archived_by: null,
        })
        .eq("id", memberId)
        .eq("church_id", profile.church_id);

      if (updateError) {
        return NextResponse.json(
          { error: updateError.message },
          { status: 400 }
        );
      }

      return NextResponse.json({
        success: true,
        message: "Membre réactivé avec succès.",
      });
    }

    if (action === "deactivate") {
      const { error: updateError } = await admin
        .from("members")
        .update({
          status: "inactif",
          qr_enabled: false,
        })
        .eq("id", memberId)
        .eq("church_id", profile.church_id);

      if (updateError) {
        return NextResponse.json(
          { error: updateError.message },
          { status: 400 }
        );
      }

      return NextResponse.json({
        success: true,
        message: "Membre désactivé avec succès.",
      });
    }

    if (action === "archive") {
      const { error: updateError } = await admin
        .from("members")
        .update({
          status: "inactif",
          qr_enabled: false,
          archived_at: new Date().toISOString(),
          archived_by: profile.id,
        })
        .eq("id", memberId)
        .eq("church_id", profile.church_id);

      if (updateError) {
        return NextResponse.json(
          { error: updateError.message },
          { status: 400 }
        );
      }

      return NextResponse.json({
        success: true,
        message: "Membre archivé avec succès.",
      });
    }

    if (action === "delete") {
      await admin
        .from("member_departments")
        .delete()
        .eq("member_id", memberId)
        .eq("church_id", profile.church_id);

      await admin
        .from("member_trainings")
        .delete()
        .eq("member_id", memberId)
        .eq("church_id", profile.church_id);

      const { error: deleteError } = await admin
        .from("members")
        .delete()
        .eq("id", memberId)
        .eq("church_id", profile.church_id);

      if (deleteError) {
        return NextResponse.json(
          {
            error:
              deleteError.message ||
              "Impossible de supprimer ce membre. Il est peut-être lié à des présences ou autres données.",
          },
          { status: 400 }
        );
      }

      return NextResponse.json({
        success: true,
        message: "Membre supprimé définitivement.",
      });
    }

    return NextResponse.json(
      { error: "Action non traitée." },
      { status: 400 }
    );
  } catch {
    return NextResponse.json(
      { error: "Erreur inattendue pendant l’action membre." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { getSecurityContext } from "@/lib/security/access";
import {
  AFP_ROLES,
  CHURCH_ADMIN_ROLES,
  DEPARTMENT_ROLES,
  LOGISTIC_ROLES,
  PASTOR_ROLES,
  SECRETARY_ROLES,
  VIEWER_ROLES,
  WORKER_ROLES,
} from "@/lib/roles";

import { requireAuthenticatedAccess } from "@/lib/security/sensitiveGuards";
function fallbackCanView(role: string, moduleCode: string) {
  if (CHURCH_ADMIN_ROLES.has(role)) return true;

  if (["dashboard", "settings", "notifications", "pwa_install"].includes(moduleCode)) {
    return true;
  }

  if (PASTOR_ROLES.has(role)) {
    return [
      "members",
      "attendance",
      "souls",
      "departments",
      "events",
      "publications",
      "teachings",
      "appointments",
      "testimonies",
      "public_requests",
    ].includes(moduleCode);
  }

  if (AFP_ROLES.has(role)) {
    return [
      "correspondence",
      "document_transmissions",
      "administrative_tasks",
      "meetings_minutes",
      "finance_dashboard",
      "offerings",
      "expenses",
      "budgets",
      "financial_reports",
      "patrimony_dashboard",
      "assets",
      "asset_maintenance",
      "asset_movements",
      "teachings",
    ].includes(moduleCode);
  }

  if (SECRETARY_ROLES.has(role)) {
    return [
      "correspondence",
      "document_transmissions",
      "administrative_tasks",
      "meetings_minutes",
      "teachings",
    ].includes(moduleCode);
  }

  if (LOGISTIC_ROLES.has(role)) {
    return [
      "patrimony_dashboard",
      "assets",
      "asset_maintenance",
      "asset_movements",
      "administrative_tasks",
    ].includes(moduleCode);
  }

  if (DEPARTMENT_ROLES.has(role)) {
    return [
      "members",
      "attendance",
      "souls",
      "departments",
      "events",
      "administrative_tasks",
    ].includes(moduleCode);
  }

  if (WORKER_ROLES.has(role)) {
    return ["members", "attendance", "souls", "events"].includes(moduleCode);
  }

  if (VIEWER_ROLES.has(role)) {
    return ["members", "attendance", "souls", "events"].includes(moduleCode);
  }

  return false;
}

export async function GET() {
  await requireAuthenticatedAccess();
  try {
    const context = await getSecurityContext();

    if (!context) {
      return NextResponse.json(
        { error: "Utilisateur non connecté." },
        { status: 401 }
      );
    }

    const { admin, profile, role, churchId } = context;

    if (profile.status && profile.status !== "active") {
      return NextResponse.json({ error: "Compte désactivé." }, { status: 403 });
    }

    if (role === "super_admin") {
      return NextResponse.json({
        role,
        churchId: null,
        moduleCodes: [],
      });
    }

    if (!churchId) {
      return NextResponse.json({
        role,
        churchId: null,
        moduleCodes: ["dashboard"],
      });
    }

    const { data: enabledRows } = await admin
      .from("church_modules")
      .select("module_code, enabled")
      .eq("church_id", churchId)
      .eq("enabled", true);

    const enabledCodes = new Set(
      (enabledRows ?? []).map((row: any) => row.module_code)
    );

    const { data: explicitPermissions } = await admin
      .from("profile_module_permissions")
      .select("module_code, can_view")
      .eq("church_id", churchId)
      .eq("profile_id", profile.id);

    if ((explicitPermissions ?? []).length > 0) {
      const moduleCodes = (explicitPermissions ?? [])
        .filter((permission: any) => permission.can_view)
        .map((permission: any) => permission.module_code)
        .filter((code: string) => enabledCodes.has(code));

      return NextResponse.json({
        role,
        churchId,
        moduleCodes: Array.from(
          new Set(["dashboard", "settings", "notifications", ...moduleCodes])
        ),
        source: "profile",
      });
    }

    const { data: rolePermissions } = await admin
      .from("church_role_module_permissions")
      .select("module_code, can_view")
      .eq("church_id", churchId)
      .eq("role", role);

    if ((rolePermissions ?? []).length > 0) {
      const moduleCodes = (rolePermissions ?? [])
        .filter((permission: any) => permission.can_view)
        .map((permission: any) => permission.module_code)
        .filter((code: string) => enabledCodes.has(code));

      return NextResponse.json({
        role,
        churchId,
        moduleCodes: Array.from(
          new Set(["dashboard", "settings", "notifications", ...moduleCodes])
        ),
        source: "role",
      });
    }

    const fallbackCodes = Array.from(enabledCodes).filter((code) =>
      fallbackCanView(role, code)
    );

    return NextResponse.json({
      role,
      churchId,
      moduleCodes: Array.from(
        new Set(["dashboard", "settings", "notifications", ...fallbackCodes])
      ),
      source: "fallback",
    });
  } catch (error) {
    return NextResponse.json(
      { error: "Impossible de charger les modules." },
      { status: 500 }
    );
  }
}

