  }

  webpush.setVapidDetails(subject, publicKey, privateKey);

  return true;
}

function toWebPushSubscription(subscription: PushSubscriptionRow) {
  return {
    endpoint: subscription.endpoint,
    keys: {
      p256dh: subscription.p256dh,
      auth: subscription.auth,
    },
  };
}

export async function POST(request: Request) {
  await requireAnyActionPermission(["notifications"], "approve");
  try {
    const body = (await request.json()) as BroadcastBody;

    const title = getString(body.title);
    const messageBody = getString(body.body);
    const url = normalizeUrl(getString(body.url) || "/");

    if (!title || !messageBody) {
      return NextResponse.json(
        { error: "Le titre et le message sont obligatoires." },
        { status: 400 }
      );
    }

    if (title.length > 70) {
      return NextResponse.json(
        { error: "Le titre ne doit pas dépasser 70 caractères." },
        { status: 400 }
      );
    }

    if (messageBody.length > 180) {
      return NextResponse.json(
        { error: "Le message ne doit pas dépasser 180 caractères." },
        { status: 400 }
      );
    }

    const { profile, error, status } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json({ error }, { status });
    }

    const vapidConfigured = configureWebPush();

    if (!vapidConfigured) {
      return NextResponse.json(
        {
          error:
            "Les clés VAPID ne sont pas configurées. Vérifiez NEXT_PUBLIC_VAPID_PUBLIC_KEY et VAPID_PRIVATE_KEY.",
        },
        { status: 500 }
      );
    }

    const admin = createAdminClient();

    const { data: church } = await admin
      .from("churches")
      .select("id, name, public_name, pwa_name, logo_url, slug")
      .eq("id", profile.church_id)
      .maybeSingle();

    if (!church) {
      return NextResponse.json(
        { error: "Église introuvable." },
        { status: 404 }
      );
    }

    const { data: subscriptions } = await admin
      .from("push_subscriptions")
      .select("id, endpoint, p256dh, auth")
      .eq("church_id", profile.church_id);

    const activeSubscriptions = (subscriptions ?? []) as PushSubscriptionRow[];

    if (activeSubscriptions.length === 0) {
      await admin.from("notification_logs").insert({
        church_id: profile.church_id,
        title,
        body: messageBody,
        target: "all",
        sent_count: 0,
        failed_count: 0,
        sent_by: profile.id,
      });

      return NextResponse.json(
        {
          error:
            "Aucun appareil abonné aux notifications pour cette église.",
        },
        { status: 400 }
      );
    }

    const payload = JSON.stringify({
      title,
      body: messageBody,
      url,
      icon: church.logo_url || "/images/mpangi-logo.png",
      badge: "/images/mpangi-logo.png",
      churchId: church.id,
      churchSlug: church.slug,
      tag: `church-${church.id}-broadcast-${Date.now()}`,
    });

    let sentCount = 0;
    let failedCount = 0;
    const invalidSubscriptionIds: string[] = [];

    await Promise.all(
      activeSubscriptions.map(async (subscription) => {
        try {
          await webpush.sendNotification(
            toWebPushSubscription(subscription),
            payload
          );

          sentCount += 1;
        } catch (sendError: any) {
          failedCount += 1;

          if (
            sendError?.statusCode === 404 ||
            sendError?.statusCode === 410
          ) {
            invalidSubscriptionIds.push(subscription.id);
          }
        }
      })
    );

    if (invalidSubscriptionIds.length > 0) {
      await admin
        .from("push_subscriptions")
        .delete()
        .in("id", invalidSubscriptionIds);
    }

    await admin.from("notification_logs").insert({
      church_id: profile.church_id,
      title,
      body: messageBody,
      target: "all",
      sent_count: sentCount,
      failed_count: failedCount,
      sent_by: profile.id,
    });

    return NextResponse.json({
      success: true,
      sentCount,
      failedCount,
      removedInvalidSubscriptions: invalidSubscriptionIds.length,
    });
  } catch {
    return NextResponse.json(
      { error: "Erreur inattendue pendant l’envoi de la notification." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

type BrowserPushSubscription = {
  endpoint?: string;
  keys?: {
    p256dh?: string;
    auth?: string;
  };
};

export async function POST(
  request: Request
) {
  try {
    const payload =
      await request.json();

    const subscription =
      (payload.subscription ||
        payload) as BrowserPushSubscription;

    const endpoint =
      subscription?.endpoint;

    const p256dh =
      subscription?.keys?.p256dh;

    const auth =
      subscription?.keys?.auth;

    if (
      !endpoint ||
      !p256dh ||
      !auth
    ) {
      return NextResponse.json(
        {
          error:
            "Subscription push invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const supabase =
      await createClient();

    const {
      data: { user },
    } = await supabase.auth.getUser();

    let profileId:
      | string
      | null = null;

    let churchId:
      | string
      | null =
      payload.churchId || null;

    if (user) {
      const { data: profile } =
        await supabase
          .from("profiles")
          .select(
            "id, church_id"
          )
          .eq(
            "user_id",
            user.id
          )
          .maybeSingle();

      if (profile?.id) {
        profileId =
          profile.id;
      }

      if (
        profile?.church_id
      ) {
        churchId =
          profile.church_id;
      }
    }

    if (
      !churchId &&
      payload.churchSlug
    ) {
      const { data: church } =
        await admin
          .from("churches")
          .select(
            "id, status, public_enabled"
          )
          .eq(
            "slug",
            String(
              payload.churchSlug
            ).trim()
          )
          .maybeSingle();

      if (
        church?.id &&
        church.status ===
          "active" &&
        church.public_enabled
      ) {
        churchId =
          church.id;
      }
    }

    if (!churchId) {
      return NextResponse.json(
        {
          error:
            "Église introuvable pour cette notification.",
        },
        { status: 400 }
      );
    }

    const {
      data: church,
      error: churchError,
    } = await admin
      .from("churches")
      .select(
        "id, status, public_enabled"
      )
      .eq("id", churchId)
      .maybeSingle();

    if (
      churchError ||
      !church ||
      church.status !==
        "active" ||
      !church.public_enabled
    ) {
      return NextResponse.json(
        {
          error:
            "Église non disponible.",
        },
        { status: 404 }
      );
    }

    const { error } =
      await admin
        .from(
          "church_notification_subscriptions"
        )
        .upsert(
          {
            church_id:
              churchId,
            profile_id:
              profileId,
            endpoint,
            p256dh,
            auth,
            user_agent:
              request.headers.get(
                "user-agent"
              ),
            active: true,
            updated_at:
              new Date().toISOString(),
          },
          {
            onConflict:
              "endpoint",
          }
        );

    if (error) {
      return NextResponse.json(
        {
          error:
            error.message,
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      ok: true,
      message:
        "Notifications activées.",
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        error:
          error?.message ||
          "Impossible d’activer les notifications.",
      },
      { status: 500 }
    );
  }
}

import {
  NextRequest,
  NextResponse,
} from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import {
  DONATION_PAYMENT_CHANNELS,
  DONATION_PURPOSES,
} from "@/lib/donations/constants";

export const dynamic = "force-dynamic";

const ALLOWED_CHANNELS = new Set(
  DONATION_PAYMENT_CHANNELS.map(
    (item) => item.value
  )
);

const ALLOWED_PURPOSES = new Set(
  DONATION_PURPOSES.map(
    (item) => item.value
  )
);

function text(
  value: unknown,
  maxLength: number
) {
  return String(value || "")
    .trim()
    .slice(0, maxLength);
}

function createReference() {
  const date = new Date();

  const compactDate = [
    date.getUTCFullYear(),
    String(date.getUTCMonth() + 1).padStart(
      2,
      "0"
    ),
    String(date.getUTCDate()).padStart(
      2,
      "0"
    ),
  ].join("");

  const random = crypto
    .randomUUID()
    .replace(/-/g, "")
    .slice(0, 8)
    .toUpperCase();

  return `DON-${compactDate}-${random}`;
}

function getMethodFromChannel(
  channel: string
) {
  if (
    channel === "mpesa" ||
    channel === "airtel_money" ||
    channel === "orange_money"
  ) {
    return "mobile_money";
  }

  if (channel === "card") {
    return "card";
  }

  if (channel === "bank_transfer") {
    return "bank_transfer";
  }

  return "cash";
}

function isTenantHostname(
  hostname: string
) {
  const rootDomain =
    process.env.NEXT_PUBLIC_ROOT_DOMAIN ||
    "mpangi-church.app";

  const normalized = hostname
    .split(":")[0]
    .toLowerCase();

  return (
    normalized.endsWith(`.${rootDomain}`) &&
    normalized !== `www.${rootDomain}`
  );
}

function createConfirmationPath(
  request: NextRequest,
  slug: string,
  reference: string,
  token: string
) {
  const hostname =
    request.headers.get("host") || "";

  const basePath = isTenantHostname(
    hostname
  )
    ? "/don/success"
    : `/church/${slug}/don/success`;

  return `${basePath}?reference=${encodeURIComponent(
    reference
  )}&token=${encodeURIComponent(token)}`;
}

function buildPaymentUrl({
  rawUrl,
  amount,
  currency,
  reference,
  returnUrl,
}: {
  rawUrl: string;
  amount: number;
  currency: string;
  reference: string;
  returnUrl: string;
}) {
  return rawUrl
    .replaceAll(
      "{amount}",
      encodeURIComponent(String(amount))
    )
    .replaceAll(
      "{currency}",
      encodeURIComponent(currency)
    )
    .replaceAll(
      "{reference}",
      encodeURIComponent(reference)
    )
    .replaceAll(
      "{return_url}",
      encodeURIComponent(returnUrl)
    );
}

export async function POST(
  request: NextRequest
) {
  try {
    const payload = await request.json();

    const slug = text(
      payload?.slug,
      160
    );

    const donorName = text(
      payload?.donorName,
      160
    );

    const donorEmail = text(
      payload?.donorEmail,
      254
    ).toLowerCase();

    const donorPhone = text(
      payload?.donorPhone,
      80
    );

    const note = text(
      payload?.note,
      1500
    );

    const amount = Number(payload?.amount);

    const currency = text(
      payload?.currency,
      12
    ).toUpperCase();

    const channel = text(
      payload?.channel,
      40
    );

    const purpose = text(
      payload?.purpose,
      40
    );

    const isAnonymous = Boolean(
      payload?.isAnonymous
    );

    if (!slug) {
      return NextResponse.json(
        { error: "Église introuvable." },
        { status: 400 }
      );
    }

    if (
      !Number.isFinite(amount) ||
      amount <= 0
    ) {
      return NextResponse.json(
        {
          error:
            "Le montant doit être supérieur à zéro.",
        },
        { status: 400 }
      );
    }

    if (amount > 1_000_000_000) {
      return NextResponse.json(
        {
          error:
            "Le montant saisi est trop élevé.",
        },
        { status: 400 }
      );
    }

    if (!ALLOWED_CHANNELS.has(channel as any)) {
      return NextResponse.json(
        {
          error:
            "Moyen de paiement invalide.",
        },
        { status: 400 }
      );
    }

    if (!ALLOWED_PURPOSES.has(purpose as any)) {
      return NextResponse.json(
        {
          error:
            "Affectation du don invalide.",
        },
        { status: 400 }
      );
    }

    if (!isAnonymous && !donorName) {
      return NextResponse.json(
        {
          error:
            "Renseignez votre nom ou activez le don anonyme.",
        },
        { status: 400 }
      );
    }

    const method =
      getMethodFromChannel(channel);

    if (
      method === "mobile_money" &&
      !donorPhone
    ) {
      return NextResponse.json(
        {
          error:
            "Le téléphone du donateur est requis pour Mobile Money.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const {
      data: church,
      error: churchError,
    } = await admin
      .from("churches")
      .select(
        `
        id,
        name,
        public_name,
        slug,
        status,
        public_enabled,
        donation_enabled,
        donation_default_currency,
        donation_allowed_currencies,
        donation_min_amount,

        donation_mpesa_enabled,
        donation_mpesa_number,
        donation_mpesa_name,

        donation_airtel_enabled,
        donation_airtel_number,
        donation_airtel_name,

        donation_orange_enabled,
        donation_orange_number,
        donation_orange_name,

        donation_card_enabled,
        donation_card_url,
        donation_card_provider_name,

        donation_bank_enabled,
        donation_bank_name,
        donation_bank_account_name,
        donation_bank_account_number,
        donation_bank_iban,
        donation_bank_swift,
        donation_bank_details,

        donation_cash_enabled,
        donation_receipt_email
      `
      )
      .eq("slug", slug)
      .maybeSingle();

    if (
      churchError ||
      !church ||
      church.status !== "active" ||
      !church.public_enabled ||
      church.donation_enabled === false
    ) {
      return NextResponse.json(
        {
          error:
            "Les dons ne sont pas disponibles pour cette église.",
        },
        { status: 404 }
      );
    }

    const allowedCurrencies =
      Array.isArray(
        church.donation_allowed_currencies
      )
        ? church.donation_allowed_currencies.map(
            (item: string) =>
              String(item).toUpperCase()
          )
        : [
            church.donation_default_currency ||
              "CDF",
          ];

    if (
      !allowedCurrencies.includes(currency)
    ) {
      return NextResponse.json(
        {
          error:
            "Cette devise n’est pas autorisée.",
        },
        { status: 400 }
      );
    }

    const minimumAmount = Number(
      church.donation_min_amount || 1
    );

    if (amount < minimumAmount) {
      return NextResponse.json(
        {
          error: `Le montant minimum est de ${minimumAmount} ${currency}.`,
        },
        { status: 400 }
      );
    }

    const mobileConfig = {
      mpesa: {
        enabled:
          church.donation_mpesa_enabled,
        number:
          church.donation_mpesa_number,
        operator: "M-Pesa",
        accountName:
          church.donation_mpesa_name,
      },
      airtel_money: {
        enabled:
          church.donation_airtel_enabled,
        number:
          church.donation_airtel_number,
        operator: "Airtel Money",
        accountName:
          church.donation_airtel_name,
      },
      orange_money: {
        enabled:
          church.donation_orange_enabled,
        number:
          church.donation_orange_number,
        operator: "Orange Money",
        accountName:
          church.donation_orange_name,
      },
    } as const;

    const selectedMobile =
      channel in mobileConfig
        ? mobileConfig[
            channel as keyof typeof mobileConfig
          ]
        : null;

    if (
      method === "mobile_money" &&
      (
        !selectedMobile?.enabled ||
        !selectedMobile.number
      )
    ) {
      return NextResponse.json(
        {
          error:
            "Ce canal Mobile Money n’est pas configuré.",
        },
        { status: 400 }
      );
    }

    if (
      channel === "card" &&
      (
        !church.donation_card_enabled ||
        !church.donation_card_url
      )
    ) {
      return NextResponse.json(
        {
          error:
            "Le paiement par carte n’est pas encore configuré.",
        },
        { status: 400 }
      );
    }

    if (
      channel === "bank_transfer" &&
      (
        !church.donation_bank_enabled ||
        (
          !church.donation_bank_account_number &&
          !church.donation_bank_iban
        )
      )
    ) {
      return NextResponse.json(
        {
          error:
            "Le virement bancaire n’est pas encore configuré.",
        },
        { status: 400 }
      );
    }

    if (
      channel === "cash" &&
      church.donation_cash_enabled === false
    ) {
      return NextResponse.json(
        {
          error:
            "Les dons en espèces ne sont pas activés.",
        },
        { status: 400 }
      );
    }

    const reference =
      createReference();

    const publicToken =
      crypto.randomUUID();

    const confirmationPath =
      createConfirmationPath(
        request,
        slug,
        reference,
        publicToken
      );

    const absoluteConfirmationUrl =
      new URL(
        confirmationPath,
        request.url
      ).toString();

    const paymentProvider =
      selectedMobile?.operator ||
      (
        channel === "card"
          ? church.donation_card_provider_name ||
            "Paiement externe"
          : channel === "bank_transfer"
            ? church.donation_bank_name ||
              "Banque"
            : "Espèces"
      );

    const instructionSnapshot = {
      channel,
      mobileMoney: selectedMobile
        ? {
            operator:
              selectedMobile.operator,
            number:
              selectedMobile.number,
            accountName:
              selectedMobile.accountName,
          }
        : null,
      bank:
        channel === "bank_transfer"
          ? {
              bankName:
                church.donation_bank_name,
              accountName:
                church.donation_bank_account_name,
              accountNumber:
                church.donation_bank_account_number,
              iban:
                church.donation_bank_iban,
              swift:
                church.donation_bank_swift,
              details:
                church.donation_bank_details,
            }
          : null,
    };

    const status =
      channel === "cash"
        ? "submitted"
        : "awaiting_payment";

    const {
      data: donation,
      error: insertError,
    } = await admin
      .from("church_donations")
      .insert({
        church_id: church.id,
        reference,
        public_token: publicToken,

        donor_name: isAnonymous
          ? null
          : donorName,
        donor_email:
          donorEmail || null,
        donor_phone:
          donorPhone || null,
        is_anonymous: isAnonymous,

        amount,
        currency,
        method,
        payment_channel: channel,
        purpose,
        note: note || null,
        status,

        payment_provider:
          paymentProvider,

        external_payment_url:
          channel === "card"
            ? church.donation_card_url
            : null,

        payment_instructions_snapshot:
          instructionSnapshot,

        metadata: {
          source:
            "public_church_page",
          host:
            request.headers.get("host"),
          userAgent:
            request.headers.get(
              "user-agent"
            ),
        },
      })
      .select(
        "reference, public_token, status"
      )
      .single();

    if (
      insertError ||
      !donation
    ) {
      return NextResponse.json(
        {
          error:
            insertError?.message ||
            "Impossible d’enregistrer ce don.",
        },
        { status: 500 }
      );
    }

    const paymentUrl =
      channel === "card" &&
      church.donation_card_url
        ? buildPaymentUrl({
            rawUrl:
              church.donation_card_url,
            amount,
            currency,
            reference,
            returnUrl:
              absoluteConfirmationUrl,
          })
        : null;

    return NextResponse.json({
      data: {
        reference:
          donation.reference,
        publicToken:
          donation.public_token,
        status:
          donation.status,
        confirmationUrl:
          confirmationPath,
        paymentUrl,
        instructions: {
          mobileMoney:
            selectedMobile
              ? {
                  operator:
                    selectedMobile.operator,
                  number:
                    selectedMobile.number,
                  accountName:
                    selectedMobile.accountName,
                }
              : null,

          bank:
            channel === "bank_transfer"
              ? {
                  bankName:
                    church.donation_bank_name,
                  accountName:
                    church.donation_bank_account_name,
                  accountNumber:
                    church.donation_bank_account_number,
                  iban:
                    church.donation_bank_iban,
                  swift:
                    church.donation_bank_swift,
                  details:
                    church.donation_bank_details,
                }
              : null,

          receiptEmail:
            church.donation_receipt_email,
        },
      },
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        error:
          error?.message ||
          "Une erreur inattendue a empêché l’enregistrement du don.",
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import { sendChurchNotification } from "@/lib/notifications/push";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";
export const maxDuration = 60;

type PublicationAction =
  | "publish"
  | "unpublish"
  | "feature"
  | "unfeature"
  | "notify"
  | "delete";

type PatchPublicationBody = {
  publicationId?: string;
  action?: PublicationAction;
};

const PUBLICATION_TYPES = new Set([
  "news",
  "event",
  "announcement",
  "teaching",
  "sermon",
  "video",
  "message",
]);

const PUBLICATION_BUCKET = "church-publications";
const MAX_IMAGE_SIZE = 4 * 1024 * 1024;

function getString(value: unknown, maxLength = 5000) {
  if (value === null || value === undefined) {
    return "";
  }

  return String(value).trim().slice(0, maxLength);
}

function getBoolean(value: unknown) {
  return (
    value === true ||
    value === "true" ||
    value === "on" ||
    value === "1"
  );
}

function getYoutubeVideoId(url: string) {
  if (!url) return null;

  const watchMatch = url.match(/[?&]v=([^&]+)/);

  if (watchMatch?.[1]) {
    return watchMatch[1];
  }

  const shortMatch = url.match(/youtu\.be\/([^?&]+)/);

  if (shortMatch?.[1]) {
    return shortMatch[1];
  }

  const embedMatch = url.match(
    /youtube\.com\/embed\/([^?&/]+)/
  );

  return embedMatch?.[1] || null;
}

function getPublicationTypeLabel(value: string) {
  if (value === "news") return "Actualité";
  if (value === "event") return "Événement";
  if (value === "announcement") return "Annonce";
  if (value === "sermon") return "Prédication";
  if (value === "video") return "Vidéo";
  if (value === "message") return "Message";
  return "Enseignement";
}

async function getCurrentProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return {
      error: "Utilisateur non connecté.",
      status: 401,
      profile: null,
    };
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, user_id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) {
    return {
      error: "Profil utilisateur introuvable.",
      status: 404,
      profile: null,
    };
  }

  if (
    profile.status &&
    !["active", "actif"].includes(profile.status)
  ) {
    return {
      error: "Compte désactivé.",
      status: 403,
      profile: null,
    };
  }

  if (
    profile.role === "super_admin" ||
    !profile.church_id
  ) {
    return {
      error:
        "Cette action doit être effectuée depuis un espace église.",
      status: 403,
      profile: null,
    };
  }

  return {
    error: null,
    status: 200,
    profile,
  };
}

async function parseCreateBody(request: Request) {
  const contentType =
    request.headers.get("content-type") || "";

  if (
    contentType.includes(
      "multipart/form-data"
    )
  ) {
    const formData =
      await request.formData();

    const imageValue =
      formData.get("coverImage");

    return {
      title: getString(
        formData.get("title"),
        180
      ),
      excerpt: getString(
        formData.get("description"),
        1000
      ),
      content: getString(
        formData.get("content"),
        10000
      ),
      category:
        getString(
          formData.get("publicationType"),
          40
        ) || "teaching",
      videoUrl: getString(
        formData.get("videoUrl"),
        1000
      ),
      isPublished: getBoolean(
        formData.get("isPublished")
      ),
      isFeatured: getBoolean(
        formData.get("isFeatured")
      ),
      notify: getBoolean(
        formData.get("notify")
      ),
      coverImage:
        imageValue instanceof File &&
        imageValue.size > 0
          ? imageValue
          : null,
    };
  }

  const body =
    (await request.json()) as Record<
      string,
      unknown
    >;

  return {
    title: getString(
      body.title,
      180
    ),
    excerpt: getString(
      body.description,
      1000
    ),
    content: getString(
      body.content,
      10000
    ),
    category:
      getString(
        body.publicationType,
        40
      ) || "teaching",
    videoUrl: getString(
      body.videoUrl,
      1000
    ),
    isPublished: getBoolean(
      body.isPublished
    ),
    isFeatured: getBoolean(
      body.isFeatured
    ),
    notify: getBoolean(body.notify),
    coverImage: null as File | null,
  };
}

async function uploadCoverImage({
  admin,
  churchId,
  file,
}: {
  admin: ReturnType<
    typeof createAdminClient
  >;
  churchId: string;
  file: File;
}) {
  const allowedTypes =
    new Map<string, string>([
      ["image/jpeg", "jpg"],
      ["image/png", "png"],
      ["image/webp", "webp"],
    ]);

  const extension =
    allowedTypes.get(file.type);

  if (!extension) {
    throw new Error(
      "La photo doit être au format JPG, PNG ou WebP."
    );
  }

  if (file.size > MAX_IMAGE_SIZE) {
    throw new Error(
      "La photo ne peut pas dépasser 4 Mo."
    );
  }

  const objectPath = `${churchId}/${new Date().getUTCFullYear()}/${crypto.randomUUID()}.${extension}`;

  const content = Buffer.from(
    await file.arrayBuffer()
  );

  const { error } = await admin.storage
    .from(PUBLICATION_BUCKET)
    .upload(objectPath, content, {
      contentType: file.type,
      cacheControl: "3600",
      upsert: false,
    });

  if (error) {
    throw new Error(
      `Photo non envoyée : ${error.message}`
    );
  }

  const {
    data: { publicUrl },
  } = admin.storage
    .from(PUBLICATION_BUCKET)
    .getPublicUrl(objectPath);

  return {
    imageUrl: publicUrl,
    imagePath: objectPath,
  };
}

async function notifySubscribers({
  churchId,
  profileId,
  title,
  excerpt,
  category,
}: {
  churchId: string;
  profileId: string;
  title: string;
  excerpt: string;
  category: string;
}) {
  try {
    const result =
      await sendChurchNotification({
        churchId,
        createdBy: profileId,
        title: `${getPublicationTypeLabel(
          category
        )} : ${title}`,
        body:
          excerpt ||
          "Une nouvelle publication vient d’être ajoutée par votre église.",
        url: "/#actualites",
        type: "publication",
        data: {
          category,
        },
      });

    return {
      sentCount:
        result.successCount,
      failedCount:
        result.failureCount,
      warning:
        result.recipientsCount === 0
          ? "Publication enregistrée, mais aucun appareil n’est encore abonné."
          : null,
    };
  } catch (error: any) {
    return {
      sentCount: 0,
      failedCount: 0,
      warning:
        error?.message ||
        "Publication enregistrée, mais les notifications n’ont pas pu être envoyées.",
    };
  }
}

export async function POST(
  request: Request
) {
  let uploadedImagePath:
    | string
    | null = null;

  try {
    const {
      profile,
      error,
      status,
    } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json(
        { error },
        { status }
      );
    }

    const body =
      await parseCreateBody(request);

    if (!body.title) {
      return NextResponse.json(
        {
          error:
            "Le titre est obligatoire.",
        },
        { status: 400 }
      );
    }

    if (
      !PUBLICATION_TYPES.has(
        body.category
      )
    ) {
      return NextResponse.json(
        {
          error:
            "Type de publication invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    let imageUrl: string | null =
      null;

    if (body.coverImage) {
      const uploaded =
        await uploadCoverImage({
          admin,
          churchId:
            profile.church_id,
          file: body.coverImage,
        });

      imageUrl =
        uploaded.imageUrl;
      uploadedImagePath =
        uploaded.imagePath;
    }

    const published =
      body.isPublished ||
      body.notify;

    const youtubeVideoId =
      getYoutubeVideoId(
        body.videoUrl
      );

    const {
      data: publication,
      error: insertError,
    } = await admin
      .from(
        "church_publications"
      )
      .insert({
        church_id:
          profile.church_id,
        title: body.title,
        excerpt:
          body.excerpt || null,
        content:
          body.content || null,
        category:
          body.category,
        image_url:
          imageUrl,
        image_path:
          uploadedImagePath,
        video_url:
          body.videoUrl || null,
        youtube_url:
          body.videoUrl || null,
        youtube_video_id:
          youtubeVideoId,
        status: published
          ? "published"
          : "draft",
        is_public: true,
        is_featured:
          body.isFeatured,
        notify_subscribers:
          body.notify,
        published_at: published
          ? new Date().toISOString()
          : null,
        notified_at: null,
        created_by:
          profile.id,
        updated_by:
          profile.id,
      })
      .select(
        "id, title, excerpt, category"
      )
      .single();

    if (
      insertError ||
      !publication
    ) {
      if (uploadedImagePath) {
        await admin.storage
          .from(
            PUBLICATION_BUCKET
          )
          .remove([
            uploadedImagePath,
          ]);
      }

      return NextResponse.json(
        {
          error:
            insertError?.message ||
            "Impossible d’enregistrer la publication.",
          code:
            insertError?.code ||
            null,
          details:
            insertError?.details ||
            null,
          hint:
            insertError?.hint ||
            null,
        },
        { status: 400 }
      );
    }

    let sentCount = 0;
    let failedCount = 0;
    let warning:
      | string
      | null = null;

    if (body.notify) {
      const notifyResult =
        await notifySubscribers({
          churchId:
            profile.church_id,
          profileId:
            profile.id,
          title:
            publication.title,
          excerpt:
            publication.excerpt ||
            "",
          category:
            publication.category ||
            "teaching",
        });

      sentCount =
        notifyResult.sentCount;
      failedCount =
        notifyResult.failedCount;
      warning =
        notifyResult.warning;

      await admin
        .from(
          "church_publications"
        )
        .update({
          notified_at:
            new Date().toISOString(),
        })
        .eq(
          "id",
          publication.id
        )
        .eq(
          "church_id",
          profile.church_id
        );
    }

    return NextResponse.json({
      success: true,
      publicationId:
        publication.id,
      sentCount,
      failedCount,
      warning,
    });
  } catch (caughtError: any) {
    return NextResponse.json(
      {
        error:
          caughtError?.message ||
          "Erreur inattendue pendant la publication.",
        code:
          caughtError?.code ||
          null,
        details:
          caughtError?.details ||
          null,
        hint:
          caughtError?.hint ||
          null,
      },
      { status: 500 }
    );
  }
}

export async function PATCH(
  request: Request
) {
  try {
    const {
      profile,
      error,
      status,
    } = await getCurrentProfile();

    if (!profile) {
      return NextResponse.json(
        { error },
        { status }
      );
    }

    const body =
      (await request.json()) as PatchPublicationBody;

    const publicationId =
      getString(
        body.publicationId,
        80
      );

    const action =
      body.action;

    if (
      !publicationId ||
      !action
    ) {
      return NextResponse.json(
        {
          error:
            "Action invalide.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const {
      data: publication,
      error:
        publicationError,
    } = await admin
      .from(
        "church_publications"
      )
      .select(
        "id, church_id, title, excerpt, category, status, is_featured, image_path"
      )
      .eq("id", publicationId)
      .eq(
        "church_id",
        profile.church_id
      )
      .maybeSingle();

    if (
      publicationError ||
      !publication
    ) {
      return NextResponse.json(
        {
          error:
            publicationError?.message ||
            "Publication introuvable.",
        },
        { status: 404 }
      );
    }

    if (action === "delete") {
      const { error: deleteError } =
        await admin
          .from(
            "church_publications"
          )
          .delete()
          .eq(
            "id",
            publicationId
          )
          .eq(
            "church_id",
            profile.church_id
          );

      if (deleteError) {
        return NextResponse.json(
          {
            error:
              deleteError.message,
          },
          { status: 400 }
        );
      }

      if (
        publication.image_path
      ) {
        await admin.storage
          .from(
            PUBLICATION_BUCKET
          )
          .remove([
            publication.image_path,
          ]);
      }

      return NextResponse.json({
        success: true,
      });
    }

    if (action === "notify") {
      if (
        publication.status !==
        "published"
      ) {
        await admin
          .from(
            "church_publications"
          )
          .update({
            status: "published",
            is_public: true,
            published_at:
              new Date().toISOString(),
            updated_by:
              profile.id,
          })
          .eq(
            "id",
            publicationId
          )
          .eq(
            "church_id",
            profile.church_id
          );
      }

      const notifyResult =
        await notifySubscribers({
          churchId:
            profile.church_id,
          profileId:
            profile.id,
          title:
            publication.title,
          excerpt:
            publication.excerpt ||
            "",
          category:
            publication.category ||
            "teaching",
        });

      await admin
        .from(
          "church_publications"
        )
        .update({
          notified_at:
            new Date().toISOString(),
          notify_subscribers:
            true,
          updated_by:
            profile.id,
        })
        .eq(
          "id",
          publicationId
        )
        .eq(
          "church_id",
          profile.church_id
        );

      return NextResponse.json({
        success: true,
        sentCount:
          notifyResult.sentCount,
        failedCount:
          notifyResult.failedCount,
        warning:
          notifyResult.warning,
      });
    }

    const updates: Record<
      string,
      unknown
    > = {
      updated_at:
        new Date().toISOString(),
      updated_by:
        profile.id,
    };

    if (action === "publish") {
      updates.status =
        "published";
      updates.is_public = true;
      updates.published_at =
        new Date().toISOString();
    }

    if (
      action === "unpublish"
    ) {
      updates.status = "draft";
    }

    if (action === "feature") {
      updates.is_featured = true;
    }

    if (
      action === "unfeature"
    ) {
      updates.is_featured = false;
    }

    const { error: updateError } =
      await admin
        .from(
          "church_publications"
        )
        .update(updates)
        .eq(
          "id",
          publicationId
        )
        .eq(
          "church_id",
          profile.church_id
        );

    if (updateError) {
      return NextResponse.json(
        {
          error:
            updateError.message,
          code:
            updateError.code ||
            null,
          details:
            updateError.details ||
            null,
          hint:
            updateError.hint ||
            null,
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      success: true,
    });
  } catch (caughtError: any) {
    return NextResponse.json(
      {
        error:
          caughtError?.message ||
          "Erreur inattendue pendant la mise à jour.",
        code:
          caughtError?.code ||
          null,
        details:
          caughtError?.details ||
          null,
        hint:
          caughtError?.hint ||
          null,
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

type BrowserPushSubscription = {
  endpoint?: string;
  keys?: {
    p256dh?: string;
    auth?: string;
  };
};

export async function POST(request: Request) {
  try {
    const body = await request.json();

    const churchId = String(
      body.churchId || ""
    ).trim();

    const subscription =
      body.subscription as BrowserPushSubscription;

    if (
      !churchId ||
      !subscription?.endpoint
    ) {
      return NextResponse.json(
        {
          error:
            "Abonnement invalide : église ou endpoint manquant.",
        },
        { status: 400 }
      );
    }

    const p256dh =
      subscription.keys?.p256dh;

    const auth =
      subscription.keys?.auth;

    if (!p256dh || !auth) {
      return NextResponse.json(
        {
          error:
            "Clés d’abonnement Push invalides.",
        },
        { status: 400 }
      );
    }

    const admin =
      createAdminClient();

    const {
      data: church,
      error: churchError,
    } = await admin
      .from("churches")
      .select(
        "id, status, public_enabled"
      )
      .eq("id", churchId)
      .maybeSingle();

    if (
      churchError ||
      !church ||
      church.status !== "active" ||
      !church.public_enabled
    ) {
      return NextResponse.json(
        {
          error:
            "Église non disponible pour les notifications.",
        },
        { status: 404 }
      );
    }

    const {
      error: subscriptionError,
    } = await admin
      .from(
        "church_notification_subscriptions"
      )
      .upsert(
        {
          church_id: churchId,
          profile_id: null,
          endpoint:
            subscription.endpoint,
          p256dh,
          auth,
          user_agent:
            request.headers.get(
              "user-agent"
            ) || null,
          active: true,
          updated_at:
            new Date().toISOString(),
        },
        {
          onConflict: "endpoint",
        }
      );

    if (subscriptionError) {
      return NextResponse.json(
        {
          error:
            subscriptionError.message,
          code:
            subscriptionError.code ||
            null,
          details:
            subscriptionError.details ||
            null,
          hint:
            subscriptionError.hint ||
            null,
        },
        { status: 400 }
      );
    }

    return NextResponse.json({
      success: true,
      message:
        "Notifications activées sur cet appareil.",
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        error:
          error?.message ||
          "Erreur pendant l’activation des notifications.",
      },
      { status: 500 }
    );
  }
}

