import { NextResponse } from "next/server";
import * as webpush from "web-push";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
type RequestBody = {
  liveStreamEnabled?: boolean;
  liveStreamUrl?: string;
  liveStreamTitle?: string;
  liveStreamDescription?: string;
  liveStreamPlatform?: string;
  notify?: boolean;
};

function getString(value: unknown) {
  if (value === null || value === undefined) return "";
  return String(value).trim();
}

function configureWebPush() {
  const publicKey = process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY;
  const privateKey = process.env.VAPID_PRIVATE_KEY;
  const subject = process.env.VAPID_SUBJECT || "mailto:contact@aksantictech.com";

  if (!publicKey || !privateKey) {
    return false;
  }

  webpush.setVapidDetails(subject, publicKey, privateKey);
  return true;
}

export async function POST(request: Request) {
  await requireAnyActionPermission(["settings"], "create");
  try {
    const body = (await request.json()) as RequestBody;

    const supabase = await createClient();

    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json(
        { error: "Utilisateur non connecté." },
        { status: 401 }
      );
    }

    const { data: profile } = await supabase
      .from("profiles")
      .select("id, role, church_id, status")
      .eq("user_id", user.id)
      .maybeSingle();

    if (!profile || !profile.church_id) {
      return NextResponse.json(
        { error: "Profil utilisateur invalide." },
        { status: 403 }
      );
    }

    if (profile.status && profile.status !== "active") {
      return NextResponse.json(
        { error: "Compte désactivé." },
        { status: 403 }
      );
    }

    if (profile.role === "super_admin") {
      return NextResponse.json(
        { error: "Action réservée aux administrateurs d’église." },
        { status: 403 }
      );
    }

    const admin = createAdminClient();

    const liveStreamEnabled = Boolean(body.liveStreamEnabled);
    const liveStreamUrl = getString(body.liveStreamUrl);
    const liveStreamTitle = getString(body.liveStreamTitle);
    const liveStreamDescription = getString(body.liveStreamDescription);
    const liveStreamPlatform = getString(body.liveStreamPlatform);

    if (liveStreamEnabled && !liveStreamUrl) {
      return NextResponse.json(
        { error: "Le lien du direct est obligatoire si le direct est activé." },
        { status: 400 }
      );
    }

    const { data: church, error: churchError } = await admin
      .from("churches")
      .update({
        live_stream_enabled: liveStreamEnabled,
        live_stream_url: liveStreamUrl || null,
        live_stream_title: liveStreamTitle || null,
        live_stream_description: liveStreamDescription || null,
        live_stream_platform: liveStreamPlatform || null,
        live_stream_started_at: liveStreamEnabled
          ? new Date().toISOString()
          : null,
      })
      .eq("id", profile.church_id)
      .select("id, slug, name, public_name")
      .single();

    if (churchError || !church) {
      return NextResponse.json(
        { error: churchError?.message || "Église introuvable." },
        { status: 400 }
      );
    }

    let sentCount = 0;
    let failedCount = 0;

    if (body.notify && liveStreamEnabled && liveStreamUrl) {
      const configured = configureWebPush();

      if (!configured) {
        return NextResponse.json(
          {
            error:
              "Notifications non configurées. Vérifie les clés VAPID dans .env.local et Vercel.",
          },
          { status: 400 }
        );
      }

      const { data: subscriptions } = await admin
        .from("push_subscriptions")
        .select("id, endpoint, p256dh, auth")
        .eq("church_id", profile.church_id);

      const payload = JSON.stringify({
        title: `🔴 ${liveStreamTitle || "Culte en direct"}`,
        body:
          liveStreamDescription ||
          "Le culte en direct vient de commencer. Cliquez pour suivre.",
        url: `/church/${church.slug}`,
        icon: "/images/mpangi-logo.png",
        badge: "/images/mpangi-logo.png",
      });

      for (const subscription of subscriptions ?? []) {
        try {
          await webpush.sendNotification(
            {
              endpoint: subscription.endpoint,
              keys: {
                p256dh: subscription.p256dh,
                auth: subscription.auth,
              },
            },
            payload
          );

          sentCount += 1;
        } catch (error: any) {
          failedCount += 1;

          if (error?.statusCode === 404 || error?.statusCode === 410) {
            await admin
              .from("push_subscriptions")
              .delete()
              .eq("id", subscription.id);
          }
        }
      }

      await admin
        .from("churches")
        .update({
          live_stream_notified_at: new Date().toISOString(),
        })
        .eq("id", profile.church_id);
    }

    return NextResponse.json({
      success: true,
      sentCount,
      failedCount,
    });
  } catch {
    return NextResponse.json(
      { error: "Erreur inattendue pendant la publication du direct." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
type RequestBody = {
  action?: "toggle" | "regenerate";
  enabled?: boolean;
};

export async function POST(request: Request) {
  await requireAnyActionPermission(["settings"], "create");
  try {
    const body = (await request.json()) as RequestBody;

    const supabase = await createClient();

    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json(
        { error: "Utilisateur non connecté." },
        { status: 401 }
      );
    }

    const { data: profile } = await supabase
      .from("profiles")
      .select("id, role, church_id, status")
      .eq("user_id", user.id)
      .maybeSingle();

    if (!profile) {
      return NextResponse.json(
        { error: "Profil utilisateur introuvable." },
        { status: 404 }
      );
    }

    if (profile.status && profile.status !== "active") {
      return NextResponse.json(
        { error: "Compte désactivé." },
        { status: 403 }
      );
    }

    if (profile.role === "super_admin") {
      return NextResponse.json(
        { error: "Action réservée aux administrateurs d’église." },
        { status: 403 }
      );
    }

    if (!profile.church_id) {
      return NextResponse.json(
        { error: "Aucune église rattachée à ce compte." },
        { status: 400 }
      );
    }

    const admin = createAdminClient();

    if (body.action === "toggle") {
      const { error } = await admin
        .from("churches")
        .update({
          member_form_enabled: Boolean(body.enabled),
        })
        .eq("id", profile.church_id);

      if (error) {
        return NextResponse.json({ error: error.message }, { status: 400 });
      }

      return NextResponse.json({ success: true });
    }

    if (body.action === "regenerate") {
      const { error } = await admin
        .from("churches")
        .update({
          member_form_token: crypto.randomUUID(),
          member_form_enabled: true,
        })
        .eq("id", profile.church_id);

      if (error) {
        return NextResponse.json({ error: error.message }, { status: 400 });
      }

      return NextResponse.json({ success: true });
    }

    return NextResponse.json(
      { error: "Action invalide." },
      { status: 400 }
    );
  } catch {
    return NextResponse.json(
      { error: "Erreur inattendue." },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

type RouteProps = {
  params: Promise<{
    profileId: string;
  }>;
};

type UpdatePayload = {
  action:
    | "update_profile"
    | "update_status"
    | "archive"
    | "reset_password";
  fullName?: string;
  email?: string;
  role?: string;
  status?: "active" | "inactive";
  password?: string;
};

const ADMIN_ROLES = new Set([
  "admin",
  "administrator",
  "church_admin",
  "admin_eglise",
  "owner",
  "pasteur",
  "pasteur_t",
  "pastor",
]);

const ALLOWED_USER_ROLES = new Set([
  "church_admin",
  "admin_eglise",
  "pasteur_t",
  "pastor",
  "pasteur_a",
  "charge_afp",
  "department_leader",
  "responsable_d",
  "logisticien",
  "secretaire",
  "worker",
  "readonly",
  "member",
]);

const ACTIVE_STATUSES = ["active", "actif"];

function cleanText(value: unknown, maxLength: number) {
  return String(value || "").trim().slice(0, maxLength);
}

function isValidEmail(value: string) {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

async function getChurchAdminContext() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    return {
      error: NextResponse.json(
        { message: "Session expirée." },
        { status: 401 }
      ),
    };
  }

  const admin = createAdminClient();

  const { data: profile } = await admin
    .from("profiles")
    .select("id, user_id, role, status, church_id")
    .eq("user_id", user.id)
    .maybeSingle();

  if (
    !profile ||
    !profile.church_id ||
    !ADMIN_ROLES.has(String(profile.role).toLowerCase()) ||
    !ACTIVE_STATUSES.includes(String(profile.status || "active"))
  ) {
    return {
      error: NextResponse.json(
        { message: "Accès refusé." },
        { status: 403 }
      ),
    };
  }

  return {
    admin,
    user,
    profile,
  };
}

async function getTargetProfile(
  admin: ReturnType<typeof createAdminClient>,
  profileId: string,
  churchId: string
) {
  const { data, error } = await admin
    .from("profiles")
    .select(
      "id, user_id, church_id, full_name, email, role, status"
    )
    .eq("id", profileId)
    .eq("church_id", churchId)
    .maybeSingle();

  if (error) {
    throw new Error(error.message);
  }

  return data;
}

async function ensureNotLastAdministrator({
  admin,
  target,
  nextRole,
  nextStatus,
}: {
  admin: ReturnType<typeof createAdminClient>;
  target: any;
  nextRole?: string;
  nextStatus?: string;
}) {
  const targetIsAdministrator = ADMIN_ROLES.has(
    String(target.role || "").toLowerCase()
  );

  const targetIsActive = ACTIVE_STATUSES.includes(
    String(target.status || "active")
  );

  const removesAdminAccess =
    targetIsAdministrator &&
    targetIsActive &&
    (
      (nextRole &&
        !ADMIN_ROLES.has(String(nextRole).toLowerCase())) ||
      (nextStatus &&
        !ACTIVE_STATUSES.includes(String(nextStatus)))
    );

  if (!removesAdminAccess) {
    return;
  }

  const { data: profiles, error } = await admin
    .from("profiles")
    .select("id, role, status")
    .eq("church_id", target.church_id);

  if (error) {
    throw new Error(error.message);
  }

  const activeAdministrators = (profiles || []).filter(
    (item: any) =>
      ADMIN_ROLES.has(
        String(item.role || "").toLowerCase()
      ) &&
      ACTIVE_STATUSES.includes(
        String(item.status || "active")
      )
  );

  if (activeAdministrators.length <= 1) {
    throw new Error(
      "Impossible de retirer le dernier administrateur actif de cette église."
    );
  }
}

export async function PATCH(
  request: NextRequest,
  { params }: RouteProps
) {
  try {
    const context = await getChurchAdminContext();

    if ("error" in context) {
      return context.error;
    }

    const { profileId } = await params;
    const payload = (await request.json()) as UpdatePayload;

    const target = await getTargetProfile(
      context.admin,
      profileId,
      String(context.profile.church_id)
    );

    if (!target) {
      return NextResponse.json(
        { message: "Utilisateur introuvable dans cette église." },
        { status: 404 }
      );
    }

    if (String(target.role) === "super_admin") {
      return NextResponse.json(
        { message: "Un compte Super Admin est protégé." },
        { status: 403 }
      );
    }

    const isSelf = target.id === context.profile.id;

    if (payload.action === "update_profile") {
      const fullName = cleanText(payload.fullName, 160);
      const email = cleanText(payload.email, 254).toLowerCase();
      const role = cleanText(payload.role || target.role, 80);

      if (!fullName) {
        return NextResponse.json(
          { message: "Le nom complet est obligatoire." },
          { status: 400 }
        );
      }

      if (!email || !isValidEmail(email)) {
        return NextResponse.json(
          { message: "L’adresse email est invalide." },
          { status: 400 }
        );
      }

      if (!ALLOWED_USER_ROLES.has(role)) {
        return NextResponse.json(
          { message: "Le rôle sélectionné n’est pas autorisé." },
          { status: 400 }
        );
      }

      if (isSelf && role !== String(target.role)) {
        return NextResponse.json(
          {
            message:
              "Vous ne pouvez pas modifier votre propre rôle depuis cette page.",
          },
          { status: 400 }
        );
      }

      await ensureNotLastAdministrator({
        admin: context.admin,
        target,
        nextRole: role,
      });

      if (target.user_id) {
        const { data: authUser } =
          await context.admin.auth.admin.getUserById(
            target.user_id
          );

        const { error: authError } =
          await context.admin.auth.admin.updateUserById(
            target.user_id,
            {
              email,
              user_metadata: {
                ...(authUser?.user?.user_metadata || {}),
                full_name: fullName,
                role,
                church_id: target.church_id,
              },
            }
          );

        if (authError) {
          return NextResponse.json(
            { message: authError.message },
            { status: 400 }
          );
        }
      }

      const { error } = await context.admin
        .from("profiles")
        .update({
          full_name: fullName,
          email,
          role,
          updated_at: new Date().toISOString(),
        })
        .eq("id", target.id)
        .eq("church_id", target.church_id);

      if (error) {
        return NextResponse.json(
          { message: error.message },
          { status: 400 }
        );
      }

      return NextResponse.json({
        message: "Informations utilisateur mises à jour.",
      });
    }

    if (payload.action === "update_status") {
      if (isSelf) {
        return NextResponse.json(
          {
            message:
              "Vous ne pouvez pas désactiver ou réactiver votre propre compte.",
          },
          { status: 400 }
        );
      }

      const status =
        payload.status === "active"
          ? "active"
          : "inactive";

      await ensureNotLastAdministrator({
        admin: context.admin,
        target,
        nextStatus: status,
      });

      const { error } = await context.admin
        .from("profiles")
        .update({
          status,
          updated_at: new Date().toISOString(),
        })
        .eq("id", target.id)
        .eq("church_id", target.church_id);

      if (error) {
        return NextResponse.json(
          { message: error.message },
          { status: 400 }
        );
      }

      if (target.user_id) {
        const { data: authUser } =
          await context.admin.auth.admin.getUserById(
            target.user_id
          );

        await context.admin.auth.admin.updateUserById(
          target.user_id,
          {
            user_metadata: {
              ...(authUser?.user?.user_metadata || {}),
              status,
            },
          }
        );
      }

      return NextResponse.json({
        message:
          status === "active"
            ? "Compte réactivé."
            : "Compte désactivé.",
      });
    }

    if (payload.action === "archive") {
      if (isSelf) {
        return NextResponse.json(
          {
            message:
              "Vous ne pouvez pas archiver votre propre compte.",
          },
          { status: 400 }
        );
      }

      await ensureNotLastAdministrator({
        admin: context.admin,
        target,
        nextStatus: "archived",
      });

      const { error } = await context.admin
        .from("profiles")
        .update({
          status: "archived",
          updated_at: new Date().toISOString(),
        })
        .eq("id", target.id)
        .eq("church_id", target.church_id);

      if (error) {
        return NextResponse.json(
          { message: error.message },
          { status: 400 }
        );
      }

      if (target.user_id) {
        const { data: authUser } =
          await context.admin.auth.admin.getUserById(
            target.user_id
          );

        await context.admin.auth.admin.updateUserById(
          target.user_id,
          {
            user_metadata: {
              ...(authUser?.user?.user_metadata || {}),
              status: "archived",
            },
          }
        );
      }

      return NextResponse.json({
        message: "Compte archivé.",
      });
    }

    if (payload.action === "reset_password") {
      const password = String(payload.password || "");

      if (!target.user_id) {
        return NextResponse.json(
          {
            message:
              "Ce profil n’est lié à aucun compte de connexion.",
          },
          { status: 400 }
        );
      }

      if (password.length < 8) {
        return NextResponse.json(
          {
            message:
              "Le mot de passe doit contenir au moins 8 caractères.",
          },
          { status: 400 }
        );
      }

      const { error } =
        await context.admin.auth.admin.updateUserById(
          target.user_id,
          {
            password,
          }
        );

      if (error) {
        return NextResponse.json(
          { message: error.message },
          { status: 400 }
        );
      }

      return NextResponse.json({
        message: "Mot de passe temporaire enregistré.",
      });
    }

    return NextResponse.json(
      { message: "Action inconnue." },
      { status: 400 }
    );
  } catch (error: any) {
    return NextResponse.json(
      {
        message:
          error?.message ||
          "Une erreur a empêché la modification du compte.",
      },
      { status: 500 }
    );
  }
}

export async function DELETE(
  _request: NextRequest,
  { params }: RouteProps
) {
  try {
    const context = await getChurchAdminContext();

    if ("error" in context) {
      return context.error;
    }

    const { profileId } = await params;

    const target = await getTargetProfile(
      context.admin,
      profileId,
      String(context.profile.church_id)
    );

    if (!target) {
      return NextResponse.json(
        { message: "Utilisateur introuvable." },
        { status: 404 }
      );
    }

    if (target.id === context.profile.id) {
      return NextResponse.json(
        {
          message:
            "Vous ne pouvez pas supprimer votre propre compte.",
        },
        { status: 400 }
      );
    }

    if (
      String(target.role) === "super_admin"
    ) {
      return NextResponse.json(
        { message: "Le compte Super Admin est protégé." },
        { status: 403 }
      );
    }

    await ensureNotLastAdministrator({
      admin: context.admin,
      target,
      nextStatus: "deleted",
    });

    if (target.user_id) {
      const { error: authError } =
        await context.admin.auth.admin.deleteUser(
          target.user_id
        );

      if (authError) {
        return NextResponse.json(
          { message: authError.message },
          { status: 400 }
        );
      }
    }

    await context.admin
      .from("profile_module_permissions")
      .delete()
      .eq("profile_id", target.id)
      .eq("church_id", target.church_id);

    const { error: profileError } =
      await context.admin
        .from("profiles")
        .delete()
        .eq("id", target.id)
        .eq("church_id", target.church_id);

    if (profileError) {
      return NextResponse.json(
        { message: profileError.message },
        { status: 400 }
      );
    }

    return NextResponse.json({
      message: "Utilisateur supprimé définitivement.",
    });
  } catch (error: any) {
    return NextResponse.json(
      {
        message:
          error?.message ||
          "Une erreur a empêché la suppression.",
      },
      { status: 500 }
    );
  }
}

"use server";

import { redirect } from "next/navigation";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import { createOrUpdateUserAccount } from "@/lib/users/createUserAccount";
import {
  canCreateChurchUsers,
  normalizeUserRole,
} from "@/lib/users/userRoles";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
function readString(formData: FormData, key: string) {
  return String(formData.get(key) || "").trim();
}

async function getCurrentProfile() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) redirect("/login?reason=auth_required");

  const admin = createAdminClient();
  const { data: profile, error } = await admin
    .from("profiles")
    .select("id, role, church_id")
    .eq("user_id", user.id)
    .maybeSingle();

  if (error || !profile) {
    redirect("/unauthorized?reason=profile_missing");
  }

  return profile;
}

export async function createChurchUserAction(formData: FormData) {
  await requireAnyActionPermission(["users"], "create");
  const profile = await getCurrentProfile();

  if (!canCreateChurchUsers(profile.role)) {
    redirect(
      `/settings/users/new?error=${encodeURIComponent(
        "Vous n’avez pas l’autorisation de créer des utilisateurs."
      )}`
    );
  }

  if (!profile.church_id) {
    redirect(
      `/settings/users/new?error=${encodeURIComponent(
        "Votre profil administrateur n’est rattaché à aucune église."
      )}`
    );
  }

  let errorMessage = "";

  try {
    await createOrUpdateUserAccount({
      fullName: readString(formData, "full_name"),
      email: readString(formData, "email"),
      password: readString(formData, "password"),
      role: normalizeUserRole(readString(formData, "role")),
      status: readString(formData, "status") || "active",
      churchId: String(profile.church_id),
      updateExisting: true,
    });
  } catch (error: any) {
    errorMessage = error?.message || "Création impossible.";
  }

  if (errorMessage) {
    redirect(
      `/settings/users/new?error=${encodeURIComponent(errorMessage)}`
    );
  }

  redirect("/settings/users?createdUser=1");
}

import { NextResponse } from "next/server";
import { createClient } from "@/lib/supabase/server";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
type RouteProps = {
  params: Promise<{
    id: string;
  }>;
};

function splitFullName(fullName?: string | null) {
  const cleanName = fullName?.trim() || "Visiteur";
  const parts = cleanName.split(/\s+/).filter(Boolean);

  if (parts.length === 1) {
    return {
      first_name: parts[0],
      last_name: "",
    };
  }

  return {
    first_name: parts[0],
    last_name: parts.slice(1).join(" "),
  };
}

export async function POST(_request: Request, { params }: RouteProps) {
  await requireAnyActionPermission(["souls","members"], "create");
  try {
    const { id } = await params;

    if (!id) {
      return NextResponse.json(
        { message: "Identifiant du suivi obligatoire." },
        { status: 400 }
      );
    }

    const supabase = await createClient();

    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json(
        { message: "Session expirée. Reconnectez-vous." },
        { status: 401 }
      );
    }

    const { data: profile } = await supabase
      .from("profiles")
      .select("id, role, church_id, status")
      .eq("user_id", user.id)
      .maybeSingle();

    if (!profile) {
      return NextResponse.json(
        { message: "Profil utilisateur introuvable." },
        { status: 403 }
      );
    }

    if (profile.status && profile.status !== "active") {
      return NextResponse.json(
        { message: "Ce compte est désactivé." },
        { status: 403 }
      );
    }

    const { data: followup, error: followupError } = await supabase
      .from("soul_followups")
      .select(
        `
        id,
        church_id,
        member_id,
        full_name,
        phone,
        notes
      `
      )
      .eq("id", id)
      .maybeSingle();

    if (followupError) {
      return NextResponse.json(
        { message: followupError.message },
        { status: 400 }
      );
    }

    if (!followup) {
      return NextResponse.json(
        { message: "Suivi pastoral introuvable." },
        { status: 404 }
      );
    }

    const canManage =
      profile.role === "super_admin" || profile.church_id === followup.church_id;

    if (!canManage) {
      return NextResponse.json(
        { message: "Accès refusé pour ce suivi pastoral." },
        { status: 403 }
      );
    }

    if (followup.member_id) {
      return NextResponse.json({
        message: "Ce suivi est déjà lié à un membre.",
        memberId: followup.member_id,
      });
    }

    const { first_name, last_name } = splitFullName(followup.full_name);

    const { data: member, error: memberError } = await supabase
      .from("members")
      .insert({
        church_id: followup.church_id,
        first_name,
        last_name,
        phone: followup.phone || null,
        status: "actif",
      })
      .select("id")
      .single();

    if (memberError || !member) {
      return NextResponse.json(
        {
          message:
            memberError?.message || "Erreur lors de la création du membre.",
        },
        { status: 400 }
      );
    }

    const { error: updateError } = await supabase
      .from("soul_followups")
      .update({
        member_id: member.id,
        status: "integre",
      })
      .eq("id", followup.id);

    if (updateError) {
      return NextResponse.json(
        { message: updateError.message },
        { status: 400 }
      );
    }

    return NextResponse.json({
      message: "Membre créé avec succès.",
      memberId: member.id,
    });
  } catch (error) {
    return NextResponse.json(
      {
        message:
          error instanceof Error
            ? error.message
            : "Une erreur inconnue est survenue.",
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { requireSuperAdmin } from "@/lib/security/access";
import {
  completeOnboarding,
  getChurchOnboarding,
  getOnboardingSummaries,
  initializeOnboarding,
  resetOnboarding,
  updateOnboardingStep,
} from "@/lib/onboarding/onboarding";

import { requireSuperAdminAccess } from "@/lib/security/sensitiveGuards";
export const dynamic = "force-dynamic";

export async function GET(request: Request) {
  await requireSuperAdminAccess();
  await requireSuperAdmin();

  const url = new URL(request.url);
  const churchId = url.searchParams.get("churchId");

  if (churchId) {
    const payload = await getChurchOnboarding(churchId);
    return NextResponse.json(payload);
  }

  const churches = await getOnboardingSummaries();

  return NextResponse.json({
    churches,
  });
}

export async function POST(request: Request) {
  await requireSuperAdminAccess();
  const session = await requireSuperAdmin();
  const body = await request.json();

  const action = String(body.action || "");
  const churchId = String(body.churchId || "");

  if (!action) {
    return NextResponse.json(
      { error: "Action obligatoire." },
      { status: 400 }
    );
  }

  if (action === "init") {
    if (!churchId) {
      return NextResponse.json(
        { error: "churchId obligatoire." },
        { status: 400 }
      );
    }

    await initializeOnboarding(churchId);
    return NextResponse.json(await getChurchOnboarding(churchId));
  }

  if (action === "reset") {
    if (!churchId) {
      return NextResponse.json(
        { error: "churchId obligatoire." },
        { status: 400 }
      );
    }

    await resetOnboarding(churchId);
    return NextResponse.json(await getChurchOnboarding(churchId));
  }

  if (action === "complete_all") {
    if (!churchId) {
      return NextResponse.json(
        { error: "churchId obligatoire." },
        { status: 400 }
      );
    }

    await completeOnboarding(churchId, session.profile?.id ?? null);
    return NextResponse.json(await getChurchOnboarding(churchId));
  }

  if (action === "set_step") {
    const stepId = String(body.stepId || "");
    const status = String(body.status || "pending") as any;
    const notes = typeof body.notes === "string" ? body.notes : "";

    if (!churchId || !stepId) {
      return NextResponse.json(
        { error: "churchId et stepId obligatoires." },
        { status: 400 }
      );
    }

    if (!["pending", "in_progress", "done", "blocked"].includes(status)) {
      return NextResponse.json(
        { error: "Statut invalide." },
        { status: 400 }
      );
    }

    await updateOnboardingStep({
      stepId,
      status,
      notes,
      completedBy: session.profile?.id ?? null,
    });

    return NextResponse.json(await getChurchOnboarding(churchId));
  }

  return NextResponse.json(
    { error: "Action inconnue." },
    { status: 400 }
  );
}

"use server";

import { redirect } from "next/navigation";
