    supabase
      .from("members")
      .select("*", { count: "exact", head: true })
      .eq("church_id", churchId)
      .eq("status", "actif"),

    selectedEvent
      ? supabase
          .from("attendances")
          .select("*", { count: "exact", head: true })
          .eq("church_id", churchId)
          .eq("event_id", selectedEvent.id)
      : supabase
          .from("attendances")
          .select("*", { count: "exact", head: true })
          .eq("church_id", churchId)
          .eq("attendance_date", attendanceDate),

    selectedEvent
      ? supabase
          .from("event_attendances")
          .select("*", { count: "exact", head: true })
          .eq("church_id", churchId)
          .eq("event_id", selectedEvent.id)
      : Promise.resolve({ count: null } as any),

    supabase
      .from("members")
      .select(
        `
        id,
        first_name,
        middle_name,
        last_name,
        phone,
        photo_url,
        status
      `
      )
      .eq("church_id", churchId)
      .eq("status", "actif")
      .order("first_name", { ascending: true }),

    selectedEvent
      ? supabase
          .from("attendances")
          .select("id, member_id, status, check_in_time, method, created_at")
          .eq("church_id", churchId)
          .eq("event_id", selectedEvent.id)
          .order("created_at", { ascending: false })
      : supabase
          .from("attendances")
          .select("id, member_id, status, check_in_time, method, created_at")
          .eq("church_id", churchId)
          .eq("attendance_date", attendanceDate)
          .order("created_at", { ascending: false }),
