  const category = params.category || "";
  const dateFrom = params.dateFrom || "";
  const dateTo = params.dateTo || "";
  const currentUrl = buildCurrentUrl({ q, status, category, dateFrom, dateTo });

  const { admin, profile } = await requireChurchModuleAccess("budgets");

  const { data: categories } = await admin
    .from("finance_categories")
    .select("id, name")
    .eq("church_id", profile.church_id)
    .eq("type", "expense")
    .eq("active", true)
    .order("name", { ascending: true });

  let query = admin
    .from("finance_budgets")
    .select(
      `
      id,
      title,
      amount,
      currency,
      period_start,
      period_end,
      status,
      category:finance_categories(name),
      department:departments(name)
      `
    )
    .eq("church_id", profile.church_id)
    .order("period_start", { ascending: false })
    .limit(200);

  if (status) query = query.eq("status", status);
  if (category) query = query.eq("category_id", category);
  if (dateFrom) query = query.gte("period_end", dateFrom);
  if (dateTo) query = query.lte("period_start", dateTo);
  if (q) query = query.ilike("title", `%${q}%`);

  const { data: budgets } = await query;
  const rows = budgets ?? [];

  const totalBudget = rows
    .filter((row: any) => row.status !== "archived")
    .reduce((sum: number, row: any) => sum + Number(row.amount || 0), 0);

  const activeCount = rows.filter((row: any) => row.status === "active").length;
  const closedCount = rows.filter((row: any) => row.status === "closed").length;

