              </Link>
            </div>
          </form>
        </section>

        <section className="overflow-hidden rounded-3xl border border-[#DCEAF5] bg-white shadow-sm">
          <div className="border-b border-[#DCEAF5] p-5">
            <h2 className="text-xl font-extrabold text-[#03357A]">Budgets enregistrés</h2>
            <p className="mt-1 text-sm text-slate-500">{rows.length} budget(s) affiché(s).</p>
          </div>

          {rows.length === 0 ? (
            <div className="p-10 text-center">
              <PieChart className="mx-auto h-12 w-12 text-[#3F79B3]" />
              <p className="mt-4 font-extrabold text-[#03357A]">Aucun budget trouvé.</p>
            </div>
          ) : (
            <div className="divide-y divide-[#DCEAF5]">
              {rows.map((row: any) => (
                <div key={row.id} className="grid gap-4 p-5 transition hover:bg-[#F8FBFD] xl:grid-cols-[1.2fr_0.8fr_0.7fr_0.9fr]">
