                        </a>
                      )}

                      {row.status !== "archived" && (
                        <form action={archiveFinanceTransactionAction}>
                          <input type="hidden" name="id" value={row.id} />
                          <input type="hidden" name="transaction_type" value={CONFIG.type} />
                          <input type="hidden" name="redirectTo" value={currentUrl} />
