                    <div>
                      <p className="text-xs font-black uppercase tracking-wide text-slate-400">
                        Actions rapides
                      </p>

                      <form action={updateTransmissionStatusAction} className="mt-2 space-y-2">
                        <input type="hidden" name="id" value={row.id} />
                        <select name="status" defaultValue={row.status} className="min-h-10 w-full rounded-2xl border border-[#DCEAF5] bg-white px-3 text-xs font-bold text-slate-700 outline-none">
                          <option value="received">Reçu</option>
                          <option value="read">Lu</option>
                          <option value="in_progress">En traitement</option>
                          <option value="completed">Terminé</option>
                          <option value="returned">Retourné</option>
                          <option value="archived">Archivé</option>
                        </select>
                        <input type="hidden" name="note" value="Mise à jour rapide depuis la boîte administrative." />
                        <button type="submit" className="w-full rounded-2xl bg-[#03357A] px-3 py-2 text-xs font-extrabold text-white">
                          Mettre à jour
                        </button>
                      </form>

                      <p className="mt-3 text-xs font-semibold text-slate-500">
                        Échéance : {formatDate(row.due_date)}
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </section>
      </div>
    </AppShell>
  );
}

function Metric({ label, value, icon: Icon }: { label: string; value: number; icon: any }) {
