          <Icon className="h-6 w-6" />
        </div>
      </div>
    </div>
  );
}

"use client";

import Image from "next/image";
import Link from "next/link";
import { FormEvent, useEffect, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import {
  ArrowLeft,
  Church,
  Eye,
  EyeOff,
  Home,
  Lock,
  Mail,
} from "lucide-react";
import AppLogo from "@/components/brand/AppLogo";
import { getDashboardPathByRole } from "@/lib/auth/redirect-by-role";
import { createClient } from "@/lib/supabase/client";
import {
  buildChurchPublicUrl,
  buildMainAppUrl,
  getTenantSubdomainFromHost,
} from "@/lib/tenant/domain";

type ChurchContext = {
  id: string;
  name: string | null;
  public_name: string | null;
  pwa_name: string | null;
  slug: string | null;
  subdomain: string | null;
  logo_url: string | null;
};

function getPublicChurchName(church: {
  name?: string | null;
  public_name?: string | null;
  pwa_name?: string | null;
}) {
  const pwaName = church.pwa_name?.trim();

  if (pwaName) return pwaName;

  const publicName = church.public_name?.trim();

  if (publicName) return publicName;

  const name = church.name?.trim();

  if (!name) return "Église";

  return name.replace(/\s*[,|-]?\s*extension.*$/i, "").trim();
}

export default function LoginPage() {
  const router = useRouter();
  const supabase = useMemo(() => createClient(), []);

  const [churchSlug, setChurchSlug] = useState("");
  const [churchInfo, setChurchInfo] = useState<ChurchContext | null>(null);

  const [showPassword, setShowPassword] = useState(false);

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const [errorMessage, setErrorMessage] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const churchPublicName = churchInfo ? getPublicChurchName(churchInfo) : null;

  const loginTitle = churchPublicName
    ? `Connexion à votre espace admin ${churchPublicName.toUpperCase()}`
    : "Connexion à votre espace admin";

  const forgotPasswordHref = churchInfo?.slug
    ? `/forgot-password?church=${churchInfo.slug}`
    : "/forgot-password";

  useEffect(() => {
    let isMounted = true;

    async function resolveChurchContext() {
      const params = new URLSearchParams(window.location.search);
      let slug = params.get("church")?.trim() || "";

      if (!slug) {
        const tenantSubdomain = getTenantSubdomainFromHost(
          window.location.hostname
        );

        if (tenantSubdomain) {
          try {
            const response = await fetch("/api/pwa/tenant", {
              cache: "no-store",
            });
            const payload = await response.json();

            if (response.ok && payload.slug) {
              slug = String(payload.slug);
            }
          } catch {
            // Le proxy injecte aussi le tenant côté serveur.
          }
        }
      }

      if (!isMounted) return;

      setChurchSlug(slug);

      if (!slug) {
        setChurchInfo(null);
        return;
      }

      const { data } = await supabase
        .from("churches")
        .select(
          "id, name, public_name, pwa_name, slug, subdomain, logo_url"
        )
        .eq("slug", slug)
        .maybeSingle();

      if (!isMounted) return;

      setChurchInfo((data as ChurchContext | null) || null);
    }

    void resolveChurchContext();

    return () => {
      isMounted = false;
    };
  }, [supabase]);

  async function handleLogin(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();

    setErrorMessage("");
    setIsLoading(true);

    const { data, error } = await supabase.auth.signInWithPassword({
      email: email.trim(),
      password,
    });

    if (error || !data.user) {
      setErrorMessage(error?.message || "Identifiants incorrects.");
      setIsLoading(false);
      return;
    }

    const { data: profile, error: profileError } = await supabase
      .from("profiles")
      .select("role, church_id, status")
      .eq("user_id", data.user.id)
      .maybeSingle();

    if (profileError || !profile) {
      await supabase.auth.signOut();

      setErrorMessage("Profil utilisateur introuvable.");
      setIsLoading(false);
      return;
    }

    if (profile.status && profile.status !== "active") {
      await supabase.auth.signOut();

      setErrorMessage("Ce compte est désactivé. Contactez l’administrateur.");
      setIsLoading(false);
      return;
    }

    if (
      churchInfo?.id &&
      profile.role !== "super_admin" &&
      profile.church_id !== churchInfo.id
    ) {
      await supabase.auth.signOut();

      setErrorMessage(
        "Ce compte n’est pas rattaché à cette église. Veuillez utiliser le bon compte administrateur."
      );
      setIsLoading(false);
      return;
    }

    const dashboardPath = getDashboardPathByRole(profile.role);

    if (profile.role === "super_admin") {
      window.location.assign(
        buildMainAppUrl("/super-admin/dashboard")
      );
      return;
    }

    let targetChurch = churchInfo;

    if (!targetChurch && profile.church_id) {
      const { data: profileChurch } = await supabase
        .from("churches")
        .select(
          "id, name, public_name, pwa_name, slug, subdomain, logo_url"
        )
        .eq("id", profile.church_id)
        .maybeSingle();

      targetChurch =
        (profileChurch as ChurchContext | null) || null;
    }

    if (targetChurch?.slug) {
      window.location.assign(
        buildChurchPublicUrl(targetChurch, dashboardPath)
      );
      return;
    }

    router.replace(dashboardPath);
    router.refresh();
  }

