function formatDate(
  value?: string | null
) {
  if (!value) return "-";

  return new Intl.DateTimeFormat(
    "fr-FR",
    {
      day: "2-digit",
      month: "short",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    }
  ).format(new Date(value));
}

function getTypeLabel(
  type?: string | null
) {
  if (type === "news") {
    return "Actualité";
  }

  if (type === "event") {
    return "Événement";
  }

  if (
    type === "announcement"
  ) {
    return "Annonce";
  }

  if (type === "sermon") {
    return "Prédication";
  }

  if (type === "video") {
    return "Vidéo";
  }

  if (type === "message") {
    return "Message";
  }

  return "Enseignement";
}

