"use server";

import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { createAdminClient } from "@/lib/supabase/admin";
import { getCurrentSecurityContext } from "@/lib/security/permissionEngine";
import {
  MODULE_CATALOG,
  ROLE_CATALOG,
} from "@/lib/security/roleCatalog";

const ADMIN_ROLES = new Set([
  "super_admin",
  "church_admin",
  "admin_eglise",
  "pasteur_t",
  "pastor",
]);

const VALID_ROLES = new Set(
  ROLE_CATALOG.map((role) => role.code)
);

const VALID_MODULES = new Set(
  MODULE_CATALOG.map(([moduleCode]) => moduleCode)
);

async function getAdminContext() {
  const context = await getCurrentSecurityContext();

  if (
    !context.churchId ||
    !ADMIN_ROLES.has(context.role)
  ) {
    redirect("/unauthorized?reason=role_settings");
  }

  return context;
}

export async function updateRolePermissionAction(
  formData: FormData
) {
  const context = await getAdminContext();

  const roleCode = String(formData.get("role_code") || "");
  const moduleCode = String(
    formData.get("module_code") || ""
  );

  if (
    !VALID_ROLES.has(roleCode as any) ||
    !VALID_MODULES.has(moduleCode as any)
  ) {
    redirect("/settings/roles?error=invalid_permission");
  }

  const admin = createAdminClient();

  const { error } = await admin
    .from("church_role_module_permissions")
    .upsert(
      {
        church_id: context.churchId,
        role_code: roleCode,
        module_code: moduleCode,
        can_view: formData.get("can_view") === "on",
        can_create: formData.get("can_create") === "on",
        can_update: formData.get("can_update") === "on",
        can_delete: formData.get("can_delete") === "on",
        can_approve: formData.get("can_approve") === "on",
        is_enabled: formData.get("is_enabled") === "on",
      },
      {
        onConflict: "church_id,role_code,module_code",
      }
    );

  if (error) {
    redirect(
      `/settings/roles?role=${encodeURIComponent(
        roleCode
      )}&error=${encodeURIComponent(error.message)}`
    );
  }

  revalidatePath("/settings/roles");
  redirect(
    `/settings/roles?role=${encodeURIComponent(
      roleCode
    )}&saved=1`
  );
}

export async function updateRoleWidgetAction(
  formData: FormData
) {
  const context = await getAdminContext();

  const roleCode = String(formData.get("role_code") || "");
  const widgetCode = String(
    formData.get("widget_code") || ""
  );
  const position = Number(
    formData.get("position") || 100
  );

  if (!VALID_ROLES.has(roleCode as any) || !widgetCode) {
    redirect("/settings/roles?error=invalid_widget");
  }

  const admin = createAdminClient();

  const { error } = await admin
    .from("church_role_dashboard_widgets")
    .upsert(
      {
        church_id: context.churchId,
        role_code: roleCode,
        widget_code: widgetCode,
        position: Number.isFinite(position)
          ? Math.max(0, Math.min(position, 1000))
          : 100,
        is_enabled:
          formData.get("is_enabled") === "on",
      },
      {
        onConflict: "church_id,role_code,widget_code",
      }
    );

  if (error) {
    redirect(
      `/settings/roles?role=${encodeURIComponent(
        roleCode
      )}&error=${encodeURIComponent(error.message)}`
    );
  }

  revalidatePath("/settings/roles");
  revalidatePath("/dashboard/role");

  redirect(
    `/settings/roles?role=${encodeURIComponent(
      roleCode
    )}&saved=1`
  );
}

import Link from "next/link";
import { redirect } from "next/navigation";
import {
  AlertTriangle,
  ArrowLeft,
  BellRing,
  CheckCircle2,
  ClipboardCheck,
  ExternalLink,
  Globe,
  HelpCircle,
  Radio,
  Settings,
  ShieldCheck,
  Smartphone,
  UserPlus,
  Video,
  XCircle,
} from "lucide-react";
import AppShell from "@/components/layout/AppShell";
import { createClient } from "@/lib/supabase/server";

type CheckStatus = "ok" | "warning" | "danger" | "info";

function getPublicChurchName(church: {
  name?: string | null;
  public_name?: string | null;
  pwa_name?: string | null;
}) {
  const pwaName = church.pwa_name?.trim();
  if (pwaName) return pwaName;

  const publicName = church.public_name?.trim();
  if (publicName) return publicName;

  const name = church.name?.trim();
  if (!name) return "Église";

  return name.replace(/\s*[,|-]?\s*extension.*$/i, "").trim();
}

function getStatusStyle(status: CheckStatus) {
  if (status === "ok") {
    return {
      icon: CheckCircle2,
      badge: "bg-green-50 text-green-700",
      card: "border-green-100 bg-green-50/40",
      iconBox: "bg-green-50 text-green-700",
      label: "OK",
    };
  }

  if (status === "warning") {
    return {
      icon: AlertTriangle,
      badge: "bg-orange-50 text-orange-700",
      card: "border-orange-100 bg-orange-50/40",
      iconBox: "bg-orange-50 text-orange-700",
      label: "À compléter",
    };
  }

  if (status === "danger") {
    return {
      icon: XCircle,
      badge: "bg-red-50 text-red-700",
      card: "border-red-100 bg-red-50/40",
      iconBox: "bg-red-50 text-red-700",
      label: "Erreur",
    };
  }

  return {
    icon: HelpCircle,
    badge: "bg-blue-50 text-blue-700",
    card: "border-blue-100 bg-blue-50/40",
    iconBox: "bg-blue-50 text-blue-700",
    label: "Info",
  };
}

async function getExactCount(
  supabase: Awaited<ReturnType<typeof createClient>>,
  table: string,
  churchId: string,
  extra?: (query: any) => any
) {
  let query = supabase
    .from(table)
    .select("id", { count: "exact", head: true })
    .eq("church_id", churchId);

  if (extra) {
    query = extra(query);
  }

  const { count, error } = await query;

  if (error) {
    return 0;
  }

  return count ?? 0;
}

export default async function SystemCheckPage() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) {
    redirect("/login");
  }

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) {
    redirect("/login");
  }

  if (profile.status && profile.status !== "active") {
    redirect("/login");
  }

  if (profile.role === "super_admin") {
    redirect("/super-admin/dashboard");
  }

  if (!profile.church_id) {
    redirect("/login");
  }

  const { data: church } = await supabase
    .from("churches")
    .select(
      `
      id,
      name,
      public_name,
      pwa_name,
      pwa_short_name,
      slug,
      status,
      public_enabled,
      login_enabled,
      custom_domain,
      custom_domain_verified,
      member_form_enabled,
      member_form_token,
      live_stream_enabled,
      live_stream_url,
      live_stream_title,
      logo_url,
      pastor_name,
      phone,
      whatsapp,
      email,
      service_times
    `
    )
    .eq("id", profile.church_id)
    .maybeSingle();

  if (!church) {
    redirect("/settings");
  }

  const [
    membersCount,
    membersWithQrCount,
    departmentsCount,
    publicationsCount,
    publishedPublicationsCount,
    pushSubscriptionsCount,
  ] = await Promise.all([
    getExactCount(supabase, "members", church.id),
    getExactCount(supabase, "members", church.id, (query) =>
      query.not("qr_token", "is", null)
    ),
    getExactCount(supabase, "departments", church.id),
    getExactCount(supabase, "church_publications", church.id),
    getExactCount(supabase, "church_publications", church.id, (query) =>
      query.eq("is_published", true)
    ),
    getExactCount(supabase, "push_subscriptions", church.id),
  ]);

  const churchName = getPublicChurchName(church);
  const appBaseUrl =
    process.env.NEXT_PUBLIC_APP_URL || "https://mpangi-church.app";

  const publicPageUrl = church.slug
    ? `${appBaseUrl}/church/${church.slug}`
    : null;

  const customDomainUrl = church.custom_domain
    ? `https://${church.custom_domain}`
    : null;

  const memberRegistrationUrl =
    church.slug && church.member_form_token
      ? `${appBaseUrl}/church/${church.slug}/member-registration?token=${church.member_form_token}`
      : null;

  const vapidConfigured = Boolean(
    process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY && process.env.VAPID_PRIVATE_KEY
  );

  const qrCoverage =
    membersCount > 0 ? Math.round((membersWithQrCount / membersCount) * 100) : 0;

  const checks = [
    {
      title: "Église active",
      description:
        church.status === "active"
          ? "L’église est active dans la plateforme."
          : "L’église n’est pas active. La page publique peut être bloquée.",
      status: church.status === "active" ? "ok" : "danger",
      icon: ShieldCheck,
      actionHref: "/settings/public-page",
      actionLabel: "Vérifier",
    },
    {
      title: "Page publique",
      description:
        church.public_enabled && church.slug
          ? "La page publique est activée et accessible."
          : "La page publique n’est pas encore totalement activée.",
      status: church.public_enabled && church.slug ? "ok" : "warning",
      icon: Globe,
      actionHref: publicPageUrl,
      actionLabel: "Ouvrir",
      external: true,
    },
    {
      title: "Sous-domaine / domaine",
      description:
        church.custom_domain && church.custom_domain_verified
          ? `${church.custom_domain} est lié à cette église.`
          : "Aucun sous-domaine vérifié n’est encore lié à cette église.",
      status:
        church.custom_domain && church.custom_domain_verified
          ? "ok"
          : "warning",
      icon: Globe,
      actionHref: customDomainUrl,
      actionLabel: "Ouvrir domaine",
      external: true,
    },
    {
      title: "Formulaire public membre",
      description:
        church.member_form_enabled && church.member_form_token
          ? "Le formulaire public d’inscription membre est actif."
          : "Le formulaire public membre n’est pas encore actif.",
      status:
        church.member_form_enabled && church.member_form_token
          ? "ok"
          : "warning",
      icon: UserPlus,
      actionHref: "/settings/member-registration",
      actionLabel: "Configurer",
    },
    {
      title: "QR personnel membre",
      description:
        membersCount === 0
          ? "Aucun membre enregistré pour vérifier la couverture QR."
          : `${membersWithQrCount}/${membersCount} membres ont un QR personnel généré (${qrCoverage}%).`,
      status:
        membersCount === 0
          ? "info"
          : membersWithQrCount === membersCount
            ? "ok"
            : "warning",
      icon: ClipboardCheck,
      actionHref: "/members",
      actionLabel: "Voir membres",
    },
    {
      title: "Départements",
