      status: vapidConfigured
        ? pushSubscriptionsCount > 0
          ? "ok"
          : "warning"
        : "danger",
      icon: BellRing,
      actionHref: publicPageUrl,
      actionLabel: "Activer sur mobile",
      external: true,
