  );
}

import Link from "next/link";
import { notFound } from "next/navigation";
import {
  ArrowLeft,
  Church,
  GraduationCap,
  Pencil,
  Users,
} from "lucide-react";
import AppShell from "@/components/layout/AppShell";
import MetricCard from "@/components/dashboard/MetricCard";
import TrainingProgramStatusButton from "@/components/settings/TrainingProgramStatusButton";
import { createClient } from "@/lib/supabase/server";

type TrainingDetailsPageProps = {
  params: Promise<{
    id: string;
  }>;
};

function firstItem<T>(value: T | T[] | null | undefined): T | null {
  if (!value) return null;
  return Array.isArray(value) ? value[0] ?? null : value;
}

export default async function TrainingDetailsPage({
  params,
}: TrainingDetailsPageProps) {
  const { id } = await params;

  const supabase = await createClient();

  const { data: trainingRaw } = await supabase
    .from("training_programs")
    .select(
      `
      id,
      church_id,
      name,
      description,
      sort_order,
      status,
      created_at,
      churches(name)
    `
    )
    .eq("id", id)
    .maybeSingle();

  if (!trainingRaw) {
    notFound();
  }

  const training = trainingRaw as any;
  const church = firstItem<any>(training.churches);

  const { count: membersCount } = await supabase
    .from("member_trainings")
    .select("*", { count: "exact", head: true })
    .eq("training_program_id", training.id);

  return (
    <AppShell>
      <div className="space-y-6">
        <Link
          href="/settings/trainings"
          className="inline-flex items-center gap-2 text-sm font-bold text-[#2563EB]"
