"use server";

import { redirect } from "next/navigation";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import { createOrUpdateUserAccount } from "@/lib/users/createUserAccount";
import {
  canCreateChurchUsers,
  normalizeUserRole,
} from "@/lib/users/userRoles";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
function readString(formData: FormData, key: string) {
  return String(formData.get(key) || "").trim();
}

async function getCurrentProfile() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) redirect("/login?reason=auth_required");

  const admin = createAdminClient();
  const { data: profile, error } = await admin
    .from("profiles")
    .select("id, role, church_id")
    .eq("user_id", user.id)
    .maybeSingle();

  if (error || !profile) {
    redirect("/unauthorized?reason=profile_missing");
  }

  return profile;
}

export async function createChurchUserAction(formData: FormData) {
  await requireAnyActionPermission(["users"], "create");
  const profile = await getCurrentProfile();

  if (!canCreateChurchUsers(profile.role)) {
    redirect(
      `/settings/users/new?error=${encodeURIComponent(
        "Vous n’avez pas l’autorisation de créer des utilisateurs."
      )}`
    );
  }

  if (!profile.church_id) {
    redirect(
      `/settings/users/new?error=${encodeURIComponent(
        "Votre profil administrateur n’est rattaché à aucune église."
      )}`
    );
  }

  let errorMessage = "";

  try {
    await createOrUpdateUserAccount({
      fullName: readString(formData, "full_name"),
      email: readString(formData, "email"),
      password: readString(formData, "password"),
      role: normalizeUserRole(readString(formData, "role")),
      status: readString(formData, "status") || "active",
      churchId: String(profile.church_id),
      updateExisting: true,
    });
  } catch (error: any) {
    errorMessage = error?.message || "Création impossible.";
  }

  if (errorMessage) {
    redirect(
      `/settings/users/new?error=${encodeURIComponent(errorMessage)}`
    );
  }

  redirect("/settings/users?createdUser=1");
}

import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import Link from "next/link";
import { UserPlus } from "lucide-react";
import ChurchUserProfileActions from "@/components/settings/ChurchUserProfileActions";

import AppShell from "@/components/layout/AppShell";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

type SettingsUsersPageProps = {
  searchParams?: Promise<{
    profileId?: string;
    saved?: string;
    created?: string;
    createdUser?: string;
    updated?: string;
    deleted?: string;
  }>;
};

const ADMIN_ROLES = new Set([
  "admin",
  "administrator",
  "church_admin",
  "owner",
  "pasteur",
  "pastor",
]);

const CATEGORY_LABELS: Record<string, string> = {
  system: "Général",
  spiritual: "Volet spirituel",
  administration: "Volet administratif",
  finance: "Volet finances",
  patrimony: "Volet patrimoine",
};

function boolFromForm(value: FormDataEntryValue | null) {
  return value === "on" || value === "true";
}

async function getCurrentAdminProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) redirect("/login");

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) redirect("/login");

  if (profile.status && profile.status !== "active") redirect("/login");

  const role = String(profile.role || "").toLowerCase();

  if (role === "super_admin") redirect("/super-admin/settings");

  if (!profile.church_id || !ADMIN_ROLES.has(role)) {
    redirect("/dashboard");
  }

  return profile;
}

export async function saveProfileModulePermissionAction(formData: FormData) {
  "use server";

  const adminProfile = await getCurrentAdminProfile();
  const admin = createAdminClient();

  const profileId = String(formData.get("profile_id") || "");
  const moduleCode = String(formData.get("module_code") || "");

  if (!profileId || !moduleCode) {
    redirect("/settings/users");
  }

  const { data: targetProfile } = await admin
    .from("profiles")
    .select("id, church_id")
    .eq("id", profileId)
    .eq("church_id", adminProfile.church_id)
    .maybeSingle();

  if (!targetProfile) {
    redirect("/settings/users");
  }

  await admin.from("profile_module_permissions").upsert(
    {
      church_id: adminProfile.church_id,
      profile_id: profileId,
      module_code: moduleCode,
      can_view: boolFromForm(formData.get("can_view")),
      can_create: boolFromForm(formData.get("can_create")),
      can_update: boolFromForm(formData.get("can_update")),
      can_delete: boolFromForm(formData.get("can_delete")),
      can_export: boolFromForm(formData.get("can_export")),
      can_approve: boolFromForm(formData.get("can_approve")),
      updated_by: adminProfile.id,
      updated_at: new Date().toISOString(),
    },
    {
      onConflict: "church_id,profile_id,module_code",
    }
  );

  revalidatePath("/settings/users");
  redirect(`/settings/users?profileId=${profileId}&saved=1`);
}

export async function clearProfileModulePermissionAction(formData: FormData) {
  "use server";

  const adminProfile = await getCurrentAdminProfile();
  const admin = createAdminClient();

  const profileId = String(formData.get("profile_id") || "");
  const moduleCode = String(formData.get("module_code") || "");

  if (!profileId || !moduleCode) {
    redirect("/settings/users");
  }

  await admin
    .from("profile_module_permissions")
    .delete()
    .eq("church_id", adminProfile.church_id)
    .eq("profile_id", profileId)
    .eq("module_code", moduleCode);

  revalidatePath("/settings/users");
  redirect(`/settings/users?profileId=${profileId}&saved=1`);
}

export default async function SettingsUsersPage({
  searchParams,
}: SettingsUsersPageProps) {
  const params = searchParams ? await searchParams : {};
  const adminProfile = await getCurrentAdminProfile();
  const admin = createAdminClient();

  const [{ data: users }, { data: enabledModules }] = await Promise.all([
    admin
      .from("profiles")
      .select("id, user_id, full_name, email, role, status")
      .eq("church_id", adminProfile.church_id)
      .order("full_name", { ascending: true }),

    admin
      .from("church_modules")
      .select(
        `
        module_code,
        enabled,
        module:app_modules(code, name, category, description)
        `
      )
      .eq("church_id", adminProfile.church_id)
      .eq("enabled", true),
  ]);

  const userRows = users ?? [];
  const selectedProfileId = params.profileId || userRows[0]?.id || "";

  const { data: permissions } = selectedProfileId
    ? await admin
        .from("profile_module_permissions")
        .select("*")
        .eq("church_id", adminProfile.church_id)
        .eq("profile_id", selectedProfileId)
    : { data: [] };

  const selectedUser = userRows.find(
    (user: any) => user.id === selectedProfileId
  );

  const permissionMap = new Map(
    (permissions ?? []).map((permission: any) => [
      permission.module_code,
      permission,
    ])
  );

  const moduleRows = (enabledModules ?? [])
    .map((row: any) => ({
      module_code: row.module_code,
      name: row.module?.name || row.module_code,
      category: row.module?.category || "system",
      description: row.module?.description || "",
    }))
    .sort((a: any, b: any) => {
      const categoryCompare = String(a.category).localeCompare(
        String(b.category)
      );

