"use server";

import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { requireChurchModuleAccess } from "@/lib/modules/moduleAccess";

import { requireAnyActionPermission } from "@/lib/security/secureAction";
import { requireAnyModulePermission } from "@/lib/security/routeGuard";
function txt(value: FormDataEntryValue | null) {
  return value === null || value === undefined ? "" : String(value).trim();
}

function normalizeStatus(status: string) {
  if (
    [
      "sent",
      "received",
      "read",
      "in_progress",
      "completed",
      "returned",
      "archived",
    ].includes(status)
  ) {
    return status;
  }

  return "sent";
}

function statusDates(status: string) {
  const now = new Date().toISOString();

  if (status === "completed") {
    return {
      received_at: now,
      completed_at: now,
    };
  }

  if (["received", "read", "in_progress"].includes(status)) {
    return {
      received_at: now,
    };
  }

  return {};
}

export async function updateTransmissionStatusAction(formData: FormData) {
  await requireAnyActionPermission(["transmissions","document_transmissions"], "update");
  const { admin, profile } = await requireChurchModuleAccess("document_transmissions");

  const id = txt(formData.get("id"));
  const status = normalizeStatus(txt(formData.get("status")));
  const note = txt(formData.get("note"));

  if (!id) {
    redirect("/administration/inbox");
  }

  await admin
    .from("admin_document_transmissions")
    .update({
      status,
      ...statusDates(status),
      updated_by: profile.id,
      updated_at: new Date().toISOString(),
    })
    .eq("church_id", profile.church_id)
    .eq("id", id);

  await admin.from("admin_document_transmission_steps").insert({
    church_id: profile.church_id,
    transmission_id: id,
    from_profile_id: profile.id,
    status,
    note: note || `Statut mis à jour : ${status}`,
    created_by: profile.id,
  });

  revalidatePath("/inbox");
  revalidatePath("/administration/inbox");
  revalidatePath("/administration/transmissions");
  revalidatePath(`/administration/transmissions/${id}`);
}

export async function archiveTransmissionAction(formData: FormData) {
  await requireAnyActionPermission(["transmissions","document_transmissions"], "delete");
  const { admin, profile } = await requireChurchModuleAccess("document_transmissions");

  const id = txt(formData.get("id"));
  const redirectTo =
    txt(formData.get("redirectTo")) ||
    txt(formData.get("redirect_to")) ||
    "/administration/inbox";

  if (!id) {
    redirect(redirectTo);
  }

  await admin
    .from("admin_document_transmissions")
    .update({
      status: "archived",
      updated_by: profile.id,
      updated_at: new Date().toISOString(),
    })
    .eq("church_id", profile.church_id)
    .eq("id", id);

  await admin.from("admin_document_transmission_steps").insert({
    church_id: profile.church_id,
    transmission_id: id,
    from_profile_id: profile.id,
    status: "archived",
    note: "Transmission archivée.",
    created_by: profile.id,
  });

  revalidatePath("/inbox");
  revalidatePath("/administration/inbox");
  revalidatePath("/administration/transmissions");
  redirect(redirectTo);
}

"use client";

import { useEffect, useMemo, useRef, useState } from "react";
import { CheckCircle2, Loader2, QrCode, RotateCcw, XCircle } from "lucide-react";
import { Html5Qrcode } from "html5-qrcode";
import { createClient } from "@/lib/supabase/client";

type AttendanceQrScannerProps = {
  churchId: string;
  eventId: string;
  profileId: string;
  attendanceDate: string;
};

type ScanResult = {
  type: "success" | "warning" | "error";
  message: string;
  memberName?: string;
};

function getMemberName(member: any) {
  return [member.first_name, member.middle_name, member.last_name]
    .filter(Boolean)
    .join(" ");
}

function extractMemberId(decodedText: string, churchId: string) {
  try {
    const payload = JSON.parse(decodedText);

    if (payload.type && payload.type !== "mpangi_church_member") {
      return {
        memberId: null,
        error: "Ce QR Code n’est pas un QR Code membre Mpangi-church.",
      };
    }

    if (payload.church_id && payload.church_id !== churchId) {
      return {
        memberId: null,
        error: "Ce QR Code appartient à une autre église.",
      };
    }

    if (!payload.member_id) {
      return {
        memberId: null,
        error: "QR Code invalide : identifiant membre manquant.",
      };
    }

    return {
      memberId: String(payload.member_id),
      error: null,
    };
  } catch {
    return {
      memberId: decodedText.trim(),
      error: null,
    };
  }
}

export default function AttendanceQrScanner({
  churchId,
  eventId,
  profileId,
  attendanceDate,
}: AttendanceQrScannerProps) {
  const supabase = useMemo(() => createClient(), []);
  const scannerRef = useRef<Html5Qrcode | null>(null);
  const isProcessingRef = useRef(false);

  const [isStarting, setIsStarting] = useState(true);
  const [cameraError, setCameraError] = useState<string | null>(null);
  const [result, setResult] = useState<ScanResult | null>(null);
  const [scanCount, setScanCount] = useState(0);

  async function processMember(memberId: string) {
    const { data: member, error: memberError } = await supabase
      .from("members")
      .select("id, church_id, first_name, middle_name, last_name, status")
      .eq("id", memberId)
      .eq("church_id", churchId)
      .maybeSingle();

    if (memberError) {
      setResult({
        type: "error",
        message: memberError.message,
      });
      return;
    }

    if (!member) {
      setResult({
        type: "error",
        message: "Membre introuvable ou non autorisé pour cette église.",
      });
      return;
    }

    if (member.status && member.status !== "actif") {
      setResult({
        type: "warning",
        message: "Ce membre n’est pas actif.",
        memberName: getMemberName(member) || "Membre",
      });
      return;
    }

    const memberName = getMemberName(member) || "Membre";

    const { data: existingAttendance, error: existingError } = await supabase
      .from("attendances")
      .select("id")
      .eq("church_id", churchId)
      .eq("event_id", eventId)
      .eq("member_id", member.id)
      .maybeSingle();

    if (existingError) {
      setResult({
        type: "error",
        message: existingError.message,
      });
      return;
    }

    if (existingAttendance) {
      setResult({
        type: "warning",
        message: "Ce membre est déjà pointé pour cet événement.",
        memberName,
      });
      return;
    }

    const { error: insertError } = await supabase.from("attendances").insert({
      church_id: churchId,
      event_id: eventId,
      member_id: member.id,
      attendance_date: attendanceDate,
      check_in_time: new Date().toISOString(),
      status: "present",
      method: "qr",
      created_by: profileId,
    });

    if (insertError) {
      setResult({
        type: "error",
        message: insertError.message,
      });
      return;
    }

    setScanCount((current) => current + 1);

    setResult({
      type: "success",
      message: "Présence enregistrée avec succès.",
      memberName,
    });
  }

  async function handleDecodedText(decodedText: string) {
    if (isProcessingRef.current) return;

    isProcessingRef.current = true;

    const { memberId, error } = extractMemberId(decodedText, churchId);

    if (error || !memberId) {
      setResult({
        type: "error",
        message: error || "QR Code invalide.",
      });

      window.setTimeout(() => {
        isProcessingRef.current = false;
      }, 1800);

      return;
    }

    await processMember(memberId);

    window.setTimeout(() => {
      isProcessingRef.current = false;
    }, 1800);
  }

  useEffect(() => {
    const scanner = new Html5Qrcode("attendance-qr-reader");
    scannerRef.current = scanner;

    scanner
      .start(
        { facingMode: "environment" },
        {
          fps: 10,
          qrbox: {
            width: 260,
            height: 260,
          },
        },
        (decodedText) => {
          void handleDecodedText(decodedText);
        },
        () => {
          // On ignore les lectures partielles.
        }
      )
      .then(() => {
        setIsStarting(false);
      })
      .catch((error) => {
        setIsStarting(false);
        setCameraError(
          error instanceof Error
            ? error.message
            : "Impossible d’ouvrir la caméra."
        );
      });

    return () => {
      isProcessingRef.current = true;

      scanner
        .stop()
        .then(() => scanner.clear())
        .catch(() => {
          // Le scanner peut déjà être arrêté.
        });
    };

    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  function resetMessage() {
    setResult(null);
  }

  return (
    <section className="rounded-3xl border border-[#DCEAF5] bg-white p-6 shadow-sm">
      <div className="flex flex-col justify-between gap-4 md:flex-row md:items-center">
        <div className="flex items-center gap-3">
          <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-[#EAF3FA] text-[#03357A]">
            <QrCode className="h-6 w-6" />
          </div>

          <div>
            <h2 className="text-xl font-extrabold text-[#03357A]">
              Scanner QR Code
            </h2>

            <p className="mt-1 text-sm text-slate-500">
              Scannez le QR Code membre pour enregistrer sa présence.
            </p>
          </div>
        </div>

        <div className="rounded-2xl bg-[#EAF3FA] px-4 py-3 text-sm font-bold text-[#03357A]">
          Scans réussis : {scanCount}
        </div>
      </div>

      <div className="mt-6 grid gap-6 xl:grid-cols-[1fr_0.75fr]">
        <div className="overflow-hidden rounded-3xl border border-[#DCEAF5] bg-[#0F172A] p-4">
          {isStarting && (
            <div className="flex min-h-[360px] items-center justify-center text-white">
              <div className="flex items-center gap-3 text-sm font-bold">
                <Loader2 className="h-5 w-5 animate-spin" />
                Ouverture de la caméra...
              </div>
            </div>
          )}

          {cameraError && (
            <div className="flex min-h-[360px] items-center justify-center p-6 text-center">
              <div>
                <XCircle className="mx-auto h-12 w-12 text-red-400" />

                <h3 className="mt-4 text-lg font-extrabold text-white">
                  Caméra indisponible
                </h3>

                <p className="mt-2 text-sm leading-6 text-slate-300">
                  {cameraError}
                </p>

                <p className="mt-4 text-xs text-slate-400">
                  Vérifiez l’autorisation caméra du navigateur ou testez depuis
                  un téléphone.
                </p>
              </div>
            </div>
          )}

          <div
            id="attendance-qr-reader"
            className={cameraError ? "hidden" : "overflow-hidden rounded-2xl"}
          />
        </div>

        <div className="space-y-4">
          <div className="rounded-3xl border border-[#DCEAF5] bg-[#F8FBFD] p-5">
            <h3 className="font-extrabold text-[#03357A]">
              Résultat du dernier scan
            </h3>

            {!result && (
              <p className="mt-3 text-sm leading-6 text-slate-500">
                Aucun QR Code scanné pour le moment. Placez le QR Code du membre
                devant la caméra.
              </p>
            )}

            {result && (
              <div
                className={`mt-4 rounded-2xl p-4 ${
                  result.type === "success"
                    ? "bg-green-50 text-green-700"
                    : result.type === "warning"
                      ? "bg-orange-50 text-orange-700"
                      : "bg-red-50 text-red-700"
                }`}
              >
                <div className="flex items-start gap-3">
                  {result.type === "success" ? (
                    <CheckCircle2 className="mt-0.5 h-5 w-5" />
                  ) : (
                    <XCircle className="mt-0.5 h-5 w-5" />
                  )}

                  <div>
                    {result.memberName && (
                      <p className="font-extrabold">{result.memberName}</p>
                    )}

                    <p className="mt-1 text-sm font-semibold">
                      {result.message}
                    </p>
                  </div>
                </div>
              </div>
            )}

            {result && (
              <button
                type="button"
                onClick={resetMessage}
                className="mt-4 inline-flex items-center gap-2 rounded-2xl bg-white px-4 py-2 text-sm font-bold text-[#03357A] ring-1 ring-[#DCEAF5] hover:bg-[#EAF3FA]"
              >
                <RotateCcw className="h-4 w-4" />
                Effacer le message
              </button>
            )}
          </div>

          <div className="rounded-3xl border border-[#DCEAF5] bg-white p-5">
            <h3 className="font-extrabold text-[#03357A]">
              Contrôles de sécurité
            </h3>

            <ul className="mt-3 space-y-2 text-sm leading-6 text-slate-500">
              <li>Le membre doit appartenir à votre église.</li>
              <li>Le membre doit avoir le statut actif.</li>
              <li>Un membre ne peut être pointé qu’une seule fois.</li>
              <li>Les QR Codes d’autres églises sont refusés.</li>
            </ul>
          </div>
        </div>
      </div>
    </section>
  );
}

"use client";

import { ChangeEvent, useEffect, useRef, useState } from "react";
import { useRouter } from "next/navigation";
import {
  AlertTriangle,
  Camera,
  CheckCircle2,
  Image as ImageIcon,
  Keyboard,
  Loader2,
  ScanLine,
  XCircle,
} from "lucide-react";

type EventQrScannerClientProps = {
  eventId: string;
};

type ScanResult = {
  status: "checked_in" | "already_checked_in" | "error";
  message: string;
  memberName?: string;
};

function getShortQrValue(value: string) {
  if (!value) return "";
  if (value.length <= 90) return value;
  return `${value.slice(0, 70)}...${value.slice(-12)}`;
}

export default function EventQrScannerClient({
  eventId,
}: EventQrScannerClientProps) {
  const router = useRouter();

  const scannerRef = useRef<any>(null);
  const isSubmittingRef = useRef(false);
  const lastCameraErrorAtRef = useRef(0);

  const [isScannerReady, setIsScannerReady] = useState(false);
  const [isStarting, setIsStarting] = useState(false);
  const [isScanningFile, setIsScanningFile] = useState(false);
  const [manualQrValue, setManualQrValue] = useState("");
  const [lastRawScan, setLastRawScan] = useState("");
  const [cameraStatus, setCameraStatus] = useState(
    "Caméra non démarrée."
  );
  const [result, setResult] = useState<ScanResult | null>(null);

  async function playSuccessSound() {
    try {
      const AudioContextClass =
        window.AudioContext || (window as any).webkitAudioContext;

      if (!AudioContextClass) return;

      const audioContext = new AudioContextClass();
      const oscillator = audioContext.createOscillator();
      const gain = audioContext.createGain();

      oscillator.type = "sine";
      oscillator.frequency.value = 880;
      gain.gain.value = 0.08;

      oscillator.connect(gain);
      gain.connect(audioContext.destination);

      oscillator.start();
      oscillator.stop(audioContext.currentTime + 0.12);
    } catch {
      // Le son est optionnel.
    }
  }

  async function submitQr(qrValue: string) {
    const cleanQrValue = qrValue.trim();

    if (!cleanQrValue || isSubmittingRef.current) return;

    isSubmittingRef.current = true;
    setLastRawScan(cleanQrValue);
    setResult(null);
    setCameraStatus("QR détecté. Enregistrement de la présence...");

    try {
      await playSuccessSound();

      const response = await fetch("/api/attendance/scan", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          eventId,
          qrValue: cleanQrValue,
        }),
      });

      const payload = await response.json();

      if (!response.ok) {
        setResult({
          status: "error",
          message: payload.error || "Impossible d’enregistrer la présence.",
        });
        setCameraStatus("QR lu, mais la présence n’a pas été enregistrée.");
        return;
      }

      setResult({
        status: payload.status,
        message: payload.message,
        memberName: payload.member?.name,
      });

      setCameraStatus("Présence traitée. Vous pouvez scanner le suivant.");
      router.refresh();
    } catch {
      setResult({
        status: "error",
        message: "Erreur pendant la lecture du QR Code.",
      });
      setCameraStatus("Erreur pendant le traitement du QR Code.");
    } finally {
      setTimeout(() => {
        isSubmittingRef.current = false;
      }, 1400);
    }
  }

  async function getScannerInstance() {
    const html5QrCodeModule = await import("html5-qrcode");
    const Html5Qrcode = (html5QrCodeModule as any).Html5Qrcode;
    const Html5QrcodeSupportedFormats = (html5QrCodeModule as any)
      .Html5QrcodeSupportedFormats;

    if (scannerRef.current) {
      return scannerRef.current;
    }

    const scanner = new Html5Qrcode("event-qr-reader", {
      verbose: false,
      formatsToSupport: [Html5QrcodeSupportedFormats.QR_CODE],
    });

    scannerRef.current = scanner;

    return scanner;
  }

  async function startScanner() {
    setIsStarting(true);
    setResult(null);
    setCameraStatus("Initialisation de la caméra...");

    try {
      const html5QrCodeModule = await import("html5-qrcode");
      const Html5Qrcode = (html5QrCodeModule as any).Html5Qrcode;
      const scanner = await getScannerInstance();

      if (isScannerReady) {
        setIsStarting(false);
        return;
      }

      const cameras = await Html5Qrcode.getCameras();

      if (!cameras || cameras.length === 0) {
        setResult({
          status: "error",
          message:
            "Aucune caméra détectée. Vérifiez les autorisations du navigateur.",
        });
        setCameraStatus("Aucune caméra détectée.");
        return;
      }

      const backCamera =
        cameras.find((camera: any) =>
          /back|rear|environment|arrière|arri[eè]re/i.test(camera.label || "")
        ) || cameras[cameras.length - 1];

      const cameraConfig = backCamera?.id || { facingMode: "environment" };

      await scanner.start(
        cameraConfig,
        {
          fps: 8,
          qrbox: (viewfinderWidth: number, viewfinderHeight: number) => {
            const minEdge = Math.min(viewfinderWidth, viewfinderHeight);
            const qrboxSize = Math.max(220, Math.floor(minEdge * 0.72));

            return {
              width: qrboxSize,
              height: qrboxSize,
            };
          },
          aspectRatio: 1.333334,
          disableFlip: false,
        },
        async (decodedText: string) => {
          await submitQr(decodedText);
        },
        (errorMessage: string) => {
          const now = Date.now();

          if (now - lastCameraErrorAtRef.current > 2500) {
            lastCameraErrorAtRef.current = now;
            setCameraStatus(
              "Recherche du QR Code... rapprochez le code, augmentez la lumière et gardez l’image stable."
            );
          }
        }
      );

      setIsScannerReady(true);
      setCameraStatus(
        "Caméra active. Placez le QR Code personnel du membre dans le cadre."
      );
    } catch (error) {
      setResult({
        status: "error",
        message:
          error instanceof Error
            ? error.message
            : "Impossible d’ouvrir la caméra. Vérifiez l’autorisation caméra ou utilisez la saisie manuelle.",
      });
      setCameraStatus("Caméra non disponible.");
    } finally {
      setIsStarting(false);
    }
  }

  async function stopScanner() {
    if (!scannerRef.current) return;

    try {
      if (isScannerReady) {
        await scannerRef.current.stop();
      }

      scannerRef.current.clear();
    } catch {
      // Rien à faire.
    }

    scannerRef.current = null;
    setIsScannerReady(false);
    setCameraStatus("Caméra arrêtée.");
  }

  async function handleFileScan(event: ChangeEvent<HTMLInputElement>) {
    const file = event.target.files?.[0];

    if (!file) return;

    setIsScanningFile(true);
    setResult(null);
    setCameraStatus("Lecture du QR Code depuis l’image...");

    try {
      const scanner = await getScannerInstance();
      const decodedText = await scanner.scanFile(file, true);

      await submitQr(decodedText);
    } catch {
      setResult({
        status: "error",
        message:
          "Impossible de lire le QR Code dans cette image. Essayez une image plus nette ou utilisez la saisie manuelle.",
      });
      setCameraStatus("Lecture image échouée.");
    } finally {
      setIsScanningFile(false);
      event.target.value = "";
    }
  }

  useEffect(() => {
    return () => {
      if (scannerRef.current) {
        scannerRef.current.stop().catch(() => {});
      }
    };
  }, []);

  function handleManualSubmit() {
    if (!manualQrValue.trim()) return;

    void submitQr(manualQrValue);
    setManualQrValue("");
  }

  return (
    <div className="space-y-5">
      <div className="rounded-3xl border border-[#DCEAF5] bg-white p-5 shadow-sm">
        <div className="flex flex-col justify-between gap-4 lg:flex-row lg:items-center">
          <div>
            <h2 className="text-xl font-extrabold text-[#03357A]">
              Scanner le QR Code du membre
            </h2>

            <p className="mt-1 text-sm leading-6 text-slate-500">
              Autorisez la caméra, puis placez le QR Code personnel du membre
              dans le cadre. Utilisez une bonne lumière et évitez les reflets.
            </p>
          </div>

          <div className="flex flex-wrap gap-3">
            <button
              type="button"
              onClick={() => void startScanner()}
              disabled={isStarting || isScannerReady}
              className="inline-flex items-center justify-center gap-2 rounded-2xl bg-[#03357A] px-5 py-3 text-sm font-extrabold text-white shadow-lg shadow-blue-900/20 disabled:opacity-60"
            >
              {isStarting ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <Camera className="h-4 w-4" />
              )}
              Démarrer caméra
            </button>

            {isScannerReady && (
              <button
                type="button"
                onClick={() => void stopScanner()}
                className="inline-flex items-center justify-center gap-2 rounded-2xl bg-red-50 px-5 py-3 text-sm font-extrabold text-red-700"
              >
                Arrêter
              </button>
            )}

            <label className="inline-flex cursor-pointer items-center justify-center gap-2 rounded-2xl bg-[#EAF3FA] px-5 py-3 text-sm font-extrabold text-[#03357A] hover:bg-[#DCEAF5]">
              {isScanningFile ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <ImageIcon className="h-4 w-4" />
              )}
              Lire une image QR
              <input
                type="file"
                accept="image/png,image/jpeg,image/webp"
                onChange={handleFileScan}
                className="hidden"
              />
            </label>
          </div>
        </div>

        <div className="mt-5 overflow-hidden rounded-3xl border border-[#DCEAF5] bg-[#F8FBFD] p-3">
          <div
            id="event-qr-reader"
            className="mx-auto min-h-[340px] max-w-xl overflow-hidden rounded-2xl bg-white"
          />
        </div>

        <div className="mt-4 rounded-2xl bg-[#F8FBFD] p-4 text-sm font-semibold text-slate-600">
          <div className="flex items-start gap-2">
            <ScanLine className="mt-0.5 h-4 w-4 shrink-0 text-[#03357A]" />
            <span>{cameraStatus}</span>
          </div>

          {lastRawScan && (
            <p className="mt-2 break-words text-xs text-slate-500">
              Dernier QR détecté : {getShortQrValue(lastRawScan)}
            </p>
          )}
        </div>
      </div>

      {result && (
        <div
          className={`flex items-start gap-3 rounded-3xl border p-5 text-sm font-bold ${
            result.status === "checked_in"
              ? "border-green-200 bg-green-50 text-green-700"
              : result.status === "already_checked_in"
                ? "border-orange-200 bg-orange-50 text-orange-700"
                : "border-red-200 bg-red-50 text-red-700"
          }`}
        >
          {result.status === "checked_in" ? (
            <CheckCircle2 className="mt-0.5 h-5 w-5" />
          ) : result.status === "already_checked_in" ? (
            <AlertTriangle className="mt-0.5 h-5 w-5" />
          ) : (
            <XCircle className="mt-0.5 h-5 w-5" />
          )}

          <span>{result.message}</span>
        </div>
      )}

      <div className="rounded-3xl border border-[#DCEAF5] bg-white p-5 shadow-sm">
        <div className="flex items-center gap-3">
          <div className="flex h-11 w-11 items-center justify-center rounded-2xl bg-[#EAF3FA] text-[#03357A]">
            <Keyboard className="h-5 w-5" />
          </div>

          <div>
            <h2 className="font-extrabold text-[#03357A]">
              Saisie manuelle de secours
            </h2>

            <p className="text-sm text-slate-500">
              À utiliser si la caméra ou la lecture automatique ne fonctionne
              pas. Collez le lien complet de la carte QR du membre.
            </p>
          </div>
        </div>

        <div className="mt-4 flex flex-col gap-3 md:flex-row">
          <input
            value={manualQrValue}
            onChange={(event) => setManualQrValue(event.target.value)}
            placeholder="Coller ici le lien ou token QR du membre"
            className="min-h-12 flex-1 rounded-2xl border border-[#DCEAF5] bg-white px-4 py-3 text-sm outline-none focus:border-[#03357A] focus:ring-4 focus:ring-[#03357A]/10"
          />

          <button
            type="button"
            onClick={handleManualSubmit}
            className="rounded-2xl bg-[#03357A] px-5 py-3 text-sm font-extrabold text-white"
          >
            Enregistrer
          </button>
        </div>
      </div>
    </div>
  );
}

