"use client";

import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import type { ReactNode } from "react";
import { useEffect, useState } from "react";
import {
  AppWindow,
  Boxes,
  Building2,
  LayoutDashboard,
  LogOut,
  MoreHorizontal,
  Rocket,
  Settings,
  ShieldCheck,
  UserRound,
  UsersRound,
  X,
} from "lucide-react";
import SuperAdminTopBar from "@/components/layout/SuperAdminTopBar";

const desktopItems = [
  {
    label: "Dashboard",
    href: "/super-admin/dashboard",
    icon: LayoutDashboard,
  },
  {
    label: "Églises",
    href: "/super-admin/churches",
    icon: Building2,
  },
  {
    label: "Applications",
    href: "/super-admin/apps",
    icon: AppWindow,
  },
  {
    label: "Utilisateurs",
    href: "/super-admin/users",
    icon: UsersRound,
  },
  {
    label: "Gestion modules",
    href: "/super-admin/modules",
    icon: Boxes,
  },
  {
    label: "Onboarding",
    href: "/super-admin/onboarding",
    icon: Rocket,
  },
  {
    label: "Paramètres",
    href: "/super-admin/settings",
    icon: Settings,
  },
];

const mobileMainItems = desktopItems.slice(0, 4);

function isActive(pathname: string, href: string) {
  return pathname === href || pathname.startsWith(`${href}/`);
}

function DesktopSidebar() {
  const pathname = usePathname();

  return (
    <aside
      data-mpangi-superadmin-sidebar
      className="flex h-full min-h-0 flex-col border-r border-[#DCEAF5] bg-white"
    >
      <div className="shrink-0 p-4">
        <div className="rounded-[2rem] bg-[#03357A] p-5 text-white">
          <div className="flex h-14 w-14 items-center justify-center rounded-2xl bg-white/15">
            <ShieldCheck className="h-7 w-7" />
          </div>

          <p className="mt-5 text-xs font-black uppercase tracking-[0.35em]">
            Mpangi-church
          </p>
          <h2 className="mt-4 text-2xl font-black">Super admin</h2>
          <p className="mt-1 text-sm font-bold text-blue-100">
            Administration globale
          </p>
        </div>
      </div>

      <nav className="min-h-0 flex-1 space-y-2 overflow-y-auto px-4 pb-5">
        {desktopItems.map((item) => {
          const Icon = item.icon;
          const active = isActive(pathname, item.href);

          return (
            <Link
              key={item.href}
              href={item.href}
              className={`flex min-h-12 w-full items-center gap-3 rounded-2xl px-4 py-3 text-sm font-black transition ${
                active
                  ? "bg-[#03357A] text-white shadow-sm"
                  : "text-slate-600 hover:bg-[#EAF3FA] hover:text-[#03357A]"
              }`}
            >
              <Icon className="h-5 w-5 shrink-0" />
              <span className="truncate">{item.label}</span>
            </Link>
          );
        })}
      </nav>
    </aside>
  );
}

export default function SuperAdminShell({
  children,
}: {
  children: ReactNode;
}) {
  const pathname = usePathname();
  const router = useRouter();
  const [moreOpen, setMoreOpen] = useState(false);
  const [logoutLoading, setLogoutLoading] = useState(false);

  useEffect(() => {
    setMoreOpen(false);
  }, [pathname]);

  useEffect(() => {
    if (!moreOpen) return;

    const previous = document.body.style.overflow;
    document.body.style.overflow = "hidden";

    return () => {
      document.body.style.overflow = previous;
    };
  }, [moreOpen]);

  async function handleLogout() {
    try {
      setLogoutLoading(true);
      await fetch("/logout", {
        method: "POST",
        cache: "no-store",
      });
      router.replace("/login?logout=1");
      router.refresh();
    } finally {
      setLogoutLoading(false);
    }
  }

  return (
    <div
      data-mpangi-superadmin-shell
      className="min-h-dvh overflow-x-hidden bg-[#F5F9FC]"
    >
      <div className="fixed inset-y-0 left-0 z-40 hidden w-[292px] lg:block">
        <DesktopSidebar />
      </div>

      <div className="min-w-0 lg:pl-[292px]">
        <SuperAdminTopBar
          onOpenMobileMenu={() => setMoreOpen(true)}
        />

        <main className="mx-auto w-full max-w-[1500px] px-3 py-5 pb-28 sm:px-6 sm:py-6 lg:px-8 lg:pb-8">
          {children}
        </main>
      </div>

      <nav
        data-mpangi-superadmin-mobile-nav
        aria-label="Navigation Super Admin mobile"
        className="fixed inset-x-0 bottom-0 z-[70] border-t border-[#DCEAF5] bg-white/95 px-2 pb-[max(env(safe-area-inset-bottom),0.5rem)] pt-2 shadow-[0_-10px_30px_rgba(15,23,42,0.10)] backdrop-blur-xl lg:hidden"
      >
        <div className="mx-auto grid max-w-xl grid-cols-5 gap-1">
          {mobileMainItems.map((item) => {
            const Icon = item.icon;
            const active = isActive(pathname, item.href);

            return (
              <Link
                key={item.href}
                href={item.href}
                className={`flex min-h-14 min-w-0 flex-col items-center justify-center gap-1 rounded-2xl px-1 text-[10px] font-black ${
                  active
                    ? "bg-[#03357A] text-white"
                    : "text-slate-500"
                }`}
              >
                <Icon className="h-5 w-5 shrink-0" />
                <span className="max-w-full truncate">
                  {item.label === "Applications"
                    ? "Apps"
                    : item.label}
                </span>
              </Link>
            );
          })}

          <button
            type="button"
            onClick={() => setMoreOpen(true)}
            className="flex min-h-14 min-w-0 flex-col items-center justify-center gap-1 rounded-2xl px-1 text-[10px] font-black text-slate-500"
          >
            <MoreHorizontal className="h-5 w-5" />
            Plus
          </button>
        </div>
      </nav>

      {moreOpen && (
        <div className="fixed inset-0 z-[100] lg:hidden">
          <button
            type="button"
            aria-label="Fermer le menu"
            onClick={() => setMoreOpen(false)}
            className="absolute inset-0 bg-slate-950/50"
          />

          <section
            data-mpangi-superadmin-more-sheet
            className="absolute inset-x-0 bottom-0 max-h-[82dvh] overflow-y-auto rounded-t-[2rem] bg-white p-4 pb-[max(env(safe-area-inset-bottom),1rem)] shadow-2xl"
          >
            <div className="flex items-center justify-between gap-3">
              <div>
                <p className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">
                  Super Admin
                </p>
                <h2 className="text-xl font-black text-[#03357A]">
                  Plus d’options
                </h2>
              </div>

              <button
                type="button"
                onClick={() => setMoreOpen(false)}
                className="flex h-11 w-11 items-center justify-center rounded-2xl bg-[#EAF3FA] text-[#03357A]"
              >
                <X className="h-5 w-5" />
              </button>
            </div>

            <div className="mt-5 grid grid-cols-2 gap-3">
              {desktopItems.slice(4).map((item) => {
                const Icon = item.icon;

                return (
                  <Link
                    key={item.href}
                    href={item.href}
                    className="flex min-h-24 flex-col justify-between rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-[#03357A]"
                  >
                    <Icon className="h-6 w-6" />
                    <span className="mt-4 break-words text-sm font-black">
                      {item.label}
                    </span>
                  </Link>
                );
              })}

              <Link
                href="/super-admin/profile"
                className="flex min-h-24 flex-col justify-between rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4 text-[#03357A]"
              >
                <UserRound className="h-6 w-6" />
                <span className="mt-4 text-sm font-black">Profil</span>
              </Link>
            </div>

            <button
              type="button"
              onClick={handleLogout}
              disabled={logoutLoading}
              className="mt-4 flex min-h-12 w-full items-center justify-center gap-2 rounded-2xl bg-red-50 px-4 text-sm font-black text-red-700 disabled:opacity-60"
            >
              <LogOut className="h-5 w-5" />
              {logoutLoading ? "Déconnexion..." : "Déconnexion"}
            </button>
          </section>
        </div>
      )}
    </div>
  );
}

"use client";

import Link from "next/link";
import { useEffect, useMemo, useState } from "react";
import type { LucideIcon } from "lucide-react";
import {
  Bell,
  BookOpen,
  Boxes,
  BriefcaseBusiness,
  Building2,
  CalendarDays,
  ChartNoAxesCombined,
  CircleDollarSign,
  ClipboardCheck,
  FileText,
  Grid3X3,
  HandCoins,
  HeartHandshake,
  Landmark,
  LayoutDashboard,
  Network,
  PackageSearch,
  QrCode,
  Settings,
  ShieldCheck,
  UsersRound,
  Wallet,
  Wrench,
} from "lucide-react";

type NavigationItem = {
  code: string;
  label: string;
  href: string;
  category?: string;
};

type Payload = {
  data?: {
    items?: NavigationItem[];
  };
};

const ICONS: Record<string, LucideIcon> = {
  role_dashboard: LayoutDashboard,
  dashboard: LayoutDashboard,
  my_work: BriefcaseBusiness,
  members: UsersRound,
  attendance: QrCode,
  souls: HeartHandshake,
  departments: Network,
  events: CalendarDays,
  public_requests: ClipboardCheck,
  teachings: BookOpen,
  notifications: Bell,
  correspondence: FileText,
  inbox: FileText,
  transmissions: FileText,
  tasks: ClipboardCheck,
  minutes: FileText,
  finance_dashboard: Wallet,
  offerings: HandCoins,
  expenses: CircleDollarSign,
  budgets: ChartNoAxesCombined,
  finance_reports: Landmark,
  donations: HandCoins,
  patrimony: Building2,
  assets: PackageSearch,
  maintenance: Wrench,
  movements: Boxes,
  extensions: Network,
  users: UsersRound,
  security: ShieldCheck,
  settings: Settings,
};

const ACCENTS = [
  "from-blue-700 to-blue-500",
  "from-violet-700 to-violet-500",
  "from-emerald-700 to-emerald-500",
  "from-cyan-700 to-cyan-500",
  "from-amber-700 to-orange-500",
  "from-rose-700 to-pink-500",
];

export default function ModuleLauncherClient() {
  const [items, setItems] = useState<NavigationItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [query, setQuery] = useState("");

  useEffect(() => {
    let mounted = true;

    fetch("/api/security/navigation", {
      cache: "no-store",
      credentials: "include",
    })
      .then(async (response) => {
        const payload = (await response.json()) as Payload & {
          error?: string;
        };

        if (!response.ok) {
          throw new Error(
            payload.error || "Navigation indisponible."
          );
        }

        if (mounted) {
          setItems(payload.data?.items || []);
        }
      })
      .catch((loadError: any) => {
        if (mounted) {
          setError(
            loadError?.message ||
              "Impossible de charger les modules."
          );
        }
      })
      .finally(() => {
        if (mounted) setLoading(false);
      });

    return () => {
      mounted = false;
    };
  }, []);

  const filtered = useMemo(() => {
    const term = query.trim().toLowerCase();

    if (!term) return items;

    return items.filter((item) =>
      `${item.label} ${item.code} ${item.category || ""}`
        .toLowerCase()
        .includes(term)
    );
  }, [items, query]);

  return (
    <section className="space-y-5">
      <div className="rounded-[1.75rem] bg-gradient-to-br from-[#03357A] via-[#2563EB] to-[#8B5CF6] p-5 text-white sm:p-7">
        <Grid3X3 className="h-8 w-8" />
        <p className="mt-4 text-xs font-black uppercase tracking-[0.22em] text-blue-100">
          Lanceur d’applications
        </p>
        <h1 className="mt-2 text-3xl font-black sm:text-4xl">
          Mes modules
        </h1>
        <p className="mt-3 max-w-3xl text-sm leading-7 text-blue-50">
          Ouvrez rapidement les fonctions autorisées pour votre rôle.
        </p>
      </div>

      <div className="rounded-2xl border border-[#DCEAF5] bg-white p-3 shadow-sm">
        <input
          type="search"
          value={query}
          onChange={(event) => setQuery(event.target.value)}
          placeholder="Rechercher un module..."
          className="min-h-12 w-full rounded-xl border border-[#DCEAF5] bg-[#F8FBFD] px-4 text-sm font-semibold outline-none focus:border-[#03357A]"
        />
      </div>

      {error && (
        <div className="rounded-2xl border border-red-200 bg-red-50 p-4 text-sm font-bold text-red-700">
          {error}
        </div>
      )}

      {loading ? (
        <div
          data-mpangi-module-grid
          className="grid grid-cols-3 gap-3 sm:grid-cols-4 lg:grid-cols-6 xl:grid-cols-7"
        >
          {Array.from({ length: 12 }).map((_, index) => (
            <div
              key={index}
              className="aspect-square animate-pulse rounded-3xl bg-white shadow-sm ring-1 ring-[#DCEAF5]"
            />
          ))}
        </div>
      ) : (
        <div
          data-mpangi-module-grid
          className="grid grid-cols-3 gap-3 sm:grid-cols-4 lg:grid-cols-6 xl:grid-cols-7"
        >
          {filtered.map((item, index) => {
            const Icon = ICONS[item.code] || Grid3X3;
            const accent = ACCENTS[index % ACCENTS.length];

            return (
              <Link
                key={`${item.code}:${item.href}`}
                href={item.href}
                className="group flex min-w-0 flex-col items-center rounded-3xl bg-white p-2.5 text-center shadow-sm ring-1 ring-[#DCEAF5] transition hover:-translate-y-1 hover:shadow-lg sm:p-3"
              >
                <span
                  className={`flex aspect-square w-full max-w-[82px] items-center justify-center rounded-[1.35rem] bg-gradient-to-br ${accent} text-white shadow-md`}
                >
                  <Icon className="h-7 w-7 sm:h-8 sm:w-8" />
                </span>

                <span className="mt-2 line-clamp-2 min-h-[2.5rem] w-full break-words text-[11px] font-black leading-5 text-[#03357A] sm:text-xs">
                  {item.label}
                </span>
              </Link>
            );
          })}
        </div>
      )}

      {!loading && filtered.length === 0 && (
        <div className="rounded-3xl border border-dashed border-[#DCEAF5] bg-white p-8 text-center">
          <p className="font-black text-[#03357A]">
            Aucun module trouvé
          </p>
          <p className="mt-2 text-sm text-slate-500">
            Vérifiez les permissions du rôle ou modifiez la recherche.
          </p>
        </div>
      )}
    </section>
  );
}

import { redirect } from "next/navigation";
import {
  AlertTriangle,
  ArrowRight,
  CheckCircle2,
  Clock3,
  Lock,
} from "lucide-react";
import AppShell from "@/components/layout/AppShell";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

type ModulePlaceholderPageProps = {
  moduleCode: string;
  title: string;
  categoryLabel: string;
  description: string;
  features: string[];
  nextSteps: string[];
};

async function getCurrentProfile() {
  const supabase = await createClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) redirect("/login");

  const { data: profile } = await supabase
    .from("profiles")
    .select("id, role, church_id, status")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) redirect("/login");
  if (profile.status && profile.status !== "active") redirect("/login");
  if (profile.role === "super_admin") redirect("/super-admin/dashboard");
  if (!profile.church_id) redirect("/login");

  return profile;
}

export default async function ModulePlaceholderPage({
  moduleCode,
  title,
  categoryLabel,
  description,
  features,
  nextSteps,
}: ModulePlaceholderPageProps) {
  const profile = await getCurrentProfile();
  const admin = createAdminClient();

  const [{ data: appModule }, { data: churchModule }, { data: permission }] =
    await Promise.all([
      admin
        .from("app_modules")
        .select("code, name, category, description")
        .eq("code", moduleCode)
        .maybeSingle(),

      admin
        .from("church_modules")
        .select("module_code, enabled")
        .eq("church_id", profile.church_id)
        .eq("module_code", moduleCode)
        .maybeSingle(),

      admin
        .from("church_role_module_permissions")
        .select("can_view, can_create, can_update, can_approve, can_export")
        .eq("church_id", profile.church_id)
        .eq("module_code", moduleCode)
        .eq("role", profile.role)
        .maybeSingle(),
    ]);

  const moduleExists = Boolean(appModule);
  const moduleEnabled = Boolean(churchModule?.enabled);
  const canView = Boolean(permission?.can_view);

  if (!moduleExists || !moduleEnabled || !canView) {
    return (
      <AppShell>
        <div className="space-y-6">
          <section className="rounded-3xl border border-orange-200 bg-orange-50 p-6 text-orange-900 shadow-sm">
            <div className="flex flex-col gap-4 md:flex-row md:items-start">
              <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-2xl bg-white text-orange-700">
                <Lock className="h-6 w-6" />
              </div>

              <div>
                <p className="text-sm font-black uppercase tracking-[0.2em] text-orange-700">
                  Accès module
                </p>

                <h1 className="mt-2 text-2xl font-black">
                  Module non disponible
                </h1>

                <p className="mt-2 max-w-3xl text-sm leading-7">
                  Ce module n’est pas activé pour votre église ou votre rôle ne
                  dispose pas encore des droits nécessaires. Le super admin peut
                  l’activer depuis la page Modules par église.
                </p>
              </div>
            </div>
          </section>
        </div>
      </AppShell>
    );
  }

  return (
    <AppShell>
      <div className="space-y-6">
        <section className="rounded-3xl bg-gradient-to-br from-[#03357A] via-[#2563EB] to-[#8B5CF6] p-6 text-white shadow-lg shadow-blue-900/20">
          <div className="flex flex-col justify-between gap-5 lg:flex-row lg:items-center">
            <div>
              <p className="text-sm font-semibold uppercase tracking-[0.25em] text-blue-100">
                {categoryLabel}
              </p>

              <h1 className="mt-3 text-3xl font-extrabold">{title}</h1>

              <p className="mt-2 max-w-3xl text-sm leading-7 text-blue-50">
                {description}
              </p>
            </div>

            <div className="rounded-2xl bg-white/15 px-5 py-4 text-center ring-1 ring-white/20">
              <p className="text-3xl font-black">Phase</p>
              <p className="text-xs font-bold uppercase tracking-wide text-blue-100">
                préparation
              </p>
            </div>
          </div>
        </section>

        <section className="grid gap-4 md:grid-cols-3">
          <StatusCard
            title="Module activé"
            description="Ce module est actif pour cette église."
            icon={CheckCircle2}
          />
          <StatusCard
            title="Accès autorisé"
            description="Votre rôle peut consulter cette page."
            icon={Lock}
          />
          <StatusCard
            title="En construction"
            description="Les écrans métier seront ajoutés progressivement."
            icon={Clock3}
          />
        </section>

        <section className="grid gap-5 xl:grid-cols-[1.2fr_0.8fr]">
          <div className="rounded-3xl border border-[#DCEAF5] bg-white p-6 shadow-sm">
            <div className="flex items-center gap-3">
              <div className="flex h-11 w-11 items-center justify-center rounded-2xl bg-[#EAF3FA] text-[#03357A]">
                <ArrowRight className="h-5 w-5" />
              </div>

              <div>
                <h2 className="text-xl font-extrabold text-[#03357A]">
                  Fonctionnalités prévues
                </h2>
                <p className="text-sm text-slate-500">
                  Ce que ce module va gérer dans Mpangi-church.
                </p>
              </div>
            </div>

            <div className="mt-6 grid gap-3 md:grid-cols-2">
              {features.map((feature) => (
                <div
                  key={feature}
                  className="rounded-2xl border border-[#DCEAF5] bg-[#F8FBFD] p-4"
                >
                  <div className="flex gap-3">
                    <CheckCircle2 className="mt-0.5 h-5 w-5 shrink-0 text-green-600" />
                    <p className="text-sm font-semibold leading-6 text-slate-700">
                      {feature}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="rounded-3xl border border-[#DCEAF5] bg-white p-6 shadow-sm">
            <div className="flex items-center gap-3">
              <div className="flex h-11 w-11 items-center justify-center rounded-2xl bg-[#F1E8FF] text-[#8B5CF6]">
