    useState(false);

  const [permission, setPermission] =
    useState<NotificationPermission>("default");

  const [isSubscribed, setIsSubscribed] =
    useState(false);

  const [isLoading, setIsLoading] =
    useState(false);

  const [message, setMessage] =
    useState("");

  const [browserLabel, setBrowserLabel] =
    useState("votre navigateur");

  const refreshPermissionState =
    useCallback(async () => {
      const supported =
        typeof window !== "undefined" &&
        "Notification" in window &&
        "serviceWorker" in navigator &&
        "PushManager" in window;

      setIsSupported(supported);
      setBrowserLabel(getBrowserLabel());

      if (!supported) {
        setIsSubscribed(false);
        return;
      }

      const nextPermission =
        Notification.permission;

      setPermission(nextPermission);

      try {
        const registration =
          await navigator.serviceWorker.getRegistration(
            "/"
          );

        const subscription =
          await registration?.pushManager.getSubscription();

        setIsSubscribed(
          Boolean(
            subscription &&
              nextPermission === "granted"
          )
        );
      } catch {
        setIsSubscribed(false);
      }
    }, []);

  useEffect(() => {
    refreshPermissionState();

    function handleVisibilityChange() {
      if (
        document.visibilityState === "visible"
      ) {
        refreshPermissionState();
      }
    }

    window.addEventListener(
      "focus",
      refreshPermissionState
    );

    document.addEventListener(
      "visibilitychange",
      handleVisibilityChange
    );

    return () => {
      window.removeEventListener(
        "focus",
        refreshPermissionState
      );

      document.removeEventListener(
        "visibilitychange",
        handleVisibilityChange
      );
    };
  }, [refreshPermissionState]);

  async function handleSubscribe() {
    setMessage("");

    if (!isSupported) {
      setMessage(
        "Ce navigateur ne supporte pas les notifications Push."
      );
      return;
    }

    if (Notification.permission === "denied") {
      setPermission("denied");
      setMessage(
        `L’autorisation est bloquée dans ${browserLabel}. Modifiez les permissions du site, puis revenez sur cette page.`
      );
      return;
    }

    const publicKey =
      process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY;

    if (!publicKey) {
      setMessage(
        "La clé publique VAPID n’est pas configurée dans Vercel."
      );
      return;
