  source: "publication" | "event";
  title: string;
  description: string | null;
  category: string;
  imageUrl: string | null;
  date: string | null;
  featured: boolean;
};

const PUBLICATION_CATEGORIES = new Set([
  "announcement",
  "annonce",
  "news",
  "actuality",
  "actualite",
  "actualité",
  "event",
  "evenement",
  "événement",
  "programme",
  "program",
  "communication",
]);

function stringValue(value: unknown) {
  if (value === null || value === undefined) {
    return "";
  }

  return String(value).trim();
}

function booleanValue(value: unknown) {
  return (
    value === true ||
    value === "true" ||
    value === 1 ||
    value === "1"
  );
}

function firstValue(
  row: Record<string, any>,
  keys: string[]
) {
  for (const key of keys) {
    const value = stringValue(row[key]);

    if (value) {
      return value;
    }
  }

  return "";
}

function normalizedCategory(
  row: Record<string, any>
) {
  /*
   * Important :
   * category/type sont prioritaires sur publication_type.
   * Certaines anciennes lignes ont publication_type="teaching"
   * par défaut alors que category="announcement".
   */
  return firstValue(row, [
    "category",
    "type",
    "publication_type",
  ]).toLowerCase();
}

function isPublishedPublication(
  row: Record<string, any>
) {
  const status =
    stringValue(row.status).toLowerCase();

  return (
    booleanValue(row.is_published) ||
    booleanValue(row.is_public) ||
    status === "published" ||
    status === "active"
  );
}

function isVisibleEvent(
  row: Record<string, any>
) {
  const status =
    stringValue(row.status).toLowerCase();

  const hiddenStatuses = new Set([
    "draft",
    "archived",
    "cancelled",
    "canceled",
    "inactive",
    "deleted",
  ]);

  const publicVisible =
    row.is_public === undefined ||
    row.is_public === null ||
    booleanValue(row.is_public);

  return (
    publicVisible &&
    !hiddenStatuses.has(status)
  );
}

function isFeatured(
  row: Record<string, any>
) {
  return booleanValue(
    row.is_featured ??
      row.featured ??
      row.show_on_homepage ??
      row.show_on_public_page
  );
}

function dateValue(value: string | null) {
  if (!value) return 0;

  const timestamp =
    new Date(value).getTime();

  return Number.isFinite(timestamp)
    ? timestamp
    : 0;
}

function formatDate(value: string | null) {
  if (!value) return null;

  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return null;
  }

  return new Intl.DateTimeFormat(
    "fr-FR",
    {
      day: "2-digit",
      month: "long",
      year: "numeric",
    }
  ).format(date);
}

function categoryLabel(
  category: string,
  source: PublicUpdate["source"]
) {
  const labels: Record<string, string> = {
    announcement: "Annonce",
    annonce: "Annonce",
    news: "Actualité",
    actuality: "Actualité",
    actualite: "Actualité",
    "actualité": "Actualité",
    event: "Événement",
    evenement: "Événement",
    "événement": "Événement",
    programme: "Programme",
    program: "Programme",
    communication: "Communication",
  };

  return (
    labels[category] ||
    (
      source === "event"
        ? "Événement"
        : "Actualité"
    )
  );
}

async function loadEventRows(
  admin: ReturnType<typeof createAdminClient>,
  churchId: string
) {
  for (const tableName of [
    "events",
    "church_events",
  ]) {
    const { data, error } = await admin
      .from(tableName)
      .select("*")
      .eq("church_id", churchId)
      .limit(60);

    if (!error && data) {
      return data;
    }
  }

  return [];
}

export default async function PublicFeaturedUpdates({
  churchId,
}: PublicFeaturedUpdatesProps) {
  const admin = createAdminClient();

  const [
    publicationsResult,
    eventRows,
  ] = await Promise.all([
    admin
      .from("church_publications")
      .select("*")
      .eq("church_id", churchId)
      .order("created_at", {
        ascending: false,
      })
      .limit(60),

    loadEventRows(
      admin,
      churchId
    ),
  ]);

  const publications: PublicUpdate[] =
    (
      publicationsResult.data ||
      []
    )
      .filter(
        (
          row: Record<string, any>
        ) => {
          const category =
            normalizedCategory(row);

          return (
            isPublishedPublication(row) &&
            PUBLICATION_CATEGORIES.has(
              category
            )
          );
        }
      )
      .map(
        (
          row: Record<string, any>
        ) => {
          const category =
            normalizedCategory(row);

          return {
            key:
              `publication-${row.id}`,
            source:
              "publication" as const,

            title:
              firstValue(row, [
                "title",
                "name",
              ]) ||
              "Publication",

            description:
              firstValue(row, [
                "excerpt",
                "description",
                "summary",
                "content",
              ]) ||
              null,

            category:
              categoryLabel(
                category,
                "publication"
              ),

            imageUrl:
              firstValue(row, [
                "image_url",
                "cover_image_url",
                "thumbnail_url",
              ]) ||
              null,

            date:
              firstValue(row, [
                "published_at",
                "event_date",
                "start_date",
                "starts_at",
                "created_at",
              ]) ||
              null,

            featured:
              isFeatured(row),
          };
        }
      );

  const events: PublicUpdate[] =
    (eventRows || [])
      .filter(
        (
          row: Record<string, any>
        ) =>
          isVisibleEvent(row)
      )
      .map(
        (
          row: Record<string, any>
        ) => ({
          key:
            `event-${row.id}`,

          source:
            "event" as const,

          title:
            firstValue(row, [
              "title",
              "name",
              "event_title",
            ]) ||
            "Événement",

          description:
            firstValue(row, [
              "description",
              "summary",
              "details",
              "notes",
            ]) ||
            null,

          category:
            "Événement",

          imageUrl:
            firstValue(row, [
              "image_url",
              "cover_image_url",
              "photo_url",
            ]) ||
            null,

          date:
            firstValue(row, [
              "starts_at",
              "start_at",
              "start_date",
              "event_date",
              "date",
              "created_at",
            ]) ||
            null,

          featured:
            isFeatured(row),
