      );

  const items = [
    ...publications,
    ...events,
  ]
    .sort((first, second) => {
      if (
        first.featured !==
        second.featured
      ) {
        return first.featured
          ? -1
          : 1;
      }

      return (
        dateValue(second.date) -
        dateValue(first.date)
      );
    })
    .slice(0, 9);

  /*
   * Le bloc reste visible même sans contenu.
   * Cela évite qu'une erreur de filtre donne l'impression
   * que la fonctionnalité n'a pas été installée.
   */
  if (items.length === 0) {
    return (
      <section
        id="actualites"
