  Star,
} from "lucide-react";
import { createClient } from "@/lib/supabase/server";

type PublicTeachingsSectionProps = {
  churchId: string;
};

function getTypeLabel(
  type?: string | null
) {
  if (type === "news") {
    return "Actualité";
  }

  if (type === "event") {
    return "Événement";
  }

  if (
    type === "announcement"
  ) {
    return "Annonce";
  }

  if (type === "sermon") {
    return "Prédication";
  }

  if (type === "video") {
    return "Vidéo";
  }

  if (type === "message") {
    return "Message";
  }

  return "Enseignement";
}

function getYoutubeEmbedUrl(
  url?: string | null
) {
  if (!url) return null;

  if (
    url.includes(
      "youtube.com/embed/"
    )
  ) {
    return url;
  }

  const watchMatch =
    url.match(/[?&]v=([^&]+)/);

  if (watchMatch?.[1]) {
    return `https://www.youtube.com/embed/${watchMatch[1]}`;
  }

  const shortMatch =
    url.match(
      /youtu\.be\/([^?&]+)/
    );

  if (shortMatch?.[1]) {
    return `https://www.youtube.com/embed/${shortMatch[1]}`;
  }

  return null;
}

function formatDate(
  value?: string | null
) {
  if (!value) return "";

  return new Intl.DateTimeFormat(
    "fr-FR",
    {
      day: "2-digit",
      month: "short",
      year: "numeric",
    }
  ).format(new Date(value));
}

