"use client";

import { useEffect, useMemo, useState } from "react";
import {
  CheckCircle2,
  Download,
  Share2,
  Smartphone,
  X,
} from "lucide-react";

type InstallPromptEvent = Event & {
  prompt: () => Promise<void>;
  userChoice: Promise<{
    outcome: "accepted" | "dismissed";
    platform: string;
  }>;
};

function isStandalone() {
  return (
    window.matchMedia("(display-mode: standalone)").matches ||
    Boolean((navigator as any).standalone)
  );
}

function detectPlatform() {
  const ua = navigator.userAgent.toLowerCase();

  return {
    ios: /iphone|ipad|ipod/.test(ua),
    android: /android/.test(ua),
    firefox: /firefox|fxios/.test(ua),
  };
}

export default function UniversalInstallButton({
  compact = false,
  className = "",
}: {
  compact?: boolean;
  className?: string;
}) {
  const [promptEvent, setPromptEvent] =
    useState<InstallPromptEvent | null>(null);
  const [installed, setInstalled] = useState(false);
  const [showHelp, setShowHelp] = useState(false);

  const platform = useMemo(() => {
    if (typeof navigator === "undefined") {
      return { ios: false, android: false, firefox: false };
    }

    return detectPlatform();
  }, []);

  useEffect(() => {
    setInstalled(isStandalone());

    const onBeforeInstallPrompt = (event: Event) => {
      event.preventDefault();
      setPromptEvent(event as InstallPromptEvent);
    };

    const onInstalled = () => {
      setInstalled(true);
      setPromptEvent(null);
      setShowHelp(false);
    };

    window.addEventListener("beforeinstallprompt", onBeforeInstallPrompt);
    window.addEventListener("appinstalled", onInstalled);

    return () => {
      window.removeEventListener(
        "beforeinstallprompt",
        onBeforeInstallPrompt
      );
      window.removeEventListener("appinstalled", onInstalled);
    };
  }, []);

  async function install() {
    if (installed) return;

    if (promptEvent) {
      await promptEvent.prompt();
      const result = await promptEvent.userChoice;

      if (result.outcome === "accepted") {
        setInstalled(true);
      }

      setPromptEvent(null);
      return;
    }

    setShowHelp(true);
  }

  return (
    <>
      <button
        type="button"
        onClick={install}
        disabled={installed}
        className={[
          "inline-flex min-h-11 items-center justify-center gap-2 rounded-2xl px-4 py-3 text-sm font-black transition",
          installed
            ? "cursor-default bg-green-50 text-green-700"
            : "bg-[#03357A] text-white shadow-lg shadow-blue-900/15",
          compact ? "px-3 py-2 text-xs" : "",
          className,
        ].join(" ")}
      >
        {installed ? (
          <>
            <CheckCircle2 className="h-4 w-4" />
            Application installée
          </>
        ) : (
          <>
            <Download className="h-4 w-4" />
            Installer l’application
          </>
        )}
      </button>

      {showHelp && (
        <div className="fixed inset-0 z-[100] flex items-end justify-center bg-slate-950/55 p-3 sm:items-center">
          <section className="w-full max-w-lg rounded-[2rem] bg-white p-5 shadow-2xl">
            <div className="flex items-start justify-between gap-4">
              <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-[#EAF3FA] text-[#03357A]">
                <Smartphone className="h-6 w-6" />
              </div>

              <button
                type="button"
                onClick={() => setShowHelp(false)}
                aria-label="Fermer"
                className="flex h-10 w-10 items-center justify-center rounded-xl bg-slate-100 text-slate-600"
              >
                <X className="h-5 w-5" />
              </button>
            </div>

            <h2 className="mt-4 text-2xl font-black text-[#03357A]">
              Installer l’application
            </h2>

            {platform.ios ? (
              <div className="mt-4 rounded-3xl bg-[#F8FBFD] p-4 text-sm leading-7 text-slate-600">
                <Share2 className="mr-2 inline h-4 w-4 text-[#03357A]" />
                Ouvrez <strong>Partager</strong>, puis choisissez
                <strong> Ajouter à l’écran d’accueil</strong>.
              </div>
            ) : platform.android ? (
              <div className="mt-4 rounded-3xl bg-[#F8FBFD] p-4 text-sm leading-7 text-slate-600">
                Ouvrez le menu du navigateur <strong>⋮</strong>, puis choisissez
                <strong> Installer l’application</strong> ou
                <strong> Ajouter à l’écran d’accueil</strong>.
              </div>
            ) : platform.firefox ? (
              <div className="mt-4 rounded-3xl bg-[#F8FBFD] p-4 text-sm leading-7 text-slate-600">
                Sur Firefox ordinateur, utilisez Chrome ou Edge pour
                l’installation PWA. Firefox Android peut proposer
                l’ajout à l’écran d’accueil.
              </div>
            ) : (
              <div className="mt-4 rounded-3xl bg-[#F8FBFD] p-4 text-sm leading-7 text-slate-600">
                Ouvrez le menu du navigateur, puis choisissez
                <strong> Installer cette application</strong>.
              </div>
            )}
          </section>
        </div>
      )}
    </>
  );
}

"use client";

import { useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import {
  Archive,
  Ban,
  KeyRound,
  Pencil,
  RotateCcw,
  Save,
  Trash2,
  UserCog,
} from "lucide-react";

type UserProfile = {
  id: string;
  userId: string | null;
  fullName: string | null;
  email: string | null;
  role: string | null;
  status: string | null;
};

type Props = {
  profile: UserProfile;
  currentProfileId: string;
};

const ROLE_OPTIONS = [
  { value: "church_admin", label: "Administrateur église" },
  { value: "pasteur_t", label: "Pasteur titulaire" },
  { value: "pastor", label: "Pasteur" },
  { value: "pasteur_a", label: "Pasteur assistant" },
  { value: "charge_afp", label: "Chargé AFP" },
  { value: "department_leader", label: "Responsable département" },
  { value: "responsable_d", label: "Responsable département" },
  { value: "logisticien", label: "Logisticien" },
  { value: "secretaire", label: "Secrétaire" },
  { value: "worker", label: "Ouvrier" },
  { value: "readonly", label: "Lecture seule" },
  { value: "member", label: "Membre" },
];

function normalizeStatus(value: string | null) {
  if (value === "actif") return "active";
  if (value === "inactif") return "inactive";
  return value || "active";
}

export default function ChurchUserProfileActions({
  profile,
  currentProfileId,
}: Props) {
  const router = useRouter();

  const [fullName, setFullName] = useState(profile.fullName || "");
  const [email, setEmail] = useState(profile.email || "");
  const [role, setRole] = useState(profile.role || "worker");
  const [status, setStatus] = useState(normalizeStatus(profile.status));

  const [isEditing, setIsEditing] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const isSelf = profile.id === currentProfileId;
  const isArchived = status === "archived";
  const isInactive = status === "inactive";

  const roleOptions = useMemo(() => {
    if (
      role &&
      !ROLE_OPTIONS.some((item) => item.value === role)
    ) {
      return [
        { value: role, label: role },
        ...ROLE_OPTIONS,
      ];
    }

    return ROLE_OPTIONS;
  }, [role]);

  async function callAction(
    payload: Record<string, unknown>,
    successMessage: string
  ) {
    setIsLoading(true);
    setError("");
    setMessage("");

    try {
      const response = await fetch(
        `/api/settings/users/${profile.id}`,
        {
          method: payload.action === "delete" ? "DELETE" : "PATCH",
          headers: {
            "Content-Type": "application/json",
          },
          body:
            payload.action === "delete"
              ? undefined
              : JSON.stringify(payload),
        }
      );

      const result = await response.json();

      if (!response.ok) {
        throw new Error(
          result?.message || "Action impossible."
        );
      }

      setMessage(result?.message || successMessage);

      if (payload.action === "delete") {
        router.push("/settings/users?deleted=1");
      } else {
        router.refresh();
      }
    } catch (actionError: any) {
      setError(
        actionError?.message || "Une erreur est survenue."
      );
    } finally {
      setIsLoading(false);
    }
  }

  async function saveProfile() {
    if (!fullName.trim()) {
      setError("Le nom complet est obligatoire.");
      return;
    }

    if (!email.trim()) {
      setError("L’adresse email est obligatoire.");
      return;
    }

    await callAction(
      {
        action: "update_profile",
        fullName,
        email,
        role,
      },
      "Informations mises à jour."
    );

    setIsEditing(false);
  }

  async function toggleStatus() {
    const nextStatus =
      isInactive || isArchived
        ? "active"
        : "inactive";

    const confirmed = window.confirm(
      nextStatus === "active"
        ? "Réactiver ce compte utilisateur ?"
        : "Désactiver temporairement ce compte ?"
    );

    if (!confirmed) return;

    await callAction(
      {
        action: "update_status",
        status: nextStatus,
      },
      nextStatus === "active"
        ? "Compte réactivé."
        : "Compte désactivé."
    );

    setStatus(nextStatus);
  }

  async function archiveProfile() {
    const confirmed = window.confirm(
      "Archiver ce compte ? Il sera conservé dans l’historique, mais ne pourra plus se connecter."
    );

    if (!confirmed) return;

    await callAction(
      {
        action: "archive",
      },
      "Compte archivé."
    );

    setStatus("archived");
  }

  async function resetPassword() {
    const password = window.prompt(
      "Saisissez un mot de passe temporaire d’au moins 8 caractères :"
    );

    if (!password) return;

    if (password.length < 8) {
      setError(
        "Le mot de passe temporaire doit contenir au moins 8 caractères."
      );
      return;
    }

    await callAction(
      {
        action: "reset_password",
        password,
      },
      "Mot de passe réinitialisé."
    );
  }

  async function deleteProfile() {
    const confirmation = window.prompt(
      "Suppression définitive. Tapez SUPPRIMER pour confirmer :"
    );

    if (confirmation !== "SUPPRIMER") {
      return;
    }

    await callAction(
      {
        action: "delete",
      },
      "Utilisateur supprimé."
    );
  }

  return (
    <section className="mt-5 rounded-3xl border border-[#C9DBEA] bg-[#F8FBFD] p-4 sm:p-5">
      <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between">
        <div>
          <div className="flex items-center gap-2">
            <UserCog className="h-5 w-5 text-[#03357A]" />
            <h3 className="font-black text-[#03357A]">
              Gestion du compte
            </h3>
          </div>

          <p className="mt-2 text-sm leading-6 text-slate-600">
            Modifiez les informations, le rôle et l’état du compte.
            L’archivage est recommandé avant une suppression définitive.
          </p>
        </div>

        <button
          type="button"
          onClick={() => setIsEditing((value) => !value)}
          disabled={isLoading}
          className="inline-flex min-h-11 items-center justify-center gap-2 rounded-xl bg-white px-4 text-sm font-black text-[#03357A] ring-1 ring-[#C9DBEA]"
        >
          <Pencil className="h-4 w-4" />
          {isEditing ? "Fermer" : "Modifier"}
        </button>
