"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { QRCodeCanvas } from "qrcode.react";
import {
  CheckCircle2,
  Clipboard,
  Download,
  ExternalLink,
  Loader2,
  QrCode,
  RefreshCcw,
  ShieldCheck,
  ShieldOff,
} from "lucide-react";

type MemberRegistrationLinkCardProps = {
  church: {
    slug: string | null;
    member_form_enabled: boolean | null;
    member_form_token: string | null;
  };
};

export default function MemberRegistrationLinkCard({
  church,
}: MemberRegistrationLinkCardProps) {
  const router = useRouter();

  const [isMounted, setIsMounted] = useState(false);
  const [registrationUrl, setRegistrationUrl] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState("");

  useEffect(() => {
    setIsMounted(true);

    if (!church.slug || !church.member_form_token) {
      setRegistrationUrl("");
      return;
    }

    setRegistrationUrl(
      `${window.location.origin}/church/${church.slug}/member-registration?token=${church.member_form_token}`
    );
  }, [church.slug, church.member_form_token]);

  async function copyLink() {
    if (!registrationUrl) return;

    try {
      await navigator.clipboard.writeText(registrationUrl);
      setMessage("Lien copié.");
    } catch {
      setMessage("Impossible de copier automatiquement. Copiez le lien manuellement.");
    }
  }

  function downloadQrCode() {
    const canvas = document.getElementById(
      "member-registration-qr"
    ) as HTMLCanvasElement | null;

    if (!canvas) return;

    const image = canvas.toDataURL("image/png");
    const link = document.createElement("a");

    link.href = image;
    link.download = "qr-code-formulaire-membre.png";
    link.click();
  }

  async function updateSettings(action: "toggle" | "regenerate") {
    setIsLoading(true);
    setMessage("");

    const response = await fetch("/api/settings/member-registration", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(
        action === "toggle"
          ? {
              action,
              enabled: !church.member_form_enabled,
            }
          : {
              action,
            }
      ),
    });

    const payload = await response.json();

    setIsLoading(false);

    if (!response.ok) {
      alert(payload.error || "Erreur pendant la mise à jour.");
      return;
    }

    setMessage(
      action === "toggle"
        ? "Statut du formulaire mis à jour."
        : "Nouveau lien sécurisé généré."
    );

    router.refresh();
  }

  return (
    <section className="rounded-3xl border border-[#DCEAF5] bg-white p-6 shadow-sm">
      <div className="flex flex-col justify-between gap-5 lg:flex-row lg:items-start">
        <div>
          <div className="flex items-center gap-3">
            <div className="flex h-12 w-12 items-center justify-center rounded-2xl bg-[#EAF3FA] text-[#03357A]">
              <QrCode className="h-6 w-6" />
            </div>

            <div>
              <h2 className="text-xl font-extrabold text-[#03357A]">
                Formulaire public d’ajout membre
              </h2>

              <p className="mt-1 text-sm text-slate-500">
                Partagez ce QR Code aux serviteurs pour qu’ils remplissent leur
                fiche membre sans compte admin.
              </p>
            </div>
          </div>

          <div className="mt-5 flex flex-wrap gap-2">
            <span
              className={`inline-flex items-center gap-2 rounded-full px-4 py-2 text-sm font-extrabold ${
                church.member_form_enabled
                  ? "bg-green-50 text-green-700"
                  : "bg-red-50 text-red-700"
              }`}
            >
              {church.member_form_enabled ? (
                <ShieldCheck className="h-4 w-4" />
              ) : (
                <ShieldOff className="h-4 w-4" />
              )}

              {church.member_form_enabled
                ? "Formulaire actif"
                : "Formulaire désactivé"}
            </span>
          </div>
        </div>

        <div className="flex flex-wrap gap-2">
          <button
            type="button"
            onClick={() => updateSettings("toggle")}
            disabled={isLoading}
            className="inline-flex items-center justify-center gap-2 rounded-2xl border border-[#DCEAF5] bg-white px-4 py-3 text-sm font-extrabold text-[#03357A] hover:bg-[#EAF3FA] disabled:opacity-60"
          >
            {isLoading && <Loader2 className="h-4 w-4 animate-spin" />}
            {church.member_form_enabled ? "Désactiver" : "Activer"}
          </button>

          <button
            type="button"
            onClick={() => updateSettings("regenerate")}
            disabled={isLoading}
            className="inline-flex items-center justify-center gap-2 rounded-2xl bg-orange-50 px-4 py-3 text-sm font-extrabold text-orange-700 hover:bg-orange-100 disabled:opacity-60"
          >
            <RefreshCcw className="h-4 w-4" />
            Régénérer le lien
          </button>
        </div>
      </div>

      <div className="mt-6 grid gap-6 lg:grid-cols-[0.6fr_1.4fr]">
        <div className="rounded-3xl bg-[#F8FBFD] p-5 text-center">
          {isMounted && registrationUrl ? (
            <div className="inline-flex rounded-3xl bg-white p-4 shadow-sm">
              <QRCodeCanvas
                id="member-registration-qr"
                value={registrationUrl}
                size={240}
                level="H"
                includeMargin
              />
            </div>
          ) : (
            <div className="rounded-3xl bg-white p-8 text-sm font-semibold text-slate-500">
              Génération du QR Code...
            </div>
          )}

          <button
            type="button"
            onClick={downloadQrCode}
            disabled={!registrationUrl}
            className="mt-4 inline-flex items-center justify-center gap-2 rounded-2xl bg-[#03357A] px-4 py-3 text-sm font-extrabold text-white hover:bg-[#022B63] disabled:opacity-60"
          >
            <Download className="h-4 w-4" />
            Télécharger QR Code
          </button>
        </div>

        <div className="rounded-3xl bg-[#F8FBFD] p-5">
          <p className="text-sm font-bold text-[#03357A]">Lien public</p>

          <div className="mt-3 break-all rounded-2xl border border-[#DCEAF5] bg-white p-4 text-sm font-semibold text-slate-600">
            {registrationUrl || "Lien en cours de génération..."}
          </div>

          <div className="mt-4 flex flex-wrap gap-2">
            <button
              type="button"
              onClick={copyLink}
              disabled={!registrationUrl}
              className="inline-flex items-center justify-center gap-2 rounded-2xl border border-[#DCEAF5] bg-white px-4 py-3 text-sm font-extrabold text-[#03357A] hover:bg-[#EAF3FA] disabled:opacity-60"
            >
              <Clipboard className="h-4 w-4" />
              Copier le lien
            </button>

            {registrationUrl && (
              <a
                href={registrationUrl}
                target="_blank"
                rel="noreferrer"
                className="inline-flex items-center justify-center gap-2 rounded-2xl bg-[#03357A] px-4 py-3 text-sm font-extrabold text-white hover:bg-[#022B63]"
              >
                <ExternalLink className="h-4 w-4" />
                Ouvrir le formulaire
              </a>
            )}
          </div>

          {message && (
            <p className="mt-4 inline-flex items-center gap-2 rounded-2xl bg-green-50 px-4 py-3 text-sm font-extrabold text-green-700">
              <CheckCircle2 className="h-4 w-4" />
              {message}
            </p>
          )}

          <div className="mt-5 rounded-2xl bg-white p-4 text-sm leading-7 text-slate-600">
            <strong className="text-[#03357A]">Important :</strong> si vous
            régénérez le lien, l’ancien QR Code ne fonctionnera plus. Faites-le
            seulement si l’ancien lien a été trop partagé ou compromis.
          </div>
        </div>
      </div>
    </section>
  );
}

"use client";

import { FormEvent, useMemo, useState } from "react";
import { useRouter } from "next/navigation";
import { Building2, Globe2, ImageIcon, MapPin, Phone } from "lucide-react";
import { createClient } from "@/lib/supabase/client";

function generateSlug(value: string) {
  return value
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)+/g, "");
}

const inputClass =
  "mt-2 w-full rounded-xl border border-[#C9DBEA] bg-white px-4 py-3 text-[#0F172A] placeholder:text-slate-400 outline-none transition focus:border-[#03357A] focus:ring-4 focus:ring-[#03357A]/10";

const labelClass = "text-sm font-semibold text-[#03357A]";

export default function ChurchForm() {
  const router = useRouter();
  const supabase = useMemo(() => createClient(), []);

  const [name, setName] = useState("");
  const [slug, setSlug] = useState("");
  const [address, setAddress] = useState("");
  const [city, setCity] = useState("");
  const [country, setCountry] = useState("");
  const [phone, setPhone] = useState("");
  const [whatsapp, setWhatsapp] = useState("");
  const [email, setEmail] = useState("");
  const [serviceTimes, setServiceTimes] = useState("");
  const [logoUrl, setLogoUrl] = useState("");
  const [coverImageUrl, setCoverImageUrl] = useState("");

  const [errorMessage, setErrorMessage] = useState("");
  const [successMessage, setSuccessMessage] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  function handleNameChange(value: string) {
    setName(value);

    if (!slug) {
      setSlug(generateSlug(value));
    }
  }

  async function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();

    setErrorMessage("");
    setSuccessMessage("");
    setIsLoading(true);

    const cleanSlug = generateSlug(slug || name);

    if (!name.trim()) {
      setErrorMessage("Le nom de l’église est obligatoire.");
      setIsLoading(false);
      return;
    }

    if (!cleanSlug) {
      setErrorMessage("Le slug public est obligatoire.");
      setIsLoading(false);
      return;
    }

    const { error } = await supabase.rpc("create_church_as_super_admin", {
      _name: name.trim(),
      _slug: cleanSlug,
      _address: address.trim(),
      _city: city.trim(),
      _country: country.trim(),
      _phone: phone.trim(),
      _whatsapp: whatsapp.trim(),
      _email: email.trim(),
      _service_times: serviceTimes.trim(),
      _logo_url: logoUrl.trim(),
      _cover_image_url: coverImageUrl.trim(),
    });

    if (error) {
      setErrorMessage(error.message);
      setIsLoading(false);
      return;
    }

    setSuccessMessage("Église créée avec succès.");

    setTimeout(() => {
      router.push("/super-admin/churches");
      router.refresh();
    }, 700);
  }

  return (
    <form onSubmit={handleSubmit} className="space-y-8">
      {errorMessage && (
        <div className="rounded-2xl border border-red-200 bg-red-50 px-5 py-4 text-sm font-medium text-red-700">
          {errorMessage}
        </div>
      )}

      {successMessage && (
        <div className="rounded-2xl border border-green-200 bg-green-50 px-5 py-4 text-sm font-medium text-green-700">
          {successMessage}
        </div>
      )}

      <section className="rounded-3xl border border-[#DCEAF5] bg-[#F8FBFD] p-5">
        <div className="mb-5 flex items-center gap-3">
          <div className="rounded-2xl bg-[#03357A] p-3 text-white">
            <Building2 className="h-5 w-5" />
          </div>

          <div>
            <h2 className="text-lg font-bold text-[#03357A]">
              Informations principales
            </h2>
            <p className="text-sm text-slate-500">
              Identité de l’église dans Mpangi-Church.
            </p>
          </div>
        </div>

        <div className="grid gap-5">
          <div>
            <label className={labelClass}>Nom de l’église *</label>
            <input
              type="text"
              value={name}
              onChange={(event) => handleNameChange(event.target.value)}
              className={inputClass}
              placeholder="Exemple : Impact Centre Chrétien"
              required
            />
          </div>

          <div>
            <label className={labelClass}>Slug public *</label>
            <input
              type="text"
              value={slug}
              onChange={(event) => setSlug(generateSlug(event.target.value))}
              className={inputClass}
              placeholder="impact-centre-chretien"
              required
            />
            <p className="mt-2 rounded-xl bg-white px-3 py-2 text-xs font-medium text-[#3F79B3]">
              Lien public : /church/{slug || "nom-eglise"}
            </p>
          </div>
        </div>
      </section>

      <section className="rounded-3xl border border-[#DCEAF5] bg-[#F8FBFD] p-5">
        <div className="mb-5 flex items-center gap-3">
          <div className="rounded-2xl bg-[#3F79B3] p-3 text-white">
            <MapPin className="h-5 w-5" />
          </div>

          <div>
            <h2 className="text-lg font-bold text-[#03357A]">
              Adresse et localisation
            </h2>
            <p className="text-sm text-slate-500">
              Ces informations apparaîtront sur la page publique.
            </p>
          </div>
        </div>

        <div className="grid gap-5 md:grid-cols-2">
          <div>
            <label className={labelClass}>Ville</label>
            <input
              type="text"
              value={city}
              onChange={(event) => setCity(event.target.value)}
              className={inputClass}
              placeholder="Kinshasa"
            />
          </div>

          <div>
            <label className={labelClass}>Pays</label>
            <input
              type="text"
              value={country}
              onChange={(event) => setCountry(event.target.value)}
              className={inputClass}
              placeholder="RD Congo"
            />
          </div>

          <div className="md:col-span-2">
            <label className={labelClass}>Adresse complète</label>
            <input
              type="text"
              value={address}
              onChange={(event) => setAddress(event.target.value)}
              className={inputClass}
              placeholder="Rue, commune, quartier..."
            />
          </div>
        </div>
      </section>

      <section className="rounded-3xl border border-[#DCEAF5] bg-[#F8FBFD] p-5">
        <div className="mb-5 flex items-center gap-3">
          <div className="rounded-2xl bg-[#6D9FC7] p-3 text-white">
            <Phone className="h-5 w-5" />
          </div>

          <div>
            <h2 className="text-lg font-bold text-[#03357A]">
              Contacts et horaires
            </h2>
            <p className="text-sm text-slate-500">
              Téléphone, WhatsApp, email et horaires des cultes.
            </p>
          </div>
        </div>

        <div className="grid gap-5 md:grid-cols-2">
          <div>
            <label className={labelClass}>Téléphone</label>
            <input
              type="text"
              value={phone}
              onChange={(event) => setPhone(event.target.value)}
              className={inputClass}
              placeholder="+243..."
            />
          </div>

          <div>
            <label className={labelClass}>WhatsApp</label>
            <input
              type="text"
              value={whatsapp}
              onChange={(event) => setWhatsapp(event.target.value)}
              className={inputClass}
              placeholder="+243..."
            />
          </div>

          <div className="md:col-span-2">
            <label className={labelClass}>Email</label>
            <input
              type="email"
              value={email}
              onChange={(event) => setEmail(event.target.value)}
              className={inputClass}
              placeholder="contact@eglise.com"
            />
          </div>

          <div className="md:col-span-2">
            <label className={labelClass}>Horaires des cultes</label>
            <textarea
              value={serviceTimes}
              onChange={(event) => setServiceTimes(event.target.value)}
              rows={4}
              className={inputClass}
              placeholder={"Dimanche : 09h00 - 12h00\nMercredi : 18h00 - 20h00"}
            />
          </div>
        </div>
      </section>

      <section className="rounded-3xl border border-[#DCEAF5] bg-[#F8FBFD] p-5">
        <div className="mb-5 flex items-center gap-3">
          <div className="rounded-2xl bg-[#C085D1] p-3 text-white">
            <ImageIcon className="h-5 w-5" />
          </div>

          <div>
            <h2 className="text-lg font-bold text-[#03357A]">
              Images publiques
            </h2>
            <p className="text-sm text-slate-500">
              Logo et photo principale de l’église.
            </p>
          </div>
        </div>

        <div className="grid gap-5 md:grid-cols-2">
          <div>
            <label className={labelClass}>URL logo</label>
            <input
              type="url"
              value={logoUrl}
              onChange={(event) => setLogoUrl(event.target.value)}
              className={inputClass}
              placeholder="https://..."
            />
          </div>

          <div>
            <label className={labelClass}>URL photo de l’église</label>
            <input
              type="url"
              value={coverImageUrl}
              onChange={(event) => setCoverImageUrl(event.target.value)}
              className={inputClass}
              placeholder="https://..."
            />
          </div>
        </div>
      </section>

      <div className="sticky bottom-0 flex flex-col gap-3 rounded-3xl border border-[#DCEAF5] bg-white/95 p-4 shadow-lg backdrop-blur sm:flex-row sm:justify-end">
        <button
          type="button"
          onClick={() => router.push("/super-admin/churches")}
          className="rounded-xl border border-[#C9DBEA] px-5 py-3 font-semibold text-[#03357A] hover:bg-[#EAF3FA]"
        >
          Annuler
        </button>

        <button
          type="submit"
          disabled={isLoading}
          className="rounded-xl bg-[#03357A] px-6 py-3 font-semibold text-white hover:bg-[#29417E] disabled:cursor-not-allowed disabled:opacity-70"
        >
          {isLoading ? "Création en cours..." : "Créer l’église"}
        </button>
      </div>
    </form>
  );
}

