  const visibleCodes = new Set(moduleCodes);

  const visibleItems = MODULE_MENU_ITEMS.filter(
    (item) => item.alwaysVisible || visibleCodes.has(item.code)
  );

  return CATEGORY_ORDER.map((category) => ({
    key: category,
    title: MODULE_CATEGORY_META[category].title,
    shortTitle: MODULE_CATEGORY_META[category].shortTitle,
    description: MODULE_CATEGORY_META[category].description,
    icon: MODULE_CATEGORY_META[category].icon,
    items: visibleItems.filter((item) => item.category === category),
  })).filter((group) => group.items.length > 0);
}

export function findActiveMenuGroup(
  groups: ModuleMenuGroup[],
  pathname: string
): ModuleMenuGroup | null {
  const sortedGroups = groups.map((group) => ({
    ...group,
    items: [...group.items].sort((a, b) => b.href.length - a.href.length),
  }));

  return (
    sortedGroups.find((group) =>
      group.items.some((item) => {
        if (item.href === "/dashboard") return pathname === item.href;
        return pathname === item.href || pathname.startsWith(`${item.href}/`);
      })
    ) ?? null
  );
}

export function isActiveMenuItem(pathname: string, href: string) {
  if (href === "/dashboard") return pathname === href;
  return pathname === href || pathname.startsWith(`${href}/`);
}

import { NextResponse } from "next/server";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

export async function GET() {
  try {
    const supabase = await createClient();

    const {
      data: { user },
    } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json(
        { error: "Utilisateur non connecté." },
        { status: 401 }
      );
    }

    const { data: profile } = await supabase
      .from("profiles")
      .select("id, role, church_id, status")
      .eq("user_id", user.id)
      .maybeSingle();

    if (!profile) {
      return NextResponse.json(
        { error: "Profil utilisateur introuvable." },
        { status: 403 }
      );
    }

    if (profile.status && profile.status !== "active") {
      return NextResponse.json(
        { error: "Compte désactivé." },
        { status: 403 }
      );
    }

    if (profile.role === "super_admin") {
      return NextResponse.json({
        role: profile.role,
        churchId: null,
        moduleCodes: [],
      });
    }

    if (!profile.church_id) {
      return NextResponse.json(
        { error: "Aucune église rattachée à ce compte." },
        { status: 403 }
      );
    }

    const admin = createAdminClient();

    const [{ data: enabledModules }, { data: permissions }] = await Promise.all([
      admin
        .from("church_modules")
        .select("module_code")
        .eq("church_id", profile.church_id)
        .eq("enabled", true),

      admin
        .from("church_role_module_permissions")
        .select("module_code, can_view")
        .eq("church_id", profile.church_id)
        .eq("role", profile.role)
        .eq("can_view", true),
    ]);

    const permissionCodes = new Set(
      (permissions ?? []).map((permission: any) => permission.module_code)
    );

    const moduleCodes = (enabledModules ?? [])
      .map((module: any) => module.module_code)
      .filter((code: string) => permissionCodes.has(code));

    return NextResponse.json({
      role: profile.role,
      churchId: profile.church_id,
      moduleCodes,
    });
  } catch {
    return NextResponse.json(
      { error: "Erreur pendant le chargement des modules." },
      { status: 500 }
    );
  }
}

import webpush from "web-push";
import { createAdminClient } from "@/lib/supabase/admin";

let configured = false;

function getPushConfiguration() {
  const publicKey =
    process.env
      .NEXT_PUBLIC_VAPID_PUBLIC_KEY;

  const privateKey =
    process.env
      .VAPID_PRIVATE_KEY;

  const subject =
    process.env.VAPID_SUBJECT ||
    "mailto:aksantictech@gmail.com";

  return {
    publicKey,
    privateKey,
    subject,
    valid:
      Boolean(publicKey) &&
      Boolean(privateKey),
  };
}

function configureWebPush() {
  if (configured) return;

  const config =
    getPushConfiguration();

  if (
    !config.publicKey ||
    !config.privateKey
  ) {
    throw new Error(
      "Variables VAPID manquantes dans Vercel."
    );
  }

  webpush.setVapidDetails(
    config.subject,
    config.publicKey,
    config.privateKey
  );

  configured = true;
}

function withTimeout<T>(
  promise: Promise<T>,
  milliseconds: number
) {
  return Promise.race([
    promise,
    new Promise<never>(
      (_resolve, reject) => {
        const timeout =
          setTimeout(() => {
            clearTimeout(timeout);

            reject(
              new Error(
                "Délai d’envoi Push dépassé."
              )
            );
          }, milliseconds);
      }
    ),
  ]);
}

export type SendChurchNotificationInput = {
  churchId: string;
  title: string;
  body?: string;
  url?: string;
  type?: string;
  createdBy?: string | null;
  data?: Record<string, unknown>;
};

export type SendChurchNotificationResult = {
  recipientsCount: number;
  successCount: number;
  failureCount: number;
  warning: string | null;
};

async function writeNotificationLog({
  churchId,
  title,
  body,
  url,
  type,
  createdBy,
  recipientsCount,
  successCount,
  failureCount,
  status,
}: {
  churchId: string;
  title: string;
  body?: string;
  url?: string;
  type: string;
  createdBy: string | null;
  recipientsCount: number;
  successCount: number;
  failureCount: number;
  status: string;
}) {
  try {
    const admin =
      createAdminClient();

    await admin
      .from(
        "church_notification_logs"
      )
      .insert({
        church_id: churchId,
        title,
        body: body || null,
        url: url || null,
        type,
        status,
        recipients_count:
          recipientsCount,
        success_count:
          successCount,
        failure_count:
          failureCount,
        created_by:
          createdBy,
      });
  } catch {
    // Le journal ne doit jamais bloquer l’action métier.
  }
}

export async function sendChurchNotification({
  churchId,
  title,
  body,
  url,
  type = "manual",
  createdBy = null,
  data = {},
}: SendChurchNotificationInput): Promise<SendChurchNotificationResult> {
  const admin =
    createAdminClient();

  const {
    data: subscriptions,
    error: subscriptionsError,
  } = await admin
    .from(
      "church_notification_subscriptions"
    )
    .select(
      "id, endpoint, p256dh, auth"
    )
    .eq("church_id", churchId)
    .eq("active", true);

  if (subscriptionsError) {
    const warning =
      `Abonnements Push non chargés : ${subscriptionsError.message}`;

    await writeNotificationLog({
      churchId,
      title,
      body,
      url,
      type,
      createdBy,
      recipientsCount: 0,
      successCount: 0,
      failureCount: 0,
      status: "failed",
    });

    return {
      recipientsCount: 0,
      successCount: 0,
      failureCount: 0,
      warning,
    };
  }

  const rows =
    subscriptions ?? [];

  if (rows.length === 0) {
    await writeNotificationLog({
      churchId,
      title,
      body,
      url,
      type,
      createdBy,
      recipientsCount: 0,
      successCount: 0,
      failureCount: 0,
      status: "skipped",
    });

    return {
      recipientsCount: 0,
      successCount: 0,
      failureCount: 0,
      warning:
        "Aucun appareil n’est encore abonné.",
    };
  }

  const config =
    getPushConfiguration();

  if (!config.valid) {
    const warning =
      "Notification non envoyée : variables VAPID absentes dans Vercel.";

    await writeNotificationLog({
      churchId,
      title,
      body,
      url,
      type,
      createdBy,
      recipientsCount:
        rows.length,
      successCount: 0,
      failureCount:
        rows.length,
      status: "failed",
    });

    return {
      recipientsCount:
        rows.length,
      successCount: 0,
      failureCount:
        rows.length,
      warning,
    };
  }

  configureWebPush();

  const payload =
    JSON.stringify({
      title,
      body: body || "",
      url: url || "/",
      type,
      data,
    });

  const results =
    await Promise.all(
      rows.map(
        async (
          subscription: any
        ) => {
          try {
            await withTimeout(
              webpush.sendNotification(
                {
                  endpoint:
                    subscription.endpoint,
                  keys: {
                    p256dh:
                      subscription.p256dh,
                    auth:
                      subscription.auth,
                  },
                },
                payload
              ),
              10000
            );

            return {
              success: true,
            };
          } catch (
            error: any
          ) {
            if (
              error?.statusCode ===
                404 ||
              error?.statusCode ===
                410
            ) {
              await admin
                .from(
                  "church_notification_subscriptions"
                )
                .update({
                  active: false,
                  updated_at:
                    new Date().toISOString(),
                })
                .eq(
                  "id",
                  subscription.id
                );
            }

            return {
              success: false,
            };
          }
        }
      )
    );

  const successCount =
    results.filter(
      (item) => item.success
    ).length;

  const failureCount =
    results.length -
    successCount;

  await writeNotificationLog({
    churchId,
    title,
    body,
    url,
    type,
    createdBy,
    recipientsCount:
      rows.length,
    successCount,
    failureCount,
    status:
      successCount > 0
        ? "sent"
        : "failed",
  });

  return {
    recipientsCount:
      rows.length,
    successCount,
    failureCount,
    warning:
      failureCount > 0
        ? `${failureCount} appareil(s) n’ont pas reçu la notification.`
        : null,
  };
}

import { createAdminClient } from "@/lib/supabase/admin";

export type OnboardingStatus = "pending" | "in_progress" | "done" | "blocked";

export type ChurchOnboardingStep = {
  id: string;
  church_id: string;
  step_key: string;
  label: string;
  description: string | null;
  status: OnboardingStatus;
  sort_order: number;
  notes: string | null;
  completed_at: string | null;
  completed_by: string | null;
};

export type ChurchOnboardingSummary = {
  id: string;
  name: string;
  slug: string;
  status: string | null;
  city: string | null;
  country: string | null;
  totalSteps: number;
  doneSteps: number;
  blockedSteps: number;
  progress: number;
};

function calculateProgress(total: number, done: number) {
  if (!total) return 0;
  return Math.round((done / total) * 100);
}

export async function initializeOnboarding(churchId: string) {
  const admin = createAdminClient();

  const { error } = await admin.rpc("initialize_church_onboarding", {
    p_church_id: churchId,
  });

  if (error) throw new Error(error.message);
}

export async function getOnboardingSummaries(): Promise<ChurchOnboardingSummary[]> {
  const admin = createAdminClient();

  const { data: churches, error: churchesError } = await admin
    .from("churches")
    .select("id, name, slug, status, city, country")
    .order("name", { ascending: true });

  if (churchesError) throw new Error(churchesError.message);

  for (const church of churches ?? []) {
    await initializeOnboarding(church.id);
  }

  const { data: steps, error: stepsError } = await admin
    .from("church_onboarding_steps")
    .select("church_id, status");

  if (stepsError) throw new Error(stepsError.message);

  return (churches ?? []).map((church: any) => {
    const churchSteps = (steps ?? []).filter(
      (step: any) => step.church_id === church.id
    );

    const totalSteps = churchSteps.length;
    const doneSteps = churchSteps.filter((step: any) => step.status === "done").length;
    const blockedSteps = churchSteps.filter(
      (step: any) => step.status === "blocked"
    ).length;

    return {
      id: church.id,
      name: church.name,
      slug: church.slug,
      status: church.status,
      city: church.city,
      country: church.country,
      totalSteps,
      doneSteps,
      blockedSteps,
      progress: calculateProgress(totalSteps, doneSteps),
    };
  });
}

export async function getChurchOnboarding(churchId: string) {
  const admin = createAdminClient();

  await initializeOnboarding(churchId);

  const [{ data: church, error: churchError }, { data: steps, error: stepsError }] =
    await Promise.all([
      admin
        .from("churches")
        .select("id, name, slug, status, city, country, logo_url")
        .eq("id", churchId)
        .maybeSingle(),

      admin
        .from("church_onboarding_steps")
        .select("*")
        .eq("church_id", churchId)
        .order("sort_order", { ascending: true }),
    ]);

  if (churchError) throw new Error(churchError.message);
  if (stepsError) throw new Error(stepsError.message);
  if (!church) throw new Error("Église introuvable.");

  const totalSteps = (steps ?? []).length;
  const doneSteps = (steps ?? []).filter((step: any) => step.status === "done").length;
  const blockedSteps = (steps ?? []).filter(
    (step: any) => step.status === "blocked"
  ).length;

  return {
    church,
    steps: (steps ?? []) as ChurchOnboardingStep[],
    totalSteps,
    doneSteps,
    blockedSteps,
    progress: calculateProgress(totalSteps, doneSteps),
  };
}

export async function updateOnboardingStep({
  stepId,
  status,
  notes,
  completedBy,
}: {
  stepId: string;
  status: OnboardingStatus;
  notes?: string;
  completedBy?: string | null;
}) {
  const admin = createAdminClient();

  const payload: Record<string, unknown> = {
    status,
    notes: notes ?? null,
    updated_at: new Date().toISOString(),
  };

  if (status === "done") {
    payload.completed_at = new Date().toISOString();
    if (completedBy) payload.completed_by = completedBy;
  } else {
    payload.completed_at = null;
    payload.completed_by = null;
  }

  const { error } = await admin
    .from("church_onboarding_steps")
    .update(payload)
    .eq("id", stepId);

  if (error) throw new Error(error.message);
}

export async function completeOnboarding(churchId: string, completedBy?: string | null) {
  const admin = createAdminClient();

  const { error } = await admin.rpc("complete_church_onboarding", {
    p_church_id: churchId,
    p_completed_by: completedBy ?? null,
  });

  if (error) throw new Error(error.message);
}

export async function resetOnboarding(churchId: string) {
  const admin = createAdminClient();

  const { error } = await admin.rpc("reset_church_onboarding", {
    p_church_id: churchId,
  });

  if (error) throw new Error(error.message);
}

import { redirect } from "next/navigation";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";
import {
  AFP_ROLES,
  CHURCH_ADMIN_ROLES,
  DEPARTMENT_ROLES,
  LOGISTIC_ROLES,
  PASTOR_ROLES,
  SECRETARY_ROLES,
  VIEWER_ROLES,
  WORKER_ROLES,
  normalizeRole,
} from "@/lib/roles";

export type PermissionAction =
  | "can_view"
  | "can_create"
  | "can_update"
  | "can_delete"
  | "can_export"
  | "can_approve";

export type ModulePermission = Record<PermissionAction, boolean>;

export type SecurityProfile = {
  id: string;
  user_id?: string | null;
  full_name?: string | null;
  email?: string | null;
  role?: string | null;
  status?: string | null;
  church_id?: string | null;
};

export type ChurchSecurityProfile = SecurityProfile & {
  church_id: string;
};

export type SecurityContext = {
  admin: ReturnType<typeof createAdminClient>;
  profile: SecurityProfile;
  role: string;
  churchId: string | null;
};

export type ChurchSecurityContext = Omit<SecurityContext, "profile" | "churchId"> & {
  profile: ChurchSecurityProfile;
  churchId: string;
};

export type ModuleAccessResult = SecurityContext & {
  moduleCode: string;
  source: "profile" | "role" | "fallback" | "super_admin";
  permissions: ModulePermission;
  granted: boolean;
  reason?: string;
};

export type RequiredModuleAccessResult = Omit<
  ModuleAccessResult,
  "profile" | "churchId"
> & {
  profile: ChurchSecurityProfile;
  churchId: string;
};

const EMPTY_PERMISSIONS: ModulePermission = {
  can_view: false,
  can_create: false,
  can_update: false,
  can_delete: false,
  can_export: false,
  can_approve: false,
};

const FULL_PERMISSIONS: ModulePermission = {
  can_view: true,
  can_create: true,
  can_update: true,
  can_delete: true,
  can_export: true,
  can_approve: true,
};

const SYSTEM_MODULES = new Set([
  "dashboard",
  "settings",
  "notifications",
  "pwa_install",
]);

function withChurchProfile(
  context: SecurityContext | ModuleAccessResult,
  churchId: string
) {
  return {
    ...context,
    churchId,
    profile: {
      ...context.profile,
      church_id: churchId,
    },
  };
}

function buildPermission(row: any): ModulePermission {
  return {
    can_view: Boolean(row?.can_view),
    can_create: Boolean(row?.can_create),
    can_update: Boolean(row?.can_update),
    can_delete: Boolean(row?.can_delete),
    can_export: Boolean(row?.can_export),
    can_approve: Boolean(row?.can_approve),
  };
}

function fallbackPermissions(role: string, moduleCode: string): ModulePermission {
  if (CHURCH_ADMIN_ROLES.has(role)) return FULL_PERMISSIONS;

  if (SYSTEM_MODULES.has(moduleCode)) {
    return {
      ...EMPTY_PERMISSIONS,
      can_view: true,
      can_update: moduleCode === "settings",
    };
  }

  if (PASTOR_ROLES.has(role)) {
    const allowed = [
      "members",
      "attendance",
      "souls",
      "departments",
      "events",
      "publications",
      "teachings",
      "appointments",
      "testimonies",
      "public_requests",
    ].includes(moduleCode);

    if (!allowed) return EMPTY_PERMISSIONS;

    return {
      can_view: true,
      can_create: true,
      can_update: true,
      can_delete: false,
      can_export: true,
      can_approve:
        role === "pastor_titulaire" || role === "pastor" || role === "pasteur",
    };
  }

  if (AFP_ROLES.has(role)) {
    const allowed = [
      "correspondence",
      "document_transmissions",
      "administrative_tasks",
      "meetings_minutes",
      "finance_dashboard",
      "offerings",
      "expenses",
      "budgets",
      "financial_reports",
      "patrimony_dashboard",
      "assets",
      "asset_maintenance",
      "asset_movements",
      "teachings",
    ].includes(moduleCode);

    if (!allowed) return EMPTY_PERMISSIONS;

    return {
      can_view: true,
      can_create: true,
      can_update: true,
      can_delete: false,
      can_export: true,
      can_approve: true,
    };
  }

  if (SECRETARY_ROLES.has(role)) {
    const allowed = [
      "correspondence",
      "document_transmissions",
      "administrative_tasks",
      "meetings_minutes",
      "teachings",
    ].includes(moduleCode);

    if (!allowed) return EMPTY_PERMISSIONS;

    return {
      can_view: true,
      can_create: true,
      can_update: true,
      can_delete: false,
      can_export: true,
      can_approve: false,
    };
  }

  if (LOGISTIC_ROLES.has(role)) {
    const allowed = [
      "patrimony_dashboard",
      "assets",
      "asset_maintenance",
      "asset_movements",
      "administrative_tasks",
    ].includes(moduleCode);

    if (!allowed) return EMPTY_PERMISSIONS;

    return {
      can_view: true,
      can_create: true,
      can_update: true,
      can_delete: false,
      can_export: true,
      can_approve: false,
    };
  }

  if (DEPARTMENT_ROLES.has(role)) {
    const allowed = [
      "members",
      "attendance",
      "souls",
      "departments",
      "events",
      "administrative_tasks",
    ].includes(moduleCode);

    if (!allowed) return EMPTY_PERMISSIONS;

    return {
      can_view: true,
      can_create: true,
      can_update: true,
      can_delete: false,
      can_export: false,
      can_approve: false,
    };
  }

  if (WORKER_ROLES.has(role)) {
    const allowed = ["members", "attendance", "souls", "events"].includes(
      moduleCode
    );

    return allowed
      ? {
          ...EMPTY_PERMISSIONS,
          can_view: true,
        }
      : EMPTY_PERMISSIONS;
  }

  if (VIEWER_ROLES.has(role)) {
    return {
      ...EMPTY_PERMISSIONS,
      can_view: ["members", "attendance", "souls", "events"].includes(
        moduleCode
      ),
    };
  }

  return EMPTY_PERMISSIONS;
}

function hasPermission(permissions: ModulePermission, action: PermissionAction) {
  if (action === "can_view") return permissions.can_view;

  return permissions.can_view && permissions[action];
}

export async function getSecurityContext(): Promise<SecurityContext | null> {
  const supabase = await createClient();
  const admin = createAdminClient();

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) return null;

  const { data: profile } = await admin
    .from("profiles")
    .select("id, user_id, full_name, email, role, status, church_id")
    .eq("user_id", user.id)
    .maybeSingle();

  if (!profile) return null;

  const role = normalizeRole(profile.role);

  return {
    admin,
    profile,
    role,
    churchId: profile.church_id ?? null,
  };
}

export async function requireActiveProfile() {
  const context = await getSecurityContext();

  if (!context) redirect("/login");

  if (context.profile.status && context.profile.status !== "active") {
    redirect("/unauthorized?reason=inactive");
  }

  return context;
}

export async function requireSuperAdmin() {
  const context = await requireActiveProfile();

  if (context.role !== "super_admin") {
    redirect("/unauthorized?reason=super_admin_required");
  }

  return context;
}

export async function requireChurchAdmin(): Promise<ChurchSecurityContext> {
  const context = await requireActiveProfile();

  if (!context.churchId) {
    redirect("/unauthorized?reason=church_required");
  }

  if (!CHURCH_ADMIN_ROLES.has(context.role) && !PASTOR_ROLES.has(context.role)) {
    redirect("/unauthorized?reason=church_admin_required");
  }

  return withChurchProfile(context, context.churchId) as ChurchSecurityContext;
}

export async function getChurchModuleAccess(
  moduleCode: string,
  action: PermissionAction = "can_view"
): Promise<ModuleAccessResult | null> {
  const context = await getSecurityContext();

  if (!context) return null;

  if (context.profile.status && context.profile.status !== "active") {
    return {
      ...context,
      moduleCode,
      source: "fallback",
      permissions: EMPTY_PERMISSIONS,
      granted: false,
      reason: "inactive_profile",
    };
  }

  if (context.role === "super_admin") {
    return {
      ...context,
      moduleCode,
      source: "super_admin",
      permissions: FULL_PERMISSIONS,
      granted: true,
    };
  }

  if (!context.churchId) {
    return {
      ...context,
      moduleCode,
      source: "fallback",
      permissions: EMPTY_PERMISSIONS,
      granted: false,
      reason: "missing_church",
    };
  }

  if (!SYSTEM_MODULES.has(moduleCode)) {
    const { data: churchModule } = await context.admin
      .from("church_modules")
      .select("enabled")
      .eq("church_id", context.churchId)
      .eq("module_code", moduleCode)
      .maybeSingle();

    if (!churchModule?.enabled) {
      return {
        ...context,
        moduleCode,
        source: "fallback",
        permissions: EMPTY_PERMISSIONS,
        granted: false,
        reason: "module_disabled",
      };
    }
  }

  const { data: explicitPermissions } = await context.admin
    .from("profile_module_permissions")
    .select("*")
    .eq("church_id", context.churchId)
    .eq("profile_id", context.profile.id);

  const hasExplicitProfilePermissions = (explicitPermissions ?? []).length > 0;

  if (hasExplicitProfilePermissions) {
    const profilePermission = (explicitPermissions ?? []).find(
      (permission: any) => permission.module_code === moduleCode
    );

    const permissions = buildPermission(profilePermission);

    return {
      ...context,
      moduleCode,
      source: "profile",
      permissions,
      granted: hasPermission(permissions, action),
      reason: hasPermission(permissions, action)
        ? undefined
        : "profile_permission_denied",
    };
  }

  const { data: rolePermission } = await context.admin
    .from("church_role_module_permissions")
    .select("*")
    .eq("church_id", context.churchId)
    .eq("role", context.role)
    .eq("module_code", moduleCode)
    .maybeSingle();

  if (rolePermission) {
    const permissions = buildPermission(rolePermission);

    return {
      ...context,
      moduleCode,
      source: "role",
      permissions,
      granted: hasPermission(permissions, action),
      reason: hasPermission(permissions, action)
        ? undefined
        : "role_permission_denied",
    };
  }

  const permissions = fallbackPermissions(context.role, moduleCode);

  return {
    ...context,
    moduleCode,
    source: "fallback",
    permissions,
    granted: hasPermission(permissions, action),
    reason: hasPermission(permissions, action)
      ? undefined
      : "fallback_permission_denied",
  };
}

export async function requireChurchModuleAccess(
  moduleCode: string,
  action: PermissionAction = "can_view"
): Promise<RequiredModuleAccessResult> {
  const access = await getChurchModuleAccess(moduleCode, action);

  if (!access) redirect("/login");

  if (!access.granted) {
    redirect(
      `/unauthorized?reason=${access.reason || "denied"}&module=${moduleCode}`
    );
  }

  if (!access.churchId) {
    redirect(`/unauthorized?reason=church_required&module=${moduleCode}`);
  }

  return withChurchProfile(access, access.churchId) as RequiredModuleAccessResult;
}

export async function requireSameChurchProfile(profileId: string) {
  const context = await requireChurchAdmin();

  const { data: targetProfile } = await context.admin
    .from("profiles")
    .select("id, church_id, role, status, full_name, email")
    .eq("id", profileId)
    .eq("church_id", context.churchId)
    .maybeSingle();

  if (!targetProfile) {
    redirect("/unauthorized?reason=profile_other_church");
  }

  return {
    ...context,
    targetProfile,
  };
}

