    label: module[1],
    href: module[2],
  };
}

import "server-only";

import { headers } from "next/headers";
import { createAdminClient } from "@/lib/supabase/admin";
import { createClient } from "@/lib/supabase/server";

export type SecurityAuditInput = {
  action: string;
  resourceType?: string | null;
  resourceId?: string | null;
  status?: "success" | "denied" | "error" | "warning";
  severity?: "low" | "medium" | "high" | "critical";
  route?: string | null;
  metadata?: Record<string, unknown>;
  churchId?: string | null;
  actorUserId?: string | null;
  actorEmail?: string | null;
  actorRole?: string | null;
};

async function resolveActor() {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return { userId: null, email: null, role: null, churchId: null };
    }

    const admin = createAdminClient();
    const { data: profile } = await admin
      .from("profiles")
      .select("user_id,email,role,church_id")
      .eq("user_id", user.id)
      .maybeSingle();

    return {
      userId: user.id,
      email: profile?.email || user.email || null,
      role: profile?.role ? String(profile.role) : null,
      churchId: profile?.church_id || null,
    };
  } catch {
    return { userId: null, email: null, role: null, churchId: null };
  }
}

async function resolveRequest() {
  try {
    const h = await headers();
    const forwarded = h.get("x-forwarded-for") || "";

    return {
      ip: forwarded.split(",")[0]?.trim() || h.get("x-real-ip") || null,
      userAgent: h.get("user-agent") || null,
      route: h.get("x-pathname") || h.get("x-invoke-path") || null,
    };
  } catch {
    return { ip: null, userAgent: null, route: null };
  }
}

export async function recordSecurityEvent(input: SecurityAuditInput) {
  try {
    const [actor, request] = await Promise.all([
      resolveActor(),
      resolveRequest(),
    ]);

    const admin = createAdminClient();

    const { error } = await admin
      .from("security_audit_logs")
      .insert({
        church_id: input.churchId ?? actor.churchId,
        actor_user_id: input.actorUserId ?? actor.userId,
        actor_email: input.actorEmail ?? actor.email,
        actor_role: input.actorRole ?? actor.role,
        action: input.action,
        resource_type: input.resourceType || null,
        resource_id: input.resourceId || null,
        status: input.status || "success",
        severity: input.severity || "low",
        route: input.route ?? request.route,
        ip_address: request.ip,
        user_agent: request.userAgent,
        metadata: input.metadata || {},
      });

    if (error) {
      console.error("Journal sécurité non enregistré :", error.message);
    }
  } catch (error) {
    console.error("Échec silencieux du journal sécurité :", error);
  }
}

export async function withSecurityAudit<TResult>(
  input: Omit<SecurityAuditInput, "status" | "severity">,
  operation: () => Promise<TResult>
): Promise<TResult> {
  try {
    const result = await operation();

    await recordSecurityEvent({
      ...input,
      status: "success",
      severity: "low",
    });

    return result;
  } catch (error: any) {
    await recordSecurityEvent({
      ...input,
      status: "error",
      severity: "high",
      metadata: {
        ...(input.metadata || {}),
        error: error?.message || "Erreur non documentée",
      },
    });

    throw error;
  }
}

export const CHURCH_DOCUMENTS_BUCKET = "church-documents";

export type UploadedChurchDocument = {
  path: string;
  url: string;
  publicUrl: string;
  document_path: string;
  document_url: string;
  filename: string;
  name: string;
  size: number;
  mime_type: string;
  mimeType: string;
  bucket: string;
};

type UploadChurchDocumentInput = {
  admin: any;
  churchId: string | null | undefined;
  module: string;
  file: FormDataEntryValue | null;
  bucket?: string;
};

type DownloadHrefInput =
  | string
  | {
      path?: string | null;
      documentPath?: string | null;
      document_path?: string | null;
      filename?: string | null;
      name?: string | null;
    }
  | null
  | undefined;

function isFile(value: FormDataEntryValue | null): value is File {
  return typeof File !== "undefined" && value instanceof File;
}

function cleanSegment(value: string) {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-zA-Z0-9._-]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "")
    .toLowerCase();
}

function getSafeFilename(filename: string) {
  const clean = cleanSegment(filename || "document");

  return clean || "document";
}

export async function uploadChurchDocument({
  admin,
  churchId,
  module,
  file,
  bucket = CHURCH_DOCUMENTS_BUCKET,
}: UploadChurchDocumentInput): Promise<UploadedChurchDocument | null> {
  if (!isFile(file) || file.size === 0) {
    return null;
  }

  if (!churchId) {
    throw new Error("churchId est obligatoire pour téléverser un document.");
  }

  const safeModule = cleanSegment(module || "general");
  const safeFilename = getSafeFilename(file.name);
  const unique = `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
  const path = `${churchId}/${safeModule}/${unique}-${safeFilename}`;
  const mimeType = file.type || "application/octet-stream";

  const { error } = await admin.storage.from(bucket).upload(path, file, {
    cacheControl: "3600",
    upsert: false,
    contentType: mimeType,
  });

  if (error) {
    throw new Error(error.message || "Téléversement du document impossible.");
  }

  const { data } = admin.storage.from(bucket).getPublicUrl(path);
  const publicUrl = data?.publicUrl || "";

  return {
    path,
    url: publicUrl,
    publicUrl,
    document_path: path,
    document_url: publicUrl,

    // Compatibilité avec les anciens modules
    filename: file.name,
    name: file.name,
    size: file.size,
    mime_type: mimeType,
    mimeType,

    bucket,
  };
}

export function getDocumentDownloadHref(input: DownloadHrefInput) {
  const path =
    typeof input === "string"
      ? input
      : input?.path || input?.documentPath || input?.document_path || "";

  const filename =
    typeof input === "string" ? "" : input?.filename || input?.name || "";

  if (!path) return "#";

  const query = new URLSearchParams({
    path,
  });

  if (filename) {
    query.set("filename", filename);
  }

  return `/api/documents/download?${query.toString()}`;
}

export function getChurchDocumentPublicUrl({
  admin,
  path,
  bucket = CHURCH_DOCUMENTS_BUCKET,
}: {
  admin: any;
  path?: string | null;
  bucket?: string;
}) {
  if (!path) return "";

  const { data } = admin.storage.from(bucket).getPublicUrl(path);

  return data?.publicUrl || "";
}

import { createAdminClient } from "@/lib/supabase/admin";
import {
  getTenantSubdomainFromHost,
  slugFromSubdomain,
} from "@/lib/tenant/domain";

function normalizeHost(host: string) {
  return host.split(":")[0].trim().toLowerCase();
}

export function getSlugFromHost(host: string) {
  const subdomain = getTenantSubdomainFromHost(host);

  return subdomain ? slugFromSubdomain(subdomain) : "";
}

function field(row: any, key: string, fallback = "") {
  const value = row?.[key];

  return typeof value === "string"
    ? value.trim() || fallback
    : fallback;
}

function getShortName(name: string, slug: string) {
  if (slug === "maison-misericorde-cmp") return "MDM";
  if (slug === "iccrdc") return "ICC RDC";
  if (/maison.*mis[eé]ricorde/i.test(name)) return "MDM";
  if (/impact.*centre.*chr[eé]tien.*rdc/i.test(name)) {
    return "ICC RDC";
  }
  if (/impact.*centre.*chr[eé]tien/i.test(name)) return "ICC";

  return name.length > 12
    ? name.slice(0, 12)
    : name || "Église";
}

export async function resolveTenantPwaData(host: string) {
  const cleanHost = normalizeHost(host);
  const subdomain = getTenantSubdomainFromHost(cleanHost);
  const fallbackSlug = subdomain
    ? slugFromSubdomain(subdomain)
    : "";
  const admin = createAdminClient();

  let church: any = null;

  if (subdomain) {
    const { data } = await admin
      .from("churches")
      .select("*")
      .eq("subdomain", subdomain)
      .maybeSingle();

    church = data ?? null;
  }

  if (!church && fallbackSlug) {
    const { data } = await admin
      .from("churches")
      .select("*")
      .eq("slug", fallbackSlug)
      .maybeSingle();

    church = data ?? null;
  }

  const finalSlug = field(
    church,
    "slug",
    fallbackSlug || "mpangi-church"
  );
  const appName =
    field(church, "public_name") ||
    field(church, "name") ||
    "Mpangi-church";

  return {
    host: cleanHost,
    subdomain,
    slug: finalSlug,
    church,
    appName,
    shortName: getShortName(appName, finalSlug),
    logoUrl: field(church, "logo_url"),
    themeColor: field(church, "theme_color", "#03357A"),
    backgroundColor: field(
      church,
      "background_color",
      "#F5F9FC"
    ),
    version:
      field(church, "updated_at") || String(Date.now()),
  };
}

import { createAdminClient } from "@/lib/supabase/admin";
import { normalizeUserRole } from "@/lib/users/userRoles";

type CreateUserAccountInput = {
  email: string;
  password: string;
  fullName: string;
  role: string;
  churchId: string | null;
  status?: string;
  updateExisting?: boolean;
};

type ExistingProfile = {
  id: string;
  user_id: string;
  church_id: string | null;
  role: string | null;
} | null;

function cleanEmail(value: string) {
  return value.trim().toLowerCase();
}

async function findAuthUserByEmail(admin: any, email: string) {
  const targetEmail = cleanEmail(email);
  const perPage = 1000;

  for (let page = 1; page <= 20; page += 1) {
    const { data, error } = await admin.auth.admin.listUsers({
      page,
      perPage,
    });

    if (error) {
      throw new Error(error.message);
    }

    const users = data?.users ?? [];
    const found = users.find(
      (user: any) => cleanEmail(user.email || "") === targetEmail
    );

    if (found) return found;
    if (users.length < perPage) break;
  }

  return null;
}

async function readProfile(
  admin: any,
  authUserId: string
): Promise<ExistingProfile> {
  const { data, error } = await admin
    .from("profiles")
    .select("id, user_id, church_id, role")
    .eq("user_id", authUserId)
    .maybeSingle();

  if (error) return null;

  return data as ExistingProfile;
}

async function saveProfile(
  admin: any,
  payload: {
    user_id: string;
    email: string;
    full_name: string;
    role: string;
    status: string;
    church_id: string | null;
  }
) {
  const existing = await readProfile(admin, payload.user_id);

  if (existing) {
    const { error } = await admin
      .from("profiles")
      .update({
        email: payload.email,
        full_name: payload.full_name,
        role: payload.role,
        status: payload.status,
        church_id: payload.church_id,
        updated_at: new Date().toISOString(),
      })
      .eq("user_id", payload.user_id);

    if (error) {
      // Certains anciens schémas n'ont pas updated_at.
      const { error: fallbackError } = await admin
        .from("profiles")
        .update({
          email: payload.email,
          full_name: payload.full_name,
          role: payload.role,
          status: payload.status,
          church_id: payload.church_id,
        })
        .eq("user_id", payload.user_id);

      if (fallbackError) throw new Error(fallbackError.message);
    }
  } else {
    // IMPORTANT : profiles.id est une clé propre à la table.
    // On laisse PostgreSQL générer id et on remplit user_id avec auth.users.id.
    const { error } = await admin.from("profiles").insert({
      user_id: payload.user_id,
      email: payload.email,
      full_name: payload.full_name,
      role: payload.role,
      status: payload.status,
      church_id: payload.church_id,
    });

    if (error) {
      throw new Error(error.message);
    }
  }

  const verified = await readProfile(admin, payload.user_id);

  if (!verified?.user_id) {
    throw new Error(
      "Le compte Auth existe, mais le profil public n’a pas été créé."
    );
  }

  return verified;
}

export async function createOrUpdateUserAccount(
  input: CreateUserAccountInput
) {
  const admin = createAdminClient();

  const email = cleanEmail(input.email);
  const fullName = input.fullName.trim();
  const password = input.password.trim();
  const role = normalizeUserRole(input.role);
  const churchId = input.churchId || null;
  const status = input.status || "active";
  const updateExisting = input.updateExisting ?? true;

  if (!fullName) {
    throw new Error("Le nom complet est obligatoire.");
  }

  if (!email) {
    throw new Error("L’adresse email est obligatoire.");
  }

  if (password.length < 6) {
    throw new Error("Le mot de passe doit contenir au moins 6 caractères.");
  }

  let authUser = await findAuthUserByEmail(admin, email);
  let created = false;

  if (authUser) {
    if (!updateExisting) {
      throw new Error(
        "Cet email existe déjà. Ouvrez Utilisateurs & rôles pour modifier le compte."
      );
    }

    const existingProfile = await readProfile(admin, authUser.id);
    const existingChurchId = existingProfile?.church_id || null;

    if (existingChurchId && churchId && existingChurchId !== churchId) {
      throw new Error(
        "Cet email existe déjà et il est rattaché à une autre église."
      );
    }

    const { data, error } = await admin.auth.admin.updateUserById(
      authUser.id,
      {
        password,
        email_confirm: true,
        user_metadata: {
          ...(authUser.user_metadata || {}),
          full_name: fullName,
          role,
          church_id: churchId,
          status,
        },
      }
    );

    if (error) {
      throw new Error(error.message);
    }

    authUser = data.user;
  } else {
    const { data, error } = await admin.auth.admin.createUser({
      email,
      password,
      email_confirm: true,
      user_metadata: {
        full_name: fullName,
        role,
        church_id: churchId,
        status,
      },
    });

    if (error) {
      throw new Error(error.message);
    }

    authUser = data.user;
    created = true;
  }

  if (!authUser?.id) {
    throw new Error("Identifiant utilisateur introuvable après création.");
  }

  try {
    await saveProfile(admin, {
      user_id: authUser.id,
      email,
      full_name: fullName,
      role,
      status,
      church_id: churchId,
    });
  } catch (error) {
    if (created) {
      await admin.auth.admin.deleteUser(authUser.id).catch(() => undefined);
    }

    throw error;
  }

  return {
    id: authUser.id,
    email,
    role,
    churchId,
    created,
  };
}
